--[[ Cinematic Graphics Suite v1.0.3 — single-file bundle generated by build/bundle.lua. Do not edit by hand. ]]

local __modules = {}
local __cache = {}
local __running = {}
local function __require(name)
	if __cache[name] ~= nil then return __cache[name] end
	local factory = __modules[name]
	if not factory then error("module not found: " .. tostring(name)) end
	if __running[name] then error("cyclic require: " .. tostring(name)) end
	__running[name] = true
	local result = factory(__require)
	__running[name] = nil
	__cache[name] = result
	return result
end


__modules["core/Util"] = (function()
--!nonstrict
--[[
	core/Util.lua
	-----------------------------------------------------------------------------
	Shared, dependency-free helpers used across every subsystem.

	WHY: A single home for math/easing/colour/table helpers keeps the rest of the
	codebase free of copy-paste. Nothing here touches engine state or other
	modules, so it can be required first and by anyone with zero ordering risk.

	The module is returned as a factory `function(require) ... end` to match the
	universal module contract (see manifest.lua / init.lua), but it needs no
	dependencies of its own.
]]

return function(_require)
	local Util = {}

	-- ── numbers ────────────────────────────────────────────────────────────
	function Util.clamp(v, lo, hi)
		if v < lo then return lo elseif v > hi then return hi else return v end
	end

	function Util.lerp(a, b, t)
		return a + (b - a) * t
	end

	-- Inverse lerp: where does `v` sit between a..b (unclamped).
	function Util.invLerp(a, b, v)
		if a == b then return 0 end
		return (v - a) / (b - a)
	end

	function Util.map(v, inA, inB, outA, outB)
		return Util.lerp(outA, outB, Util.invLerp(inA, inB, v))
	end

	function Util.round(v, step)
		step = step or 1
		if step <= 0 then return v end
		return math.floor(v / step + 0.5) * step
	end

	function Util.approxEqual(a, b, eps)
		return math.abs(a - b) <= (eps or 1e-4)
	end

	-- Frame-rate-independent exponential smoothing.
	-- WHY: `v += (target-v)*alpha` with a fixed alpha is dt-dependent and shimmers
	-- at variable FPS. The exp form is the correct continuous-time decay:
	--   v += (target - v) * (1 - exp(-dt / tau))
	-- Larger `tau` = slower response (use a big tau for exposure, small for FOV).
	function Util.damp(current, target, tau, dt)
		if tau <= 0 then return target end
		local alpha = 1 - math.exp(-dt / tau)
		return current + (target - current) * alpha
	end

	-- ── easing (t in 0..1) ─────────────────────────────────────────────────
	function Util.easeInOutQuad(t)
		t = Util.clamp(t, 0, 1)
		return t < 0.5 and 2 * t * t or 1 - (-2 * t + 2) ^ 2 / 2
	end

	function Util.easeOutCubic(t)
		t = Util.clamp(t, 0, 1)
		return 1 - (1 - t) ^ 3
	end

	function Util.smoothstep(t)
		t = Util.clamp(t, 0, 1)
		return t * t * (3 - 2 * t)
	end

	-- ── colour ─────────────────────────────────────────────────────────────
	function Util.lerpColor(a, b, t)
		return a:Lerp(b, Util.clamp(t, 0, 1))
	end

	-- Rec.709 luminance of a Color3 (0..1). Used by eye-adaptation/tonemap.
	function Util.luminance(c)
		return 0.2126 * c.R + 0.7152 * c.G + 0.0722 * c.B
	end

	function Util.color3FromHex(hex)
		hex = hex:gsub("#", "")
		local r = tonumber(hex:sub(1, 2), 16) or 0
		local g = tonumber(hex:sub(3, 4), 16) or 0
		local b = tonumber(hex:sub(5, 6), 16) or 0
		return Color3.fromRGB(r, g, b)
	end

	-- ── tables ─────────────────────────────────────────────────────────────
	function Util.deepCopy(value)
		if type(value) ~= "table" then return value end
		local out = {}
		for k, v in pairs(value) do
			out[k] = Util.deepCopy(v)
		end
		return out
	end

	-- Shallow-merge `overlay` onto a copy of `base` (overlay wins).
	function Util.merge(base, overlay)
		local out = Util.deepCopy(base)
		if type(overlay) == "table" then
			for k, v in pairs(overlay) do
				out[k] = v
			end
		end
		return out
	end

	function Util.keys(t)
		local out = {}
		for k in pairs(t) do out[#out + 1] = k end
		return out
	end

	function Util.count(t)
		local n = 0
		for _ in pairs(t) do n += 1 end
		return n
	end

	-- Stable alphabetical key iteration (deterministic UI / serialisation order).
	function Util.sortedKeys(t)
		local out = Util.keys(t)
		table.sort(out, function(a, b) return tostring(a) < tostring(b) end)
		return out
	end

	-- ── value-type round-trip helpers (for JSON serialisation) ─────────────
	-- WHY: HttpService:JSONEncode cannot encode Color3/Vector3/Enum. The
	-- Serializer leans on these to flatten/expand the few engine types we store
	-- in config. Keep this list in sync with Config value `type`s.
	function Util.encodeValue(v)
		local tv = typeof(v)
		if tv == "Color3" then
			return { __t = "Color3", r = v.R, g = v.G, b = v.B }
		elseif tv == "Vector3" then
			return { __t = "Vector3", x = v.X, y = v.Y, z = v.Z }
		elseif tv == "EnumItem" then
			return { __t = "Enum", e = tostring(v.EnumType), n = v.Name }
		end
		return v
	end

	function Util.decodeValue(v)
		if type(v) == "table" and v.__t then
			if v.__t == "Color3" then
				return Color3.new(v.r, v.g, v.b)
			elseif v.__t == "Vector3" then
				return Vector3.new(v.x, v.y, v.z)
			elseif v.__t == "Enum" then
				local ok, enumGroup = pcall(function()
					return (Enum :: any)[v.e:gsub("Enum%.", "")]
				end)
				if ok and enumGroup then
					local ok2, item = pcall(function() return enumGroup[v.n] end)
					if ok2 then return item end
				end
				return nil
			end
		end
		return v
	end

	-- Try-call that never throws; returns ok, result|errMessage.
	function Util.try(fn, ...)
		return pcall(fn, ...)
	end

	-- Perlin-ish smooth noise sample in [-1, 1] via math.noise (built-in).
	function Util.noise(x, y, z)
		return math.noise(x or 0, y or 0, z or 0)
	end

	-- EditableImage binding (CPU pixel work) — feature-detected, never assumed.
	-- Creates an EditableImage of sizePx² and binds it to an existing ImageLabel,
	-- trying the current Content.fromObject API then the older child-parent API.
	-- Returns (editableImage, writeFn(flatRGBAarray)) or nil on ANY failure so
	-- callers degrade gracefully. Keep buffers small (128–256) — this is CPU-bound.
	function Util.bindEditableImage(imageLabel, sizePx)
		local AssetService = game:GetService("AssetService")
		if typeof(AssetService.CreateEditableImage) ~= "function" then return nil end
		local img
		pcall(function() img = AssetService:CreateEditableImage({ Size = Vector2.new(sizePx, sizePx) }) end)
		if not img then
			pcall(function() img = (AssetService :: any):CreateEditableImage(Vector2.new(sizePx, sizePx)) end)
		end
		if not img then return nil end
		-- bind to the label: current API uses Content.fromObject; older beta parented.
		local bound = false
		pcall(function()
			imageLabel.ImageContent = Content.fromObject(img)
			bound = true
		end)
		if not bound then
			pcall(function() img.Parent = imageLabel; bound = true end)
		end
		if not bound then
			pcall(function() img:Destroy() end)
			return nil
		end
		local size2 = Vector2.new(sizePx, sizePx)
		local write = function(buf)
			return pcall(function() img:WritePixels(Vector2.zero, size2, buf) end)
		end
		return img, write
	end

	return Util
end

end)()

__modules["core/Logger"] = (function()
--!nonstrict
--[[
	core/Logger.lua
	-----------------------------------------------------------------------------
	Tiny levelled logger with a ring buffer.

	WHY: We want one consistent prefix in the dev console, a level gate so we can
	go quiet in production, and a retained "last error" that the About tab in the
	UI can surface to the user without them opening the developer console.

	No engine state is mutated here; safe to require early.
]]

return function(_require)
	local Logger = {}

	Logger.Levels = { trace = 1, debug = 2, info = 3, warn = 4, error = 5, silent = 99 }

	local PREFIX = "[Cinematic]"
	local minLevel = Logger.Levels.info
	local ring = {}            -- recent messages, capped
	local RING_MAX = 64
	local lastError = nil

	local function push(levelName, msg)
		ring[#ring + 1] = { level = levelName, msg = msg }
		if #ring > RING_MAX then
			table.remove(ring, 1)
		end
	end

	function Logger.setLevel(levelNameOrNumber)
		if type(levelNameOrNumber) == "string" then
			minLevel = Logger.Levels[levelNameOrNumber] or minLevel
		elseif type(levelNameOrNumber) == "number" then
			minLevel = levelNameOrNumber
		end
	end

	local function fmt(...)
		local parts = {}
		for i = 1, select("#", ...) do
			parts[i] = tostring(select(i, ...))
		end
		return table.concat(parts, " ")
	end

	function Logger.trace(...) if minLevel <= 1 then print(PREFIX, "trace:", ...) end end

	function Logger.debug(...)
		if minLevel <= 2 then print(PREFIX, ...) end
		push("debug", fmt(...))
	end

	function Logger.info(...)
		if minLevel <= 3 then print(PREFIX, ...) end
		push("info", fmt(...))
	end

	function Logger.warn(...)
		if minLevel <= 4 then warn(PREFIX, ...) end
		push("warn", fmt(...))
	end

	function Logger.error(...)
		local m = fmt(...)
		lastError = m
		if minLevel <= 5 then warn(PREFIX, "ERROR:", m) end
		push("error", m)
	end

	-- Run fn in a pcall, logging (not raising) any failure. Returns ok, result.
	function Logger.guard(label, fn, ...)
		local ok, res = pcall(fn, ...)
		if not ok then
			Logger.error(label, "->", res)
		end
		return ok, res
	end

	function Logger.getLastError() return lastError end
	function Logger.getHistory() return ring end
	function Logger.clear() ring = {}; lastError = nil end

	return Logger
end

end)()

__modules["core/Signal"] = (function()
--!nonstrict
--[[
	core/Signal.lua
	-----------------------------------------------------------------------------
	Minimal synchronous signal/event implementation (BindableEvent-free).

	WHY: State broadcasts config changes and several subsystems subscribe. A pure
	Luau signal avoids the overhead/teardown quirks of real Instances and lets a
	Maid disconnect everything deterministically. Fires are synchronous and
	wrapped so one bad listener cannot break the rest.

	Returns a class (not a singleton). `Signal.new()` per channel.
]]

return function(_require)
	local Connection = {}
	Connection.__index = Connection

	function Connection:Disconnect()
		if not self._connected then return end
		self._connected = false
		local conns = self._signal._connections
		for i = #conns, 1, -1 do
			if conns[i] == self then
				table.remove(conns, i)
				break
			end
		end
	end
	Connection.disconnect = Connection.Disconnect -- alias

	local Signal = {}
	Signal.__index = Signal

	function Signal.new()
		return setmetatable({ _connections = {} }, Signal)
	end

	function Signal:Connect(fn)
		assert(type(fn) == "function", "Signal:Connect expects a function")
		local conn = setmetatable({ _signal = self, _fn = fn, _connected = true }, Connection)
		self._connections[#self._connections + 1] = conn
		return conn
	end
	Signal.connect = Signal.Connect -- alias

	function Signal:Once(fn)
		local conn
		conn = self:Connect(function(...)
			conn:Disconnect()
			fn(...)
		end)
		return conn
	end

	function Signal:Fire(...)
		-- Iterate a snapshot so listeners may disconnect during dispatch.
		local snapshot = table.clone(self._connections)
		for _, conn in ipairs(snapshot) do
			if conn._connected then
				local ok, err = pcall(conn._fn, ...)
				if not ok then
					warn("[Cinematic] signal listener error:", err)
				end
			end
		end
	end

	function Signal:DisconnectAll()
		for _, conn in ipairs(self._connections) do
			conn._connected = false
		end
		table.clear(self._connections)
	end
	Signal.Destroy = Signal.DisconnectAll

	return Signal
end

end)()

__modules["core/Maid"] = (function()
--!nonstrict
--[[
	core/Maid.lua
	-----------------------------------------------------------------------------
	Janitor / Maid — tracks everything that must be cleaned up.

	WHY: The single most important robustness primitive in this suite. Every
	RBXScriptConnection, custom Signal connection, created Instance, task.spawn
	thread and arbitrary teardown closure is handed to a Maid. On unload we clean
	in REVERSE insertion order so dependents die before their dependencies. No
	orphaned PreRender/RenderStepped loops, no leaked GUIs.

	Accepts (and knows how to clean up):
	  * RBXScriptConnection                -> :Disconnect()
	  * tables with :Disconnect / :disconnect (our Signal connections)
	  * Instances                          -> :Destroy()
	  * functions                          -> called
	  * threads (task.spawn result)        -> task.cancel
	  * tables with :Destroy / :destroy    -> called

	Returns a class. Each subsystem owns a child Maid given to the root Maid, so
	tearing down the root tears down the whole tree.
]]

return function(_require)
	local Maid = {}
	Maid.__index = Maid

	function Maid.new()
		return setmetatable({ _tasks = {}, _alive = true }, Maid)
	end

	-- Add a task; returns it so you can write `local c = maid:give(conn)`.
	function Maid:give(item)
		if not self._alive then
			-- Already cleaned: dispose immediately to avoid leaks.
			Maid._dispose(item)
			return item
		end
		self._tasks[#self._tasks + 1] = item
		return item
	end
	Maid.Add = Maid.give
	Maid.GiveTask = Maid.give

	-- Convenience: spawn a tracked thread that is cancelled on cleanup.
	function Maid:spawn(fn, ...)
		local thread = task.spawn(fn, ...)
		self:give(thread)
		return thread
	end

	-- Convenience: create + track a child Maid.
	function Maid:childMaid()
		local child = Maid.new()
		self:give(child)
		return child
	end

	function Maid._dispose(item)
		local t = typeof(item)
		if t == "RBXScriptConnection" then
			item:Disconnect()
		elseif t == "Instance" then
			item:Destroy()
		elseif t == "function" then
			local ok, err = pcall(item)
			if not ok then warn("[Cinematic] maid task error:", err) end
		elseif t == "thread" then
			pcall(task.cancel, item)
		elseif t == "table" then
			if type(item.Disconnect) == "function" then
				pcall(item.Disconnect, item)
			elseif type(item.disconnect) == "function" then
				pcall(item.disconnect, item)
			elseif type(item.Destroy) == "function" then
				pcall(item.Destroy, item)
			elseif type(item.destroy) == "function" then
				pcall(item.destroy, item)
			elseif type(item.clean) == "function" then
				pcall(item.clean, item)
			end
		end
	end

	-- Clean everything in reverse order. Safe to call multiple times.
	function Maid:clean()
		self._alive = false
		local tasks = self._tasks
		self._tasks = {}
		for i = #tasks, 1, -1 do
			Maid._dispose(tasks[i])
			tasks[i] = nil
		end
		-- Allow re-arming after a clean (e.g. effect toggled off then on).
		self._alive = true
	end
	Maid.Destroy = Maid.clean
	Maid.DoCleaning = Maid.clean

	function Maid:isEmpty()
		return #self._tasks == 0
	end

	return Maid
end

end)()

__modules["core/Platform"] = (function()
--!nonstrict
--[[
	core/Platform.lua
	-----------------------------------------------------------------------------
	Capability + device detection. Feature-detect, never assume.

	WHY: This suite targets vanilla Roblox clients AND executor environments, on
	desktop AND mobile, on Future lighting AND legacy fallbacks. Every risky
	capability (executor HTTP, EditableImage, Future lighting) is probed once
	here and exposed as a boolean so the rest of the code can `if Platform.caps.X`
	rather than re-pcalling everywhere.

	HARD TRUTHS honoured:
	  * loadstring/HttpGet/writefile/setclipboard/syn.request are EXECUTOR-only.
	  * EditableImage needs an ID-verified 13+ creator in published games — we
	    feature-detect by attempting a tiny image and degrade if it errors.
	  * Future lighting / Clouds silently degrade on low-end; we only report
	    whether the *enum* exists, not whether the GPU honours it.
]]

return function(require)
	local Logger = require("core/Logger")

	local Players = game:GetService("Players")
	local UserInputService = game:GetService("UserInputService")
	local GuiService = game:GetService("GuiService")
	local RunService = game:GetService("RunService")

	local Platform = {}
	Platform.caps = {}
	local caps = Platform.caps

	-- ── environment ─────────────────────────────────────────────────────────
	-- getgenv is the executor global table; absent in vanilla/Studio.
	local hasGetgenv = (typeof(getgenv) == "function")
	caps.executor = hasGetgenv or (typeof(syn) == "table") or (typeof(request) == "function")
	caps.studio = RunService:IsStudio()

	-- Shared global table: executor getgenv() if present, else _G.
	function Platform.globalTable()
		if hasGetgenv then
			local ok, g = pcall(getgenv)
			if ok and type(g) == "table" then return g end
		end
		return _G
	end

	-- ── executor file / net capabilities (all optional) ──────────────────────
	caps.httpGet = (typeof(game.HttpGet) == "function") or (typeof((syn or {}).request) == "function")
		or (typeof(request) == "function") or (typeof(http_request) == "function")
	caps.writefile = (typeof(writefile) == "function")
	caps.readfile = (typeof(readfile) == "function")
	caps.isfile = (typeof(isfile) == "function")
	caps.makefolder = (typeof(makefolder) == "function")
	caps.setclipboard = (typeof(setclipboard) == "function")
	caps.loadstring = (typeof(loadstring) == "function")
	-- gethui hides protected GUIs from the game on executors; fall back to PlayerGui.
	caps.gethui = (typeof(gethui) == "function")

	-- ── lighting capabilities ────────────────────────────────────────────────
	local function enumExists(group, name)
		local ok, val = pcall(function() return (Enum :: any)[group][name] end)
		return ok and val ~= nil, ok and val or nil
	end
	caps.futureLighting = enumExists("Technology", "Future")
	caps.realisticLightingStyle = enumExists("LightingStyle", "Realistic")
	do
		-- ShadowSoftness only exists on newer Lighting; probe the property.
		local okProp = pcall(function() return game:GetService("Lighting").ShadowSoftness end)
		caps.shadowSoftness = okProp
		local okPrio = pcall(function() return (game:GetService("Lighting") :: any).PrioritizeLightingQuality end)
		caps.prioritizeLightingQuality = okPrio
	end

	-- ── EditableImage / EditableMesh (CPU pixel work) ─────────────────────────
	-- Feature-detect properly: the API may exist but be gated to verified 13+
	-- creators, in which case CreateEditableImage throws at runtime.
	do
		local AssetService = game:GetService("AssetService")
		local ok = false
		if typeof(AssetService.CreateEditableImage) == "function" then
			ok = pcall(function()
				-- Newer signature takes a props table; older took (Vector2).
				local img = AssetService:CreateEditableImage({ Size = Vector2.new(8, 8) })
				if img then img:Destroy() end
			end)
			if not ok then
				ok = pcall(function()
					local img = (AssetService :: any):CreateEditableImage(Vector2.new(8, 8))
					if img then img:Destroy() end
				end)
			end
		end
		caps.editableImage = ok
	end

	-- ── device / input ────────────────────────────────────────────────────────
	caps.touch = UserInputService.TouchEnabled
	caps.keyboard = UserInputService.KeyboardEnabled
	caps.mouse = UserInputService.MouseEnabled
	caps.gamepad = UserInputService.GamepadEnabled
	caps.tenFootInterface = GuiService:IsTenFootInterface() -- console

	-- Heuristic: mobile = touch & not keyboard, OR a small screen.
	local viewport = workspace.CurrentCamera and workspace.CurrentCamera.ViewportSize or Vector2.new(1280, 720)
	caps.screenSize = viewport
	Platform.isMobile = (caps.touch and not caps.keyboard) or (viewport.X > 0 and viewport.X < 800)
	Platform.isConsole = caps.tenFootInterface
	Platform.isDesktop = not Platform.isMobile and not Platform.isConsole

	-- Coarse performance tier guess from device class; refined later by Benchmark.
	-- 1 = potato/mobile, 2 = mid, 3 = high desktop.
	Platform.tierGuess = Platform.isMobile and 1 or (Platform.isConsole and 2 or 3)

	function Platform.localPlayer()
		return Players.LocalPlayer
	end

	function Platform.describe()
		return string.format(
			"device=%s executor=%s future=%s editableImage=%s screen=%dx%d",
			Platform.isMobile and "mobile" or (Platform.isConsole and "console" or "desktop"),
			tostring(caps.executor), tostring(caps.futureLighting),
			tostring(caps.editableImage), viewport.X, viewport.Y
		)
	end

	Logger.info("Platform:", Platform.describe())
	return Platform
end

end)()

__modules["core/Config"] = (function()
--!nonstrict
--[[
	core/Config.lua
	=============================================================================
	THE SINGLE SOURCE OF TRUTH.

	Every tunable in the entire suite is declared here exactly once, with typed
	metadata. Modules NEVER hardcode magic numbers — they read live values from
	core/State (which is seeded from these defaults). The UI is GENERATED from
	this table, so adding a setting here automatically:
	    * gives it a validated default + clamp range,
	    * makes it live-editable (State.set fires a change signal),
	    * renders the matching Rayfield control in the right tab/group,
	    * round-trips through JSON export/import.

	Metadata schema per key:
	    default  : the seed value (also defines the runtime type)
	    type     : "number" | "boolean" | "color" | "option" | "keybind" | "string"
	    min,max  : numeric bounds (number type) — values are clamped on set
	    step     : numeric quantisation / UI slider increment
	    options  : array of strings (option type)
	    label    : human label for the UI
	    desc     : tooltip / docs string
	    tab      : UI tab name (must exist in Config.tabs)
	    group    : group heading inside the tab
	    requires : capability key in Platform.caps that must be true, else the
	               control is shown disabled / skipped (e.g. "futureLighting")
	    save     : if true, Rayfield ConfigurationSaving persists this control

	`Config.layout` defines UI ORDER (Lua dicts are unordered). Schema walks the
	layout; any key present in meta but absent from layout still validates but is
	hidden (used for internal/derived values).

	NOTE ON HONESTY: keys named *reflection*/*ssr* drive an APPROXIMATION of
	screen-space reflections via roving raycasts — never true RT. Labels/desc say
	so. Keys named *vignette/grain/chromatic/letterbox/dither/motionblur* drive
	GUI / EditableImage OVERLAYS — the engine exposes no such post effects.
]]

return function(_require)
	local Config = {}

	Config.version = "1.0.3"
	Config.schemaVersion = 1

	Config.tabs = {
		"General", "Lighting", "Reflections", "Atmosphere & Weather",
		"Camera & Cinematic", "Materials", "Performance", "Presets", "About",
	}

	-- KeyCode names are stored as strings and resolved to Enum.KeyCode at use.
	local KEYCODES = {
		"RightShift", "LeftShift", "RightControl", "LeftControl", "F1", "F2",
		"F3", "F4", "Backquote", "P", "V", "B", "K", "Insert", "End", "Home",
	}

	Config.meta = {
		-- ════════════════════════ GENERAL ══════════════════════════════════
		master_enabled = {
			default = true, type = "boolean", label = "Master Enable",
			desc = "Master on/off for the entire suite. Off restores the game look without unloading.",
			tab = "General", group = "Master", save = true,
		},
		quality = {
			default = 1.0, type = "number", min = 0, max = 1, step = 0.05,
			label = "Global Quality", desc = "0 = cheapest, 1 = maximum fidelity. Scales every effect's internal budget.",
			tab = "General", group = "Master", save = true,
		},
