__modules["core/State"] = (function()
--!nonstrict
--[[
	core/State.lua
	-----------------------------------------------------------------------------
	Live, mutable settings store seeded from Config defaults.

	WHY: Config is static metadata; State is the running value of every setting.
	Modules read with State.get(key) and react to changes via State.changed (a
	Signal that fires (key, newValue, oldValue) on every set). This is the live-
	update backbone — change a slider in the UI and the owning module updates
	immediately, no reload.

	State.set() validates/clamps through Config.coerce, so out-of-range UI input
	or bad imported JSON can never poison a module.

	Singleton (one store per loaded suite).
]]

return function(require)
	local Config = require("core/Config")
	local Signal = require("core/Signal")
	local Logger = require("core/Logger")

	local State = {}
	local values = Config.buildDefaults()

	-- Fired on every successful change: (key, newValue, oldValue).
	State.changed = Signal.new()
	-- Fired after a bulk apply (preset/import) completes: (changedKeysArray).
	State.bulkChanged = Signal.new()

	function State.get(key)
		return values[key]
	end

	-- Snapshot of ALL live values (shallow copy; values are immutable types).
	function State.snapshot()
		local out = {}
		for k, v in pairs(values) do out[k] = v end
		return out
	end

	-- Set one key. Coerces, stores, fires changed (unless silent / unchanged).
	-- Returns the stored (coerced) value.
	function State.set(key, value, silent)
		local coerced = Config.coerce(key, value)
		local old = values[key]
		if old == coerced then
			return coerced -- no-op; don't spam the signal
		end
		values[key] = coerced
		if not silent then
			State.changed:Fire(key, coerced, old)
		end
		return coerced
	end

	-- Apply a partial overlay (preset / imported data). Only keys present are
	-- touched — this is what makes presets PARTIAL overlays. Fires per-key
	-- changed signals plus one bulkChanged at the end.
	function State.applyOverlay(overlay, silentPerKey)
		local changed = {}
		for key, value in pairs(overlay) do
			if Config.meta[key] ~= nil then
				local old = values[key]
				local coerced = Config.coerce(key, value)
				if old ~= coerced then
					values[key] = coerced
					changed[#changed + 1] = key
					if not silentPerKey then
						State.changed:Fire(key, coerced, old)
					end
				end
			else
				Logger.warn("State.applyOverlay: unknown key ignored:", key)
			end
		end
		State.bulkChanged:Fire(changed)
		return changed
	end

	-- Reset everything to Config defaults.
	function State.reset()
		local overlay = Config.buildDefaults()
		return State.applyOverlay(overlay)
	end

	-- Subscribe to a single key; returns a connection. Fires immediately once
	-- with the current value so modules can self-initialise from one code path.
	function State.observe(key, fn)
		fn(values[key], nil)
		return State.changed:Connect(function(k, new, old)
			if k == key then fn(new, old) end
		end)
	end

	-- Subscribe to several keys at once (any of them firing calls fn(key,new)).
	function State.observeMany(keys, fn)
		local set = {}
		for _, k in ipairs(keys) do set[k] = true end
		return State.changed:Connect(function(k, new, old)
			if set[k] then fn(k, new, old) end
		end)
	end

	return State
end

end)()

__modules["core/Snapshot"] = (function()
--!nonstrict
--[[
	core/Snapshot.lua
	-----------------------------------------------------------------------------
	The zero-residue safety net.

	WHY: This suite mutates shared singletons (Lighting, Camera, Terrain) that we
	do NOT own. On unload we must restore the game EXACTLY as we found it. Two
	mechanisms:

	  1. Property capture — before the FIRST write to any property we record its
	     original value (capture-once; later writes never overwrite the original).
	     restore() writes them all back and clears the record.

	  2. Created-instance tagging — every Instance we create is stamped with the
	     attribute __cinematic=true and (optionally) tracked. On teardown we
	     Destroy ONLY tagged instances. We never Destroy or modify pre-existing
	     game effects — we add our own alongside and restore originals.

	This module does not decide WHEN to restore (that's Teardown/API); it only
	remembers and reverts.
]]

return function(require)
	local Logger = require("core/Logger")

	local Snapshot = {}
	local TAG_ATTR = "__cinematic"

	-- records[instance] = { propName = originalValue, ... }
	local records = setmetatable({}, { __mode = "k" }) -- weak keys: GC'd instances drop out
	local createdOrder = {}                              -- tracked created instances (ordered)

	-- Capture the original value of inst[prop] exactly once.
	function Snapshot.capture(inst, prop)
		if not inst then return end
		local rec = records[inst]
		if not rec then
			rec = {}
			records[inst] = rec
		end
		if rec[prop] == nil then
			local ok, val = pcall(function() return (inst :: any)[prop] end)
			if ok then
				-- store a sentinel for genuine nils so we know we captured it
				rec[prop] = { v = val }
			end
		end
	end

	-- Capture then write in one call — the canonical "mutate a foreign prop" path.
	function Snapshot.set(inst, prop, value)
		Snapshot.capture(inst, prop)
		local ok, err = pcall(function() (inst :: any)[prop] = value end)
		if not ok then
			Logger.warn("Snapshot.set failed", tostring(inst), prop, "->", err)
		end
		return ok
	end

	-- Mark an instance as ours and track it for destruction on teardown.
	function Snapshot.track(inst)
		if not inst then return inst end
		pcall(function() inst:SetAttribute(TAG_ATTR, true) end)
		createdOrder[#createdOrder + 1] = inst
		return inst
	end

	-- Create + parent + tag in one call.
	function Snapshot.create(className, props, parent)
		local inst = Instance.new(className)
		if props then
			for k, v in pairs(props) do
				pcall(function() (inst :: any)[k] = v end)
			end
		end
		Snapshot.track(inst)
		if parent then inst.Parent = parent end
		return inst
	end

	function Snapshot.isOurs(inst)
		local ok, val = pcall(function() return inst:GetAttribute(TAG_ATTR) end)
		return ok and val == true
	end

	-- Restore every captured property to its original value.
	function Snapshot.restoreProperties()
		local restored, failed = 0, 0
		for inst, rec in pairs(records) do
			if inst then
				for prop, boxed in pairs(rec) do
					local ok = pcall(function() (inst :: any)[prop] = boxed.v end)
					if ok then restored += 1 else failed += 1 end
				end
			end
		end
		table.clear(records)
		Logger.debug(string.format("Snapshot restored %d properties (%d failed)", restored, failed))
		return restored, failed
	end

	-- Destroy every tracked created instance (reverse order). Also sweeps any
	-- stray tagged instances under a provided root as a belt-and-braces pass.
	function Snapshot.destroyCreated(extraRoots)
		local destroyed = 0
		for i = #createdOrder, 1, -1 do
			local inst = createdOrder[i]
			if inst then
				pcall(function() inst:Destroy() end)
				destroyed += 1
			end
			createdOrder[i] = nil
		end
		-- Sweep for anything tagged we may have lost track of.
		for _, root in ipairs(extraRoots or {}) do
			if root then
				for _, d in ipairs(root:GetDescendants()) do
					if Snapshot.isOurs(d) then
						pcall(function() d:Destroy() end)
						destroyed += 1
					end
				end
			end
		end
		Logger.debug(string.format("Snapshot destroyed %d created instances", destroyed))
		return destroyed
	end

	-- Full revert. Properties first (so restored refs are valid), then instances.
	function Snapshot.restoreAll(extraRoots)
		Snapshot.restoreProperties()
		Snapshot.destroyCreated(extraRoots)
	end

	function Snapshot.stats()
		local propCount = 0
		for _, rec in pairs(records) do
			for _ in pairs(rec) do propCount += 1 end
		end
		return { properties = propCount, created = #createdOrder }
	end

	Snapshot.TAG_ATTR = TAG_ATTR
	return Snapshot
end

end)()

__modules["manifest"] = (function()
--!nonstrict
--[[
	src/manifest.lua
	-----------------------------------------------------------------------------
	Module registry + load metadata. Returned as a factory like every module, but
	it requires nothing — the loader can call it with a no-op require to read the
	table before the shim is fully warmed.

	* version        — suite version (kept in sync with Config.version).
	* repo           — GitHub coordinates the network loader pins to (EDIT THESE).
	* modules        — EVERY src logical name. Used by:
	                     - the network loader to eagerly warm-fetch all files,
	                     - build/bundle.lua to inline them in a deterministic order.
	                   Order is irrelevant to correctness (requires are lazy) but
	                   core/ is listed first for readability.
	* boot           — ordered list of CONTROLLER modules that init:start()s. Each
	                   controller requires + starts its own sub-modules, so init
	                   never needs to know every leaf file.
]]

return function(_require)
	local manifest = {}

	manifest.version = "1.0.3"
	manifest.schemaVersion = 1

	-- ⚠ EDIT FOR YOUR FORK: the loader pins network fetches to <user>/<name>@<ref>.
	manifest.repo = {
		user = "EcoTopWoods",
		name = "cinematic-shader",
		ref = "v1.0.3", -- a TAG or commit SHA — never a moving branch in production
		srcDir = "src",
	}

	-- Every module file (logical name = path under src/ without extension).
	manifest.modules = {
		-- core
		"core/Util", "core/Logger", "core/Signal", "core/Maid", "core/Platform",
		"core/Config", "core/State", "core/Snapshot",
		-- entry
