	-- Controllers init starts, in order. Each owns + starts its sub-modules.
	manifest.boot = {
		"detection/Scanner",
		"materials/PBR",
		"lighting/Lighting",
		"postfx/Pipeline",
		"reflections/Reflections",
		"timeofday/Mood",
		"weather/Weather",
		"enhancers/Enhancers",
		"camera/CameraFX",
