__modules["init"] = (function()
--!nonstrict
--[[
	src/init.lua  —  ENTRY POINT
	=============================================================================
	Boots the whole suite and returns the public API handle.

	Responsibilities:
	  1. Double-load guard — if a suite is already live in the shared global table
	     (getgenv() on executors, else _G), surface its UI and return its API
	     instead of stacking a second pipeline.
	  2. Build the boot CONTEXT (`ctx`) handed to every controller's start(ctx).
	  3. Start each manifest.boot controller in order, each wrapped in pcall so one
	     failing subsystem cannot abort the rest.
	  4. Publish the global handle and return it.

	=============================================================================
	THE MODULE CONTRACT (every src/*.lua follows this)
	-----------------------------------------------------------------------------
	    return function(require)        -- factory; `require` is the injected shim
	        local Module = {}
	        function Module.start(ctx)  -- called once by init or a parent controller
	            local maid = ctx.maid:childMaid()   -- OWN your cleanup
	            -- read ctx.state, apply effects, subscribe via maid:give(...)
	            return Module
	        end
	        function Module.setQuality(q) end   -- OPTIONAL: scale budget 0..1
	        function Module.stop() end          -- OPTIONAL: explicit early stop
	        return Module
	    end

	THE CONTEXT (`ctx`) — shared across all modules
	-----------------------------------------------------------------------------
	    ctx.require      injected require shim (lazy-load any sibling by name)
	    ctx.maid         ROOT Maid. Call ctx.maid:childMaid() to own your cleanup.
	    ctx.state        core/State          (live settings; :get/:set/:observe)
	    ctx.config       core/Config         (metadata)
	    ctx.snapshot     core/Snapshot       (capture/restore/create — USE THIS to
	                                          mutate ANY foreign property/instance)
	    ctx.util         core/Util
	    ctx.log          core/Logger
	    ctx.platform     core/Platform       (.caps, .isMobile, …)
	    ctx.services     pre-fetched services table (Lighting, Workspace, …)
	    ctx.worldFolder  tagged Folder in Workspace for world instances (beams…)
	    ctx.gui          tagged ScreenGui for overlays (vignette/grain/letterbox…)
	    ctx.camera()     returns the current workspace.CurrentCamera (re-fetch!)
	    ctx.getQuality() effective quality 0..1 (global × adaptive multiplier)
	    ctx.bus          shared scratch table for cross-module live values, e.g.
	                       bus.exposure       (EyeAdaptation writes, Bloom reads)
	                       bus.sceneLuminance
	                       bus.camCFrame / bus.camDelta (CameraFX writes)
	    ctx.perf         { report(name, ms), get() } per-effect cost bus (PerfHUD)
	    ctx.registerHandle(handle)  add a started module to the setQuality fan-out
	=============================================================================
]]

return function(require)
	local manifest = require("manifest")
	local Logger = require("core/Logger")
	local Platform = require("core/Platform")
	local State = require("core/State")
	local Config = require("core/Config")
	local Snapshot = require("core/Snapshot")
	local Util = require("core/Util")
	local Maid = require("core/Maid")

	-- Apply persisted log level immediately.
	Logger.setLevel(State.get("log_level"))

	local GLOBAL_KEY = "__CINEMATIC_SHADER"
	local globals = Platform.globalTable()

	-- ── 1. double-load guard ─────────────────────────────────────────────────
	local existing = globals[GLOBAL_KEY]
	if existing and type(existing) == "table" and existing.__alive then
		Logger.warn("Suite already loaded — surfacing existing instance.")
		pcall(function() if existing.toggleUI then existing.toggleUI(true) end end)
		return existing
	end

	-- ── 2. build context ─────────────────────────────────────────────────────
	local rootMaid = Maid.new()

	local services = {}
	for _, name in ipairs({
		"Lighting", "Workspace", "RunService", "Players", "UserInputService",
		"TweenService", "CollectionService", "HttpService", "StarterGui",
		"GuiService", "AssetService", "ContextActionService", "ReplicatedStorage",
	}) do
		local ok, svc = pcall(game.GetService, game, name)
		services[name] = ok and svc or nil
	end

	-- A single tagged Folder in Workspace holds all world instances we create.
	local worldFolder = Snapshot.create("Folder", { Name = "CinematicSuite" }, services.Workspace)

	-- A single ScreenGui holds all faked overlays. Prefer gethui() on executors
	-- so the host game cannot see/clobber our UI; else PlayerGui.
	local guiParent
	if Platform.caps.gethui then
		local ok, hui = pcall(gethui)
		if ok then guiParent = hui end
	end
	if not guiParent then
		local lp = services.Players.LocalPlayer
		guiParent = lp and lp:WaitForChild("PlayerGui", 5)
	end
	local overlayGui = Snapshot.create("ScreenGui", {
		Name = "CinematicOverlays",
		ResetOnSpawn = false,
		IgnoreGuiInset = true,
		ZIndexBehavior = Enum.ZIndexBehavior.Sibling,
		DisplayOrder = 9_999,
	}, guiParent)

	-- effective quality = global slider × adaptive multiplier (AdaptiveQuality
	-- writes bus.qualityMul; default 1).
	local bus = { exposure = State.get("lighting_exposure"), qualityMul = 1 }

	-- per-effect cost bus for the PerfHUD
	local perfCosts = {}
	local perf = {
		report = function(name, ms) perfCosts[name] = ms end,
		get = function() return perfCosts end,
	}

	local startedHandles = {}

	local ctx
	ctx = {
		require = require,
		maid = rootMaid,
		state = State,
		config = Config,
		snapshot = Snapshot,
		util = Util,
		log = Logger,
		platform = Platform,
		services = services,
		worldFolder = worldFolder,
		gui = overlayGui,
		bus = bus,
		perf = perf,
		manifest = manifest,
		camera = function()
			return services.Workspace.CurrentCamera
		end,
		getQuality = function()
			return Util.clamp(State.get("quality") * (bus.qualityMul or 1), 0, 1)
		end,
		registerHandle = function(handle)
			if handle then startedHandles[#startedHandles + 1] = handle end
		end,
	}

	-- ── 3. start controllers ─────────────────────────────────────────────────
	Logger.info(("Booting v%s — %s"):format(manifest.version, Platform.describe()))
	for _, name in ipairs(manifest.boot) do
		local ok, handle = pcall(function()
			local mod = require(name)
			if type(mod) == "table" and type(mod.start) == "function" then
				return mod.start(ctx) or mod
			end
			return mod
		end)
		if ok and handle then
			ctx.registerHandle(handle)
			Logger.debug("started", name)
		else
			Logger.error("controller failed:", name, "->", handle)
		end
	end

	-- propagate the current quality once everything is up
	local function fanoutQuality()
		local q = ctx.getQuality()
		for _, h in ipairs(startedHandles) do
			if type(h.setQuality) == "function" then
				pcall(h.setQuality, q)
			end
		end
	end
	rootMaid:give(State.observe("quality", fanoutQuality))
	-- expose for AdaptiveQuality (it changes bus.qualityMul then re-fans out)
	ctx.fanoutQuality = fanoutQuality

	-- ── 4. publish handle ────────────────────────────────────────────────────
	-- The full public API lives in api/API; init seeds the minimal shape so the
	-- double-load guard works even if api/API failed to load.
	local handle = globals[GLOBAL_KEY]
	if not (type(handle) == "table") then
		handle = {}
		globals[GLOBAL_KEY] = handle
	end
	handle.__alive = true
	handle.version = manifest.version
	handle.ctx = ctx
	handle._handles = startedHandles
	handle._fanoutQuality = fanoutQuality
	handle.loadSource = handle.loadSource or "unknown"

	if State.get("intro_notify") then
		pcall(function()
			if handle.notify then
				handle.notify("Cinematic Suite", "Loaded v" .. manifest.version, 4)
			end
		end)
	end

	Logger.info("Boot complete.")
	return handle
end

end)()

__modules["detection/Scanner"] = (function()
--!nonstrict
--[[
	detection/Scanner.lua  —  CONTROLLER (manifest.boot, started 1st)
	-----------------------------------------------------------------------------
	Streaming-aware, debounced, BUDGETED world part classifier.

	WHY: Reflections / Materials / Enhancers all need to know "is this a floor / a
	piece of foliage / water / a light holder". Walking workspace:GetDescendants()
	every frame would be catastrophic on big places (and StreamingEnabled means the
	tree changes constantly). Instead we maintain a work QUEUE fed by
	DescendantAdded, drain at most `perf_scanner_budget` parts/frame on Heartbeat,
	cache results in a weak table, and keep per-kind sets current.

	Classification = Material (via materials/PBR) + size/orientation + name hints +
	child emitters + CollectionService tags. Cached; we deliberately do NOT connect
	a Changed listener per part (that would mean thousands of connections) — call
	rescan() if the world's materials are mutated wholesale.

	Public API (the cross-module contract):
	    Scanner.classify(part) -> { kind, roughness, f0, isFloor, isFoliage,
	                                 isWater, isGlass, isMetal }
	    Scanner.getFloors()    -> { BasePart, ... }
	    Scanner.getByKind(k)   -> { BasePart, ... }
	    Scanner.onClassified   -> Signal (part, classification)
	    Scanner.rescan()
]]

return function(require)
	local State = require("core/State")
	local Signal = require("core/Signal")
	local CollectionService = game:GetService("CollectionService")

	local Scanner = {}
	Scanner.id = "detection/Scanner"
	Scanner.onClassified = Signal.new()

	-- name hint tables (lower-cased substring match)
	local FOLIAGE_WORDS = { "leaf", "leaves", "bush", "tree", "foliage", "grass", "fern", "plant", "vine", "hedge" }
	local WATER_WORDS = { "water", "ocean", "sea", "pond", "lake", "river", "pool" }

	local KINDS = { "floor", "foliage", "water", "glass", "metal", "fire", "smoke", "light", "generic" }

	-- state
	local cache = setmetatable({}, { __mode = "k" })       -- part -> classification
	local sets = {}                                        -- kind -> { [part]=true }
	for _, k in ipairs(KINDS) do sets[k] = setmetatable({}, { __mode = "k" }) end
	local queue = {}                                       -- pending parts
	local queued = setmetatable({}, { __mode = "k" })      -- part -> true (dedupe)
	local qualityMul = 1

	local function hasWord(name, words)
		name = string.lower(name)
		for _, w in ipairs(words) do
			if string.find(name, w, 1, true) then return true end
		end
		return false
	end

	-- compute (does not cache) the classification for a part
	local function compute(part)
		local PBR = require("materials/PBR")
		local props = PBR.props(part.Material)
		local mat = part.Material
		local name = part.Name

		local cls = {
			kind = "generic",
			roughness = props.roughness,
			f0 = props.f0,
			isFloor = false, isFoliage = false, isWater = false,
			isGlass = false, isMetal = false,
		}

		-- tags force-mark
		local floorTag = State.get("reflect_floor_tag")
		local tagged = false
		pcall(function() tagged = floorTag ~= "" and CollectionService:HasTag(part, floorTag) end)

		-- child emitters → kind holders (used by enhancers)
		if part:FindFirstChildOfClass("Fire") then cls.kind = "fire" end
		if part:FindFirstChildOfClass("Smoke") then cls.kind = (cls.kind == "fire") and "fire" or "smoke" end
		if part:FindFirstChildWhichIsA("Light", true)
			or part:FindFirstChildOfClass("PointLight")
			or part:FindFirstChildOfClass("SpotLight")
			or part:FindFirstChildOfClass("SurfaceLight") then
			if cls.kind == "generic" then cls.kind = "light" end
		end

		if mat == Enum.Material.Water or hasWord(name, WATER_WORDS) then
			cls.isWater = true
			if cls.kind == "generic" then cls.kind = "water" end
		end
		if mat == Enum.Material.Glass or mat == Enum.Material.ForceField then
			cls.isGlass = true
			if cls.kind == "generic" then cls.kind = "glass" end
		end
		if mat == Enum.Material.Metal or mat == Enum.Material.DiamondPlate
			or mat == Enum.Material.Foil or mat == Enum.Material.CorrodedMetal then
			cls.isMetal = true
			if cls.kind == "generic" then cls.kind = "metal" end
		end
		if mat == Enum.Material.Grass or mat == Enum.Material.LeafyGrass or hasWord(name, FOLIAGE_WORDS) then
			cls.isFoliage = true
			if cls.kind == "generic" then cls.kind = "foliage" end
		end

		-- FLOOR: tagged, OR a big upward-facing top face. Top face normal of a part
		-- in world space is its CFrame.UpVector. Area of the top face = X*Z.
		if tagged then
			cls.isFloor = true
			cls.kind = "floor"
		else
			local up = part.CFrame.UpVector
			local upish = up:Dot(Vector3.yAxis) > 0.85
			local size = part.Size
			local area = size.X * size.Z
			local flatish = size.Y <= math.max(size.X, size.Z) -- platey, not a tall wall
			if upish and flatish and area >= 100 then
				cls.isFloor = true
				if cls.kind == "generic" or cls.kind == "metal" or cls.kind == "glass" then
					cls.kind = "floor"
				end
			end
		end

		return cls
	end

	local function removeFromSets(part)
		for _, set in pairs(sets) do set[part] = nil end
	end

	local function addToSets(part, cls)
		removeFromSets(part)
		sets[cls.kind][part] = true
		-- floors also live in their own boolean flag regardless of primary kind
		if cls.isFloor then sets.floor[part] = true end
	end

	-- classify + cache + announce
	function Scanner.classify(part)
		if not (part and part:IsA("BasePart")) then return nil end
		local existing = cache[part]
		if existing then return existing end
		local ok, cls = pcall(compute, part)
		if not ok or not cls then return nil end
		cache[part] = cls
		addToSets(part, cls)
		Scanner.onClassified:Fire(part, cls)
		return cls
	end

	local function setToArray(set)
		local out = {}
		for part in pairs(set) do
			if part.Parent then out[#out + 1] = part end
		end
		return out
	end

	function Scanner.getFloors() return setToArray(sets.floor) end
	function Scanner.getByKind(kind)
		local set = sets[kind]
		return set and setToArray(set) or {}
	end

	local function enqueue(part)
		if part and part:IsA("BasePart") and not queued[part] and not cache[part] then
			queued[part] = true
			queue[#queue + 1] = part
		end
	end

	function Scanner.rescan()
		table.clear(cache)
		table.clear(queued)
		table.clear(queue)
		for _, set in pairs(sets) do table.clear(set) end
		for _, d in ipairs(workspace:GetDescendants()) do enqueue(d) end
	end

	function Scanner.setQuality(q)
		qualityMul = math.clamp(q, 0.25, 1)
	end

	-- ── lifecycle ─────────────────────────────────────────────────────────────
	function Scanner.start(ctx)
		local maid = ctx.maid:childMaid()
		Scanner._maid = maid
		local RunService = ctx.services.RunService

		-- initial sweep (queued, drained over frames — never all at once)
		for _, d in ipairs(workspace:GetDescendants()) do enqueue(d) end

		-- streaming: enroll new parts; reclassify holders when an emitter/light is added
		maid:give(workspace.DescendantAdded:Connect(function(inst)
			if inst:IsA("BasePart") then
				enqueue(inst)
			elseif inst:IsA("Fire") or inst:IsA("Smoke") or inst:IsA("Light") then
				local p = inst.Parent
				if p and p:IsA("BasePart") then
					cache[p] = nil  -- force reclassify so it lands in fire/smoke/light set
					enqueue(p)
				end
			end
		end))
		maid:give(workspace.DescendantRemoving:Connect(function(inst)
			if inst:IsA("BasePart") then
				cache[inst] = nil
				queued[inst] = nil
				removeFromSets(inst)
			end
		end))

		-- drain loop: budgeted parts/frame
		maid:give(RunService.Heartbeat:Connect(function()
			if #queue == 0 then return end
			local budget = math.max(8, math.floor(State.get("perf_scanner_budget") * qualityMul))
			local processed = 0
			while processed < budget and #queue > 0 do
				local part = table.remove(queue)
				if part then
					queued[part] = nil
					if part.Parent then Scanner.classify(part) end
				end
				processed += 1
			end
		end))

		ctx.log.debug("Scanner online; initial queue =", #queue)
		return Scanner
	end

	function Scanner.stop()
		if Scanner._maid then Scanner._maid:clean() end
	end

	return Scanner
end

end)()

__modules["materials/PBR"] = (function()
--!nonstrict
--[[
	materials/PBR.lua  —  CONTROLLER (manifest.boot, started 2nd)
	-----------------------------------------------------------------------------
	Material → PBR classifier + global reflectance/roughness bias pass.

	WHY: Roblox parts only expose Material + Reflectance, not a real PBR stack.
	We approximate per-material roughness / metalness / F0 (Fresnel reflectance at
	normal incidence) from a static lookup so Reflections and the Scanner can reason
	about how shiny a surface "should" be, then nudge Reflectance toward that via
	Snapshot (so originals restore on unload).

	PBR.props(materialEnum) is a PURE static lookup — safe to call without start().
	The Scanner calls it during classification, so it must not depend on ctx.

	HONESTY: this is a heuristic material model, not a measured BRDF. We never claim
	metalness/roughness maps exist on stock parts; SurfaceAppearance work is opt-in
	and only touches author-flagged surfaces (see _applySurfaceAppearance).
]]

return function(require)
	local State = require("core/State")
	local Util = require("core/Util")

	local PBR = {}
	PBR.id = "materials/PBR"

	-- ── static material table ────────────────────────────────────────────────
	-- roughness 0(mirror)..1(matte), metalness 0..1, f0 reflectance at normal angle.
	-- Tuned by eye for a filmic look; reflectance is the *baseline* we may bias up.
	local M = Enum.Material
	local TABLE = {
		[M.Plastic]        = { roughness = 0.55, metalness = 0.0, f0 = 0.04 },
		[M.SmoothPlastic]  = { roughness = 0.30, metalness = 0.0, f0 = 0.05 },
		[M.Neon]           = { roughness = 0.20, metalness = 0.0, f0 = 0.02 },
		[M.Glass]          = { roughness = 0.05, metalness = 0.0, f0 = 0.08 },
		[M.ForceField]     = { roughness = 0.10, metalness = 0.0, f0 = 0.05 },
		[M.Metal]          = { roughness = 0.28, metalness = 1.0, f0 = 0.85 },
		[M.DiamondPlate]   = { roughness = 0.40, metalness = 1.0, f0 = 0.80 },
		[M.Foil]           = { roughness = 0.22, metalness = 1.0, f0 = 0.88 },
		[M.CorrodedMetal]  = { roughness = 0.70, metalness = 0.9, f0 = 0.55 },
		[M.Wood]           = { roughness = 0.75, metalness = 0.0, f0 = 0.04 },
		[M.WoodPlanks]     = { roughness = 0.78, metalness = 0.0, f0 = 0.04 },
		[M.Marble]         = { roughness = 0.22, metalness = 0.0, f0 = 0.06 },
		[M.Granite]        = { roughness = 0.55, metalness = 0.0, f0 = 0.05 },
		[M.Slate]          = { roughness = 0.60, metalness = 0.0, f0 = 0.05 },
		[M.Concrete]       = { roughness = 0.85, metalness = 0.0, f0 = 0.03 },
		[M.Pavement]       = { roughness = 0.88, metalness = 0.0, f0 = 0.03 },
		[M.Brick]          = { roughness = 0.90, metalness = 0.0, f0 = 0.03 },
		[M.Cobblestone]    = { roughness = 0.88, metalness = 0.0, f0 = 0.03 },
		[M.Sandstone]      = { roughness = 0.86, metalness = 0.0, f0 = 0.03 },
		[M.Limestone]      = { roughness = 0.80, metalness = 0.0, f0 = 0.04 },
		[M.Rock]           = { roughness = 0.82, metalness = 0.0, f0 = 0.04 },
		[M.Basalt]         = { roughness = 0.80, metalness = 0.0, f0 = 0.04 },
		[M.Sand]           = { roughness = 0.95, metalness = 0.0, f0 = 0.02 },
		[M.Mud]            = { roughness = 0.70, metalness = 0.0, f0 = 0.05 },
		[M.Ground]         = { roughness = 0.92, metalness = 0.0, f0 = 0.02 },
		[M.Grass]          = { roughness = 0.95, metalness = 0.0, f0 = 0.02 },
		[M.LeafyGrass]     = { roughness = 0.96, metalness = 0.0, f0 = 0.02 },
		[M.Fabric]         = { roughness = 0.98, metalness = 0.0, f0 = 0.02 },
		[M.Pebble]         = { roughness = 0.78, metalness = 0.0, f0 = 0.04 },
		[M.Asphalt]        = { roughness = 0.80, metalness = 0.0, f0 = 0.04 },
		[M.Ice]            = { roughness = 0.12, metalness = 0.0, f0 = 0.10 },
		[M.Glacier]        = { roughness = 0.18, metalness = 0.0, f0 = 0.09 },
		[M.Snow]           = { roughness = 0.85, metalness = 0.0, f0 = 0.03 },
		[M.Salt]           = { roughness = 0.80, metalness = 0.0, f0 = 0.03 },
		[M.CrackedLava]    = { roughness = 0.65, metalness = 0.0, f0 = 0.05 },
		[M.Water]          = { roughness = 0.08, metalness = 0.0, f0 = 0.06 },
	}
	local DEFAULT = { roughness = 0.6, metalness = 0.0, f0 = 0.04 }

	-- PURE lookup. Returns a *copy field* table augmented with a baseline reflectance.
	function PBR.props(material)
		local base = TABLE[material] or DEFAULT
		return {
			roughness = base.roughness,
			metalness = base.metalness,
			f0 = base.f0,
			-- baseline engine Reflectance we'd apply if the global pass is on:
			reflectance = base.metalness > 0.5 and base.f0 or (base.f0 * 0.5),
		}
	end

	-- ── global reflectance bias pass ─────────────────────────────────────────
	-- Applies Reflectance to metal/floor/glass parts the Scanner surfaces, biased
	-- by pbr_reflectance_bias / pbr_metal_boost. Foreign writes via Snapshot.
	function PBR.start(ctx)
		local maid = ctx.maid:childMaid()
		PBR._maid = maid
		local Snapshot = ctx.snapshot
		local log = ctx.log
		local q = ctx.getQuality()

		local Scanner = require("detection/Scanner") -- already started before us

		local function targetReflectance(part)
			local props = PBR.props(part.Material)
			local bias = State.get("pbr_reflectance_bias")
			local metalBoost = State.get("pbr_metal_boost")
			local r = props.reflectance + bias
			if props.metalness > 0.5 then
				r = Util.lerp(r, 0.9, metalBoost)
			end
			return Util.clamp(r, 0, 1)
		end

		local function apply(part)
			if not (part and part:IsA("BasePart")) then return end
			if not State.get("pbr_enabled") then return end
			local cls = Scanner.classify(part)
			-- Only touch surfaces where added reflectance reads as "intended":
			if cls.isMetal or cls.isGlass or cls.isFloor then
				Snapshot.set(part, "Reflectance", targetReflectance(part))
			end
		end

		-- enroll already-classified + future parts
		local function applyAll()
			if not State.get("pbr_enabled") then return end
			for _, p in ipairs(Scanner.getByKind("metal")) do apply(p) end
			for _, p in ipairs(Scanner.getByKind("glass")) do apply(p) end
			for _, p in ipairs(Scanner.getByKind("floor")) do apply(p) end
		end

		maid:give(Scanner.onClassified:Connect(function(part)
			apply(part)
		end))
		maid:give(State.observeMany(
			{ "pbr_enabled", "pbr_reflectance_bias", "pbr_metal_boost", "pbr_roughness_bias" },
			function() applyAll() end
		))

		-- first pass shortly after boot (Scanner needs a few frames to fill)
		maid:spawn(function()
			task.wait(0.5)
			applyAll()
		end)

		-- optional SurfaceAppearance scaffold (opt-in, author-flagged only)
		maid:give(State.observe("pbr_surface_appearance", function(on)
			if on then PBR._applySurfaceAppearance(ctx, Scanner) end
		end))

		log.debug("PBR pass online (q=" .. string.format("%.2f", q) .. ")")
		return PBR
	end

	-- Only acts on parts the author flagged by giving them string attributes
	-- "ColorMap"/"NormalMap"/"MetalnessMap"/"RoughnessMap" (rbxassetid). We ship no
	-- texture ids, so on stock places this is a safe no-op. Correct property names
	-- are ColorMap/NormalMap/MetalnessMap/RoughnessMap — NEVER AlbedoMap.
	function PBR._applySurfaceAppearance(ctx, Scanner)
		local Snapshot = ctx.snapshot
		for _, part in ipairs(Scanner.getByKind("metal")) do
			if part:IsA("MeshPart") or part:IsA("Part") then
				local color = part:GetAttribute("ColorMap")
				if type(color) == "string" and color ~= "" then
					if not part:FindFirstChildOfClass("SurfaceAppearance") then
						local sa = Snapshot.create("SurfaceAppearance", {
							ColorMap = color,
							NormalMap = part:GetAttribute("NormalMap") or "",
							MetalnessMap = part:GetAttribute("MetalnessMap") or "",
							RoughnessMap = part:GetAttribute("RoughnessMap") or "",
						}, part)
						ctx.log.debug("SurfaceAppearance applied to", part:GetFullName())
					end
				end
			end
		end
	end

	function PBR.setQuality(_q)
		-- Material bias is cheap; nothing to scale per quality.
	end

	function PBR.stop()
		if PBR._maid then PBR._maid:clean() end
	end

	return PBR
end

end)()

__modules["lighting/Lighting"] = (function()
--!nonstrict
--[[
	lighting/Lighting.lua  —  CONTROLLER (manifest.boot)
	-----------------------------------------------------------------------------
	Sole writer to Lighting's core properties. Applies every lighting_* config key
	and owns the Future-lighting capability gate. Also starts Atmosphere + Sky.

	WHY each lever (all REAL Lighting properties — no inventions):
	  Technology=Future ......... per-pixel lighting + soft shadows (gated by caps)
	  LightingStyle=Realistic ... newer realistic pipeline (gated by caps)
	  Brightness/ClockTime/GeographicLatitude ... key light + sun position
	  ExposureCompensation ...... overall EV (driven by EyeAdaptation via bus.exposure)
	  EnvironmentDiffuse/SpecularScale ... fakes GI + environment reflections
	  ShadowSoftness ............ Future-only penumbra
	  Ambient/OutdoorAmbient .... shadow + skylight fill
	  ColorShift_Top/Bottom ..... warm key / cool bounce tint

	Every foreign write goes through Snapshot so unload restores the game exactly.
]]

return function(require)
	local State = require("core/State")

	local Lighting = {}
	Lighting.id = "lighting/Lighting"

	function Lighting.start(ctx)
		local maid = ctx.maid:childMaid()
		Lighting._maid = maid
		local L = ctx.services.Lighting
		local Snapshot = ctx.snapshot
		local caps = ctx.platform.caps
		local log = ctx.log

		-- ── capability-gated technology/style ────────────────────────────────
		local function applyTechnology()
			if not State.get("lighting_enabled") then return end
			if State.get("lighting_future") and caps.futureLighting then
				Snapshot.set(L, "Technology", Enum.Technology.Future)
			end
			if caps.realisticLightingStyle then
				pcall(function() Snapshot.set(L, "LightingStyle", Enum.LightingStyle.Realistic) end)
			end
			if caps.prioritizeLightingQuality then
				pcall(function() Snapshot.set(L, "PrioritizeLightingQuality", true) end)
			end
		end

		-- ── direct property appliers, each keyed to its config ───────────────
		local appliers = {
			lighting_brightness    = function(v) Snapshot.set(L, "Brightness", v) end,
			lighting_clock_time    = function(v) Snapshot.set(L, "ClockTime", v) end,
			lighting_geo_latitude  = function(v) Snapshot.set(L, "GeographicLatitude", v) end,
			lighting_global_shadows= function(v) Snapshot.set(L, "GlobalShadows", v) end,
			lighting_ambient       = function(v) Snapshot.set(L, "Ambient", v) end,
			lighting_outdoor_ambient = function(v) Snapshot.set(L, "OutdoorAmbient", v) end,
			lighting_env_diffuse   = function(v) Snapshot.set(L, "EnvironmentDiffuseScale", v) end,
			lighting_env_specular  = function(v) Snapshot.set(L, "EnvironmentSpecularScale", v) end,
			lighting_color_shift_top    = function(v) Snapshot.set(L, "ColorShift_Top", v) end,
			lighting_color_shift_bottom = function(v) Snapshot.set(L, "ColorShift_Bottom", v) end,
			lighting_shadow_softness = function(v)
				if caps.shadowSoftness then Snapshot.set(L, "ShadowSoftness", v) end
			end,
		}

		local function applyAll()
			if not State.get("lighting_enabled") then return end
			applyTechnology()
			for key, fn in pairs(appliers) do
				fn(State.get(key))
			end
			-- exposure: if eye-adaptation is off, apply the static config value now.
			if not State.get("eye_adapt_enabled") then
				Snapshot.set(L, "ExposureCompensation", State.get("lighting_exposure"))
			end
		end

		-- live updates per key
		for key, fn in pairs(appliers) do
			maid:give(State.observe(key, function(v)
				if State.get("lighting_enabled") then fn(v) end
			end))
		end
		maid:give(State.observe("lighting_future", function() applyTechnology() end))
		maid:give(State.observe("lighting_exposure", function(v)
			if not State.get("eye_adapt_enabled") then
				Snapshot.set(L, "ExposureCompensation", v)
			end
		end))
		maid:give(State.observe("lighting_enabled", function(on)
			if on then applyAll() end
			-- when toggled off we leave Snapshot to restore on teardown; live revert
			-- of a single subsystem is intentionally a no-op to avoid fighting others.
		end))

		-- ── exposure bridge ──────────────────────────────────────────────────
		-- EyeAdaptation writes bus.exposure each frame; we push it to the engine
		-- here (Lighting is the sole writer to ExposureCompensation). Throttled.
		local accum = 0
		maid:give(ctx.services.RunService.Heartbeat:Connect(function(dt)
			accum += dt
			if accum < 0.05 then return end
			accum = 0
			if State.get("lighting_enabled") and State.get("eye_adapt_enabled") then
				local e = ctx.bus.exposure
				if type(e) == "number" then
					Snapshot.set(L, "ExposureCompensation", e)
				end
			end
		end))

		applyAll()

		-- start sub-systems
		for _, name in ipairs({ "lighting/Atmosphere", "lighting/Sky" }) do
			local ok, handle = pcall(function()
				local m = require(name)
				return m.start(ctx) or m
			end)
			if ok and handle then ctx.registerHandle(handle) else log.error("lighting sub failed:", name, handle) end
		end

		log.debug("Lighting online (future=" .. tostring(State.get("lighting_future") and caps.futureLighting) .. ")")
		return Lighting
	end

	function Lighting.stop()
		if Lighting._maid then Lighting._maid:clean() end
	end

	return Lighting
end

end)()

__modules["lighting/Tonemap"] = (function()
--!nonstrict
--[[
	lighting/Tonemap.lua  —  driver, started by postfx/Pipeline
	-----------------------------------------------------------------------------
	APPROXIMATE filmic / ACES tonemapping.

	HARD TRUTH: Roblox has no ACES node, no tonemap operator, no LUT pass. The best
	legal approximation of a filmic response is a dedicated ColorCorrectionEffect
	tuned for toe/shoulder contrast + a slight desaturation, applied BEFORE the
	creative grade, working together with ExposureCompensation. This module DRIVES
	that pre-grade CCE (created + owned by postfx/Pipeline, published on
	bus.pipeline.tonemapCCE). It never creates the effect itself.

	The four "modes" are not real curves — they are different contrast/saturation
	bias presets that *evoke* ACES / Filmic / Reinhard / Neutral responses. Comments
	below state the intent of each so nobody mistakes this for a true operator.
]]

return function(require)
	local State = require("core/State")
	local Util = require("core/Util")

	local Tonemap = {}
	Tonemap.id = "lighting/Tonemap"

	-- contrast/saturation multipliers that lean the CCE toward each look.
	local MODES = {
		ACES     = { contrastMul = 1.0,  satBias = -0.04 }, -- punchy toe, slightly desaturated highlights
		Filmic   = { contrastMul = 0.9,  satBias = -0.02 }, -- gentler shoulder
		Reinhard = { contrastMul = 0.7,  satBias =  0.00 }, -- soft, low-contrast roll-off
		Neutral  = { contrastMul = 0.5,  satBias =  0.02 }, -- nearly linear, minimal grade
	}

	function Tonemap.start(ctx)
		local maid = ctx.maid:childMaid()
		Tonemap._maid = maid

		local function cce()
			return ctx.bus.pipeline and ctx.bus.pipeline.tonemapCCE or nil
		end

		local function apply()
			local effect = cce()
			if not effect then return end
			local enabled = State.get("tonemap_enabled")
			effect.Enabled = enabled
			if not enabled then return end
			local mode = MODES[State.get("tonemap_mode")] or MODES.ACES
			local contrast = State.get("tonemap_contrast") * mode.contrastMul
			local sat = State.get("tonemap_saturation") + mode.satBias
			-- white point biases brightness slightly (>1 lifts, <1 lowers) to mimic
			-- a shoulder that rolls highlights off before the creative grade.
			local wp = State.get("tonemap_white_point")
			effect.Contrast = Util.clamp(contrast, -1, 1)
			effect.Saturation = Util.clamp(sat, -1, 1)
			effect.Brightness = Util.clamp((wp - 1) * 0.15, -0.3, 0.3)
		end

		-- the CCE may not exist the instant we start (Pipeline starts us right after
		-- creating it, but be defensive): poll briefly until present, then wire.
		maid:spawn(function()
			local tries = 0
			while not cce() and tries < 60 do
				task.wait(0.05)
				tries += 1
			end
			apply()
		end)

		maid:give(State.observeMany(
			{ "tonemap_enabled", "tonemap_mode", "tonemap_contrast", "tonemap_saturation", "tonemap_white_point" },
			apply))

		ctx.log.debug("Tonemap driver online")
		return Tonemap
	end

	function Tonemap.stop()
		if Tonemap._maid then Tonemap._maid:clean() end
	end

	return Tonemap
end

end)()

__modules["lighting/Atmosphere"] = (function()
--!nonstrict
--[[
	lighting/Atmosphere.lua
	-----------------------------------------------------------------------------
	Owns a single Atmosphere instance under Lighting. Atmosphere is the modern,
	physically-flavoured fog (preferred over legacy FogStart/End) and gives the
	deep, hazy distance falloff that reads as "cinematic depth".

	All properties used are REAL: Density, Offset, Color, Decay, Glare, Haze.

	We create OUR OWN tagged Atmosphere rather than mutating a pre-existing one,
	but if the place already ships an Atmosphere we capture+disable it (via
	Snapshot, so it restores) so there are not two stacking. On teardown ours is
	destroyed and the original re-enabled.
]]

return function(require)
	local State = require("core/State")

	local Atmosphere = {}
	Atmosphere.id = "lighting/Atmosphere"

	function Atmosphere.start(ctx)
		local maid = ctx.maid:childMaid()
		Atmosphere._maid = maid
		local L = ctx.services.Lighting
		local Snapshot = ctx.snapshot

		-- If the game already has an Atmosphere, neutralise it non-destructively by
		-- re-parenting under Lighting only ours. Roblox only honours the first
		-- Atmosphere child; to be safe we capture the existing one's Density to 0
		-- is not possible without mutating it, so instead we simply parent ours and
		-- let the engine pick one. Simplest robust path: reuse the existing one if
		-- present (capture all props), else create our own tagged one.
		local atmos = L:FindFirstChildOfClass("Atmosphere")
		local owned = false
		if not atmos then
			atmos = Snapshot.create("Atmosphere", { Name = "CinematicAtmosphere" }, L)
			owned = true
		end
		Atmosphere._inst = atmos

		local appliers = {
			atmos_density = function(v) Snapshot.set(atmos, "Density", v) end,
			atmos_offset  = function(v) Snapshot.set(atmos, "Offset", v) end,
			atmos_color   = function(v) Snapshot.set(atmos, "Color", v) end,
			atmos_decay   = function(v) Snapshot.set(atmos, "Decay", v) end,
			atmos_glare   = function(v) Snapshot.set(atmos, "Glare", v) end,
			atmos_haze    = function(v) Snapshot.set(atmos, "Haze", v) end,
		}

		local function applyAll()
			if not State.get("atmos_enabled") then
				-- soften to near-nothing when disabled (Density 0); restored on unload
				Snapshot.set(atmos, "Density", 0)
				return
			end
			for key, fn in pairs(appliers) do fn(State.get(key)) end
		end

		for key, fn in pairs(appliers) do
			maid:give(State.observe(key, function(v)
				if State.get("atmos_enabled") then fn(v) end
			end))
		end
		maid:give(State.observe("atmos_enabled", function() applyAll() end))

		applyAll()
		ctx.log.debug("Atmosphere online (owned=" .. tostring(owned) .. ")")
		return Atmosphere
	end

	function Atmosphere.stop()
		if Atmosphere._maid then Atmosphere._maid:clean() end
	end

	return Atmosphere
end

end)()

__modules["lighting/Sky"] = (function()
--!nonstrict
--[[
	lighting/Sky.lua
	-----------------------------------------------------------------------------
	Owns a Sky (under Lighting) and a Clouds (under workspace.Terrain).

	HARD TRUTH: clouds are a `Clouds` instance parented to workspace.Terrain — there
	is NO "Atmosphere clouds" object. Sky properties used are all REAL: SkyboxUp/Dn/
	Lf/Rt/Ft/Bk, SunAngularSize, MoonAngularSize, StarCount, CelestialBodiesShown.

	Skybox FACE ids are intentionally left blank in the presets below — we ship no
	texture assets, and pointing faces at an invalid id would look worse than the
	game's own sky. Presets therefore tune sun/moon/stars/celestial bodies and you
	can paste your own face asset ids into SKY_PRESETS to get full skybox swaps.
]]

return function(require)
	local State = require("core/State")

	local Sky = {}
	Sky.id = "lighting/Sky"

	-- Paste rbxassetid strings into the face fields to enable full skybox swaps.
	-- Leaving a face as "" means "leave the existing sky face untouched".
	local SKY_PRESETS = {
		["Default"]     = { stars = 3000, celestial = true,  sun = 21, moon = 11 },
		["Clear Blue"]  = { stars = 1500, celestial = true,  sun = 21, moon = 11 },
		["Golden Dusk"] = { stars = 2200, celestial = true,  sun = 28, moon = 13 },
		["Overcast"]    = { stars = 800,  celestial = false, sun = 16, moon = 9 },
		["Night Stars"] = { stars = 7000, celestial = true,  sun = 12, moon = 22 },
		-- faces = { up=, dn=, lf=, rt=, ft=, bk= }   ← add your own ids here
	}

	function Sky.start(ctx)
		local maid = ctx.maid:childMaid()
		Sky._maid = maid
		local L = ctx.services.Lighting
		local Snapshot = ctx.snapshot

		-- own a Sky (reuse existing if present so we don't double up)
		local sky = L:FindFirstChildOfClass("Sky")
		if not sky then
			sky = Snapshot.create("Sky", { Name = "CinematicSky" }, L)
		end
		Sky._sky = sky

		-- own a Clouds under Terrain (guard Terrain existence on void places)
		local terrain = ctx.services.Workspace:FindFirstChildOfClass("Terrain")
		local clouds
		if terrain then
			clouds = terrain:FindFirstChildOfClass("Clouds")
			if not clouds then
				clouds = Snapshot.create("Clouds", { Name = "CinematicClouds" }, terrain)
			end
			Sky._clouds = clouds
		end

		local function applySky()
			if not State.get("sky_enabled") then return end
			local preset = SKY_PRESETS[State.get("sky_preset")] or SKY_PRESETS.Default
			-- sun/moon/stars come from explicit config keys (preset seeds defaults)
			Snapshot.set(sky, "SunAngularSize", State.get("sky_sun_size"))
			Snapshot.set(sky, "MoonAngularSize", State.get("sky_moon_size"))
			Snapshot.set(sky, "StarCount", State.get("sky_star_count"))
			pcall(function() Snapshot.set(sky, "CelestialBodiesShown", preset.celestial) end)
			-- optional face swaps when the preset carries ids
			if preset.faces then
				local f = preset.faces
				if f.up and f.up ~= "" then Snapshot.set(sky, "SkyboxUp", f.up) end
				if f.dn and f.dn ~= "" then Snapshot.set(sky, "SkyboxDn", f.dn) end
				if f.lf and f.lf ~= "" then Snapshot.set(sky, "SkyboxLf", f.lf) end
				if f.rt and f.rt ~= "" then Snapshot.set(sky, "SkyboxRt", f.rt) end
				if f.ft and f.ft ~= "" then Snapshot.set(sky, "SkyboxFt", f.ft) end
				if f.bk and f.bk ~= "" then Snapshot.set(sky, "SkyboxBk", f.bk) end
			end
		end

		local function applyClouds()
			if not clouds then return end
			local on = State.get("clouds_enabled")
			Snapshot.set(clouds, "Enabled", on)
			if on then
				Snapshot.set(clouds, "Cover", State.get("clouds_cover"))
				Snapshot.set(clouds, "Density", State.get("clouds_density"))
				Snapshot.set(clouds, "Color", State.get("clouds_color"))
			end
		end

		maid:give(State.observeMany(
			{ "sky_enabled", "sky_preset", "sky_sun_size", "sky_moon_size", "sky_star_count" },
			applySky))
		maid:give(State.observeMany(
			{ "clouds_enabled", "clouds_cover", "clouds_density", "clouds_color" },
			applyClouds))

		applySky()
		applyClouds()
		ctx.log.debug("Sky online (clouds=" .. tostring(clouds ~= nil) .. ")")
		return Sky
	end

	function Sky.stop()
		if Sky._maid then Sky._maid:clean() end
	end

	return Sky
end

end)()

__modules["postfx/Pipeline"] = (function()
--!nonstrict
--[[
	postfx/Pipeline.lua  —  CONTROLLER (manifest.boot)
	-----------------------------------------------------------------------------
	Creates and OWNS every post-processing Instance and the render budget.

	The ONLY real post-processing effects in Roblox are: BloomEffect, BlurEffect,
	ColorCorrectionEffect, DepthOfFieldEffect, SunRaysEffect. We create two CCEs —
	a TONEMAP CCE (filmic approximation, applied first conceptually) and a GRADE CCE
	(creative look). We do NOT control the exact inter-effect compositing order the
	engine uses; we only control which effects exist and their values.

	All instances are parented to Lighting via Snapshot (so they restore/destroy on
	unload) and PUBLISHED on ctx.bus.pipeline so sibling modules (Tonemap, Bloom,
	ColorGrade, DoFAuto, EyeAdaptation, Lightning, MotionBlur) can drive them without
	owning their lifecycle.

	Faked overlays (vignette/grain/dither/chromatic/letterbox/motion-blur) are NOT
	post-effects — those live in their own driver modules drawing GUI overlays.
]]

return function(require)
	local State = require("core/State")

	local Pipeline = {}
	Pipeline.id = "postfx/Pipeline"
	local drivers = {}

	function Pipeline.start(ctx)
		local maid = ctx.maid:childMaid()
		Pipeline._maid = maid
		local L = ctx.services.Lighting
		local Snapshot = ctx.snapshot

		-- Create owned effects. Tonemap CCE created FIRST (intent: pre-grade).
		local tonemapCCE = Snapshot.create("ColorCorrectionEffect", {
			Name = "CinematicTonemap", Enabled = true,
		}, L)
		local gradeCCE = Snapshot.create("ColorCorrectionEffect", {
			Name = "CinematicGrade", Enabled = true,
		}, L)
		local bloom = Snapshot.create("BloomEffect", { Name = "CinematicBloom", Enabled = true }, L)
		local dof = Snapshot.create("DepthOfFieldEffect", { Name = "CinematicDoF", Enabled = true }, L)
		local blur = Snapshot.create("BlurEffect", { Name = "CinematicBlur", Size = 0, Enabled = true }, L)
		local sunrays = Snapshot.create("SunRaysEffect", { Name = "CinematicSunRays", Enabled = true }, L)

		-- Publish for cross-module access (READ-only for others; we own lifecycle).
		ctx.bus.pipeline = {
			tonemapCCE = tonemapCCE,
			gradeCCE = gradeCCE,
			bloom = bloom,
			dof = dof,
			blur = blur,
			sunrays = sunrays,
		}

		Pipeline.getEffect = function(name)
			return ctx.bus.pipeline[name]
		end

		-- Sun rays from a simple coupling to atmosphere glare feel.
		local function applySunRays()
			Snapshot.set(sunrays, "Intensity", 0.1)
			Snapshot.set(sunrays, "Spread", 0.9)
		end
		applySunRays()

		-- Start the driver sub-modules. lighting/Tonemap is included here because it
		-- drives the tonemap CCE this Pipeline owns.
		local subs = {
			"lighting/Tonemap",
			"postfx/Bloom", "postfx/ColorGrade", "postfx/DepthOfField",
			"postfx/Vignette", "postfx/FilmGrain", "postfx/Dither",
			"postfx/Chromatic", "postfx/Letterbox",
		}
		for _, name in ipairs(subs) do
			local ok, handle = pcall(function()
				local m = require(name)
				return m.start(ctx) or m
			end)
			if ok and handle then
				drivers[#drivers + 1] = handle
				ctx.registerHandle(handle)
			else
				ctx.log.error("postfx sub failed:", name, handle)
			end
		end

		ctx.log.debug("Pipeline online; effects published on bus.pipeline")
		return Pipeline
	end

	function Pipeline.setQuality(q)
		for _, d in ipairs(drivers) do
			if type(d.setQuality) == "function" then pcall(d.setQuality, q) end
		end
	end

	function Pipeline.stop()
		if Pipeline._maid then Pipeline._maid:clean() end
	end

	return Pipeline
end

end)()

