__modules["postfx/Vignette"] = (function()
--!nonstrict
--[[
	postfx/Vignette.lua  —  FAKED overlay
	-----------------------------------------------------------------------------
	There is NO native vignette post-effect in Roblox. We fake edge darkening with
	four black edge Frames, each carrying a UIGradient whose transparency ramps from
	opaque (screen edge) to transparent (inward). Overlapping corners read darkest —
	exactly what a lens vignette does.

	This is a GUI overlay: it darkens pixels but does NOT anti-alias or affect the
	3D scene. NumberSequences are cached and only rebuilt when intensity changes
	(never per-frame).
]]

return function(require)
	local State = require("core/State")

	local Vignette = {}
	Vignette.id = "postfx/Vignette"

	function Vignette.start(ctx)
		local maid = ctx.maid:childMaid()
		Vignette._maid = maid
		local Snapshot = ctx.snapshot

		local root = Snapshot.create("Frame", {
			Name = "Vignette",
			BackgroundTransparency = 1,
			Size = UDim2.fromScale(1, 1),
			ZIndex = 50,
			Active = false,            -- never intercept input
		}, ctx.gui)

		-- (size, position, gradientRotation, edgeAtOffset0)
		-- edgeAtOffset0=true means offset 0 is the opaque screen edge.
		local edges = {
			{ UDim2.fromScale(1, 0.32), UDim2.fromScale(0, 0),    90, true  }, -- top
			{ UDim2.fromScale(1, 0.32), UDim2.fromScale(0, 0.68), 90, false }, -- bottom
			{ UDim2.fromScale(0.32, 1), UDim2.fromScale(0, 0),    0,  true  }, -- left
			{ UDim2.fromScale(0.32, 1), UDim2.fromScale(0.68, 0), 0,  false }, -- right
		}

		local gradients = {}
		for _, e in ipairs(edges) do
			local frame = Snapshot.create("Frame", {
				BackgroundColor3 = Color3.new(0, 0, 0),
				BackgroundTransparency = 0,
				BorderSizePixel = 0,
				Size = e[1], Position = e[2],
				ZIndex = 50, Active = false,
			}, root)
			local grad = Snapshot.create("UIGradient", { Rotation = e[3] }, frame)
			gradients[#gradients + 1] = { grad = grad, edgeAtZero = e[4] }
		end

		local function rebuild(intensity)
			-- opaque-end alpha = 1-intensity (Transparency 0 = fully opaque black)
			local opaque = 1 - math.clamp(intensity, 0, 1)
			for _, g in ipairs(gradients) do
				local seq
				if g.edgeAtZero then
					seq = NumberSequence.new({
						NumberSequenceKeypoint.new(0, opaque),
						NumberSequenceKeypoint.new(1, 1),
					})
				else
					seq = NumberSequence.new({
						NumberSequenceKeypoint.new(0, 1),
						NumberSequenceKeypoint.new(1, opaque),
					})
				end
				g.grad.Transparency = seq
			end
		end

		local function apply()
			local on = State.get("overlay_vignette")
			root.Visible = on
			if on then rebuild(State.get("overlay_vignette_intensity")) end
		end

		maid:give(State.observeMany({ "overlay_vignette", "overlay_vignette_intensity" }, apply))
		apply()
		return Vignette
	end

	function Vignette.stop()
		if Vignette._maid then Vignette._maid:clean() end
	end

	return Vignette
end

end)()

__modules["postfx/FilmGrain"] = (function()
--!nonstrict
--[[
	postfx/FilmGrain.lua  —  FAKED overlay
	-----------------------------------------------------------------------------
	There is NO native film-grain effect. We author animated monochrome noise into a
	small EditableImage (CPU pixel work) tiled across the screen at low opacity, and
	regenerate it a few times a second for the "moving grain" look.

	EditableImage requires an ID-verified 13+ creator in published places, so it is
	FEATURE-DETECTED (ctx.platform.caps.editableImage). When unavailable we degrade
	to a very subtle full-screen alpha flicker (a crude luminance dither) rather than
	failing. The pixel buffer is reused in-place — no per-frame table allocation; the
	regen itself is throttled (~8 Hz), not per-frame.
]]

return function(require)
	local State = require("core/State")

	local FilmGrain = {}
	FilmGrain.id = "postfx/FilmGrain"

	local SIZE = 128
	local PIXELS = SIZE * SIZE
	local qualityMul = 1

	function FilmGrain.start(ctx)
		local maid = ctx.maid:childMaid()
		FilmGrain._maid = maid
		local Snapshot = ctx.snapshot
		local Util = ctx.util
		local rng = Random.new(1337)

		local label = Snapshot.create("ImageLabel", {
			Name = "FilmGrain",
			BackgroundTransparency = 1,
			Size = UDim2.fromScale(1, 1),
			ScaleType = Enum.ScaleType.Tile,
			TileSize = UDim2.fromOffset(SIZE, SIZE),
			ImageTransparency = 1,
			ZIndex = 60, Active = false,
		}, ctx.gui)

		local editable, writeFn
		if ctx.platform.caps.editableImage then
			editable, writeFn = Util.bindEditableImage(label, SIZE)
		end

		-- reused RGBA buffer (flat, 0..1). Allocated ONCE.
		local buffer = table.create(PIXELS * 4, 0)

		local function regen()
			-- monochrome noise into alpha; rgb white so tint stays neutral.
			for i = 0, PIXELS - 1 do
				local n = rng:NextNumber()
				local o = i * 4
				buffer[o + 1] = 1
				buffer[o + 2] = 1
				buffer[o + 3] = 1
				buffer[o + 4] = n -- alpha (final opacity scaled by ImageTransparency)
			end
			if writeFn then writeFn(buffer) end
		end

		if writeFn then
			regen()
		else
			ctx.log.debug("FilmGrain: EditableImage unavailable — using alpha-flicker fallback")
		end

		local accum = 0
		maid:give(ctx.services.RunService.Heartbeat:Connect(function(dt)
			if not State.get("overlay_grain") then
				if label.Visible then label.Visible = false end
				return
			end
			label.Visible = true
			local intensity = State.get("overlay_grain_intensity") * qualityMul
			accum += dt
			if writeFn then
				label.ImageTransparency = 1 - math.clamp(intensity, 0, 1)
				if accum >= 0.12 then -- ~8 Hz regen
					accum = 0
					regen()
				end
			else
				-- fallback: gentle per-frame alpha flicker on a flat tint
				label.ImageTransparency = 1 - math.clamp(intensity, 0, 1) * (0.5 + 0.5 * rng:NextNumber()) * 0.25
			end
		end))

		return FilmGrain
	end

	function FilmGrain.setQuality(q)
		qualityMul = math.clamp(q, 0, 1)
	end

	function FilmGrain.stop()
		if FilmGrain._maid then FilmGrain._maid:clean() end
	end

	return FilmGrain
end

end)()

__modules["postfx/Dither"] = (function()
--!nonstrict
--[[
	postfx/Dither.lua  —  FAKED overlay
	-----------------------------------------------------------------------------
	A near-transparent tiled blue-noise overlay that breaks up the visible banding
	you get in smooth gradients (skies, fog, soft bloom). Authored once into a small
	EditableImage and left static (unlike grain it does not animate).

	HARD TRUTH: this hides 8-bit gradient banding; it does NOT anti-alias 3D edges —
	the engine gives us no MSAA/FXAA control. Feature-detected; no-op (with a logged
	note) when EditableImage is unavailable.
]]

return function(require)
	local State = require("core/State")

	local Dither = {}
	Dither.id = "postfx/Dither"

	local SIZE = 64
	local PIXELS = SIZE * SIZE

	function Dither.start(ctx)
		local maid = ctx.maid:childMaid()
		Dither._maid = maid

		if not ctx.platform.caps.editableImage then
			ctx.log.debug("Dither: EditableImage unavailable — skipped")
			return Dither
		end

		local Snapshot = ctx.snapshot
		local Util = ctx.util
		local rng = Random.new(7)

		local label = Snapshot.create("ImageLabel", {
			Name = "Dither",
			BackgroundTransparency = 1,
			Size = UDim2.fromScale(1, 1),
			ScaleType = Enum.ScaleType.Tile,
			TileSize = UDim2.fromOffset(SIZE, SIZE),
			ImageTransparency = 0.96,
			ZIndex = 61, Active = false,
		}, ctx.gui)

		local editable, writeFn = Util.bindEditableImage(label, SIZE)
		if not writeFn then
			ctx.log.debug("Dither: EditableImage bind failed — skipped")
			label:Destroy()
			return Dither
		end

		-- static blue-ish noise: high-frequency, value-balanced around mid-grey so it
		-- nudges pixels both up and down across a band edge.
		local buffer = table.create(PIXELS * 4, 0)
		for i = 0, PIXELS - 1 do
			local n = rng:NextNumber()
			local o = i * 4
			buffer[o + 1] = n
			buffer[o + 2] = n
			buffer[o + 3] = n
			buffer[o + 4] = 1
		end
		writeFn(buffer)

		local function apply()
			local on = State.get("overlay_dither")
			label.Visible = on
		end
		maid:give(State.observe("overlay_dither", apply))
		apply()

		return Dither
	end

	function Dither.stop()
		if Dither._maid then Dither._maid:clean() end
	end

	return Dither
end

end)()

__modules["postfx/Chromatic"] = (function()
--!nonstrict
--[[
	postfx/Chromatic.lua  —  FAKED overlay (chromatic aberration)
	-----------------------------------------------------------------------------
	There is NO native chromatic-aberration post-effect in Roblox. Real CA resamples
	the framebuffer per colour channel with a radial offset that grows toward the
	edges — we have NO framebuffer access, so a true version is impossible.

	What we CAN do legally is paint subtle COLOUR FRINGING at the screen edges: a red
	gradient bleeding in from the left edge and a complementary blue/cyan gradient
	from the right. That reproduces the *visual signature* of lens CA (coloured edge
	fringe) without claiming to be the real per-channel resample. Kept deliberately
	subtle (capped alpha) so it reads as a lens artefact, not a colour wash.

	GUI overlay only: does not anti-alias or alter the 3D scene. Sequences cached;
	rebuilt only when intensity changes.
]]

return function(require)
	local State = require("core/State")

	local Chromatic = {}
	Chromatic.id = "postfx/Chromatic"

	function Chromatic.start(ctx)
		local maid = ctx.maid:childMaid()
		Chromatic._maid = maid
		local Snapshot = ctx.snapshot

		local root = Snapshot.create("Frame", {
			Name = "ChromaticAberration",
			BackgroundTransparency = 1,
			Size = UDim2.fromScale(1, 1),
			ZIndex = 48, Active = false,
		}, ctx.gui)

		-- two thin coloured edge bands, each faded inward by a UIGradient.
		local function edgeBand(color, posX)
			local f = Snapshot.create("Frame", {
				BackgroundColor3 = color, BorderSizePixel = 0,
				Size = UDim2.fromScale(0.14, 1), Position = UDim2.fromScale(posX, 0),
				ZIndex = 48, Active = false,
			}, root)
			local g = Snapshot.create("UIGradient", { Rotation = 0 }, f)
			return g
		end
		local leftG = edgeBand(Color3.fromRGB(255, 48, 48), 0)        -- opaque toward x=0
		local rightG = edgeBand(Color3.fromRGB(48, 150, 255), 0.86)   -- opaque toward x=1

		local function rebuild(intensity)
			-- cap fringe at ~45% alpha so it stays a subtle lens artefact.
			local opaque = 1 - math.clamp(intensity, 0, 1) * 0.45
			leftG.Transparency = NumberSequence.new({
				NumberSequenceKeypoint.new(0, opaque), NumberSequenceKeypoint.new(1, 1),
			})
			rightG.Transparency = NumberSequence.new({
				NumberSequenceKeypoint.new(0, 1), NumberSequenceKeypoint.new(1, opaque),
			})
		end

		local function apply()
			local on = State.get("overlay_chromatic")
			root.Visible = on
			if on then rebuild(State.get("overlay_chromatic_intensity")) end
		end

		maid:give(State.observeMany({ "overlay_chromatic", "overlay_chromatic_intensity" }, apply))
		apply()
		return Chromatic
	end

	function Chromatic.stop()
		if Chromatic._maid then Chromatic._maid:clean() end
	end

	return Chromatic
end

end)()

__modules["postfx/Letterbox"] = (function()
--!nonstrict
--[[
	postfx/Letterbox.lua  —  cinematic bars
	-----------------------------------------------------------------------------
	Two black bars (top + bottom) that crop the frame to a target aspect ratio
	(overlay_letterbox_ratio, e.g. 2.39 anamorphic scope). The bar height is derived
	from the live viewport aspect vs the target aspect, so it is correct on any
	screen and recomputes on resize. Bars tween in/out for a smooth reveal.

	This is the one "overlay" that is genuinely real (it IS just black bars) rather
	than an approximation of a shader effect. GUI Frames only — no scene impact.
]]

return function(require)
	local State = require("core/State")
	local Util = require("core/Util")

	local Letterbox = {}
	Letterbox.id = "postfx/Letterbox"

	function Letterbox.start(ctx)
		local maid = ctx.maid:childMaid()
		Letterbox._maid = maid
		local Snapshot = ctx.snapshot
		local TweenService = ctx.services.TweenService

		local top = Snapshot.create("Frame", {
			Name = "LetterboxTop", BackgroundColor3 = Color3.new(0, 0, 0), BorderSizePixel = 0,
			Size = UDim2.new(1, 0, 0, 0), Position = UDim2.fromScale(0, 0),
			ZIndex = 60, Active = false, Visible = false,
		}, ctx.gui)
		local bottom = Snapshot.create("Frame", {
			Name = "LetterboxBottom", BackgroundColor3 = Color3.new(0, 0, 0), BorderSizePixel = 0,
			Size = UDim2.new(1, 0, 0, 0), Position = UDim2.fromScale(0, 1), AnchorPoint = Vector2.new(0, 1),
			ZIndex = 60, Active = false, Visible = false,
		}, ctx.gui)

		local function barFraction()
			local cam = ctx.camera()
			local vp = (cam and cam.ViewportSize) or Vector2.new(16, 9)
			local viewAspect = vp.X / math.max(1, vp.Y)
			local target = State.get("overlay_letterbox_ratio")
			if target <= viewAspect then return 0 end             -- screen already wider
			return Util.clamp((1 - viewAspect / target) / 2, 0, 0.25)
		end

		local function apply(animate)
			local on = State.get("overlay_letterbox")
			local frac = on and barFraction() or 0
			local goal = UDim2.new(1, 0, frac, 0)
			top.Visible = frac > 0
			bottom.Visible = frac > 0
			if animate then
				local ti = TweenInfo.new(0.6, Enum.EasingStyle.Quad, Enum.EasingDirection.Out)
				pcall(function() TweenService:Create(top, ti, { Size = goal }):Play() end)
				pcall(function() TweenService:Create(bottom, ti, { Size = goal }):Play() end)
			else
				top.Size, bottom.Size = goal, goal
			end
		end

		maid:give(State.observeMany({ "overlay_letterbox", "overlay_letterbox_ratio" }, function() apply(true) end))
		local cam = ctx.camera()
		if cam then
			maid:give(cam:GetPropertyChangedSignal("ViewportSize"):Connect(function() apply(false) end))
		end
		apply(false)
		return Letterbox
	end

	function Letterbox.stop()
		if Letterbox._maid then Letterbox._maid:clean() end
	end

	return Letterbox
end

end)()

__modules["reflections/Reflections"] = (function()
--!nonstrict
--[[
	reflections/Reflections.lua  —  CONTROLLER (manifest.boot)
	-----------------------------------------------------------------------------
	Glossy / wet reflective floors + reflection-probe strategy selector.

	WHAT'S REAL vs APPROXIMATED (read this before judging the realism claim):
	  * REAL engine reflection: under Future lighting, a part's `Reflectance` plus
	    `EnvironmentSpecularScale` produces genuine environment-mapped reflections,
	    and `Glass` material gives SSR/refraction. We MAXIMISE this — it's the primary,
	    real reflection. Strength is driven by a Schlick-Fresnel term so floors get
	    more reflective at grazing angles, exactly like real surfaces.
	  * APPROXIMATED: local reflections of NEARBY geometry that environment maps miss.
	    That's what the probe strategies estimate (cheap sky tint, or roving raycasts).
	    This is an SSR APPROXIMATION, never true ray tracing.

	Floor classification is delegated to detection/Scanner (material-aware, tag-driven
	via CollectionService, cached) — not a per-frame area heuristic.

	The controller owns floor Reflectance + optional Glass sheen overlays; the active
	probe sub-module supplies a per-floor reflected colour for those overlays.
]]

return function(require)
	local State = require("core/State")
	local Util = require("core/Util")

	local Reflections = {}
	Reflections.id = "reflections/Reflections"

	local MAX_OVERLAYS = 10      -- cap glass sheen planes (budget)
	local FLOOR_RADIUS = 220     -- only service floors within this distance of camera
	local UPDATE_BUDGET = 12     -- floors re-evaluated per throttled tick

	function Reflections.start(ctx)
		local maid = ctx.maid:childMaid()
		Reflections._maid = maid
		local Snapshot = ctx.snapshot
		local caps = ctx.platform.caps
		local Scanner = require("detection/Scanner")

		-- floorEntry: { part=, up=, overlay=BasePart? }
		local floors = {}            -- part -> entry
		local order = {}             -- array of parts (rotating cursor)
		local cursor = 1
		local overlayCount = 0
		Reflections._q = ctx.getQuality()

		-- ── probe strategies ─────────────────────────────────────────────────
		local strategies = {}
		local active = nil
		local function getStrategy(mode)
			if mode == "Color Blend (cheap)" then
				strategies.overlay = strategies.overlay or require("reflections/OverlayReflection")
				return strategies.overlay
			elseif mode == "Raycast Probe (SSR approx.)" then
				strategies.raycast = strategies.raycast or require("reflections/RaycastProbe")
				return strategies.raycast
			end
			return nil -- "Off"
		end

		local function switchStrategy()
			local mode = State.get("reflect_mode")
			local want = getStrategy(mode)
			if want == active then return end
			if active and active.stop then pcall(active.stop) end
			active = want
			if active and active.start then
				pcall(active.start, ctx)
				-- re-register existing floors with the new strategy
				for _, entry in pairs(floors) do
					if active.register then pcall(active.register, entry) end
				end
			end
		end

		-- ── floor enrollment ─────────────────────────────────────────────────
		local function makeOverlay(entry)
			if overlayCount >= MAX_OVERLAYS then return end
			if not (State.get("reflect_glass_overlay") and caps.futureLighting) then return end
			local part = entry.part
			-- thin glass sheen plane hugging the floor's top face. Box-ish floors only.
			local size = part.Size
			local overlay = Snapshot.create("Part", {
				Name = "FloorSheen",
				Anchored = true, CanCollide = false, CanQuery = false, CanTouch = false,
				CastShadow = false,
				Material = Enum.Material.Glass,
				Transparency = 0.6,
				Reflectance = 0.5,
				Size = Vector3.new(size.X, 0.05, size.Z),
				CFrame = part.CFrame * CFrame.new(0, size.Y / 2 + 0.03, 0),
				Color = part.Color,
			}, ctx.worldFolder)
			entry.overlay = overlay
			overlayCount += 1
		end

		local function enroll(part)
			if floors[part] then return end
			if not part:IsA("BasePart") then return end
			local entry = { part = part, up = part.CFrame.UpVector, overlay = nil }
			floors[part] = entry
			order[#order + 1] = part
			if active and active.register then pcall(active.register, entry) end
		end

		local function unenroll(part)
			local entry = floors[part]
			if not entry then return end
			if entry.overlay then overlayCount = math.max(0, overlayCount - 1) end
			if active and active.unregister then pcall(active.unregister, entry) end
			floors[part] = nil
		end

		-- seed from Scanner + subscribe to new classifications
		for _, p in ipairs(Scanner.getFloors()) do enroll(p) end
		maid:give(Scanner.onClassified:Connect(function(part, cls)
			if cls.isFloor then enroll(part) end
		end))

		-- ── per-floor reflectance update (Schlick-Fresnel from grazing angle) ──
		local function wetness()
			local base = State.get("reflect_wetness")
			local fromWeather = (ctx.bus.wetness or 0) * State.get("weather_wet_boost")
			return Util.clamp(base + fromWeather, 0, 1)
		end

		local function updateFloor(entry, camLook, camPos)
			local part = entry.part
			if not part.Parent then return false end
			-- Ceilings/overpasses also have up-facing tops; never glaze a surface that
			-- sits well ABOVE the eye (that produced "gray planes above me").
			local aboveEye = camPos and (part.Position.Y > camPos.Y + 4)
			local cls = Scanner.classify(part)
			local f0 = (cls and cls.f0) or 0.04
			local up = part.CFrame.UpVector
			-- cosθ between view and surface normal; grazing → small → high Fresnel
			local cosT = math.abs(up:Dot(camLook))
			local fr = (1 - cosT) ^ 5                              -- Schlick term
			local fresnelTerm = Util.lerp(1, fr, State.get("reflect_fresnel"))
			local strength = State.get("reflect_strength")
			local wet = wetness()
			-- ALBEDO-AWARE reflectance: a black asphalt mostly ABSORBS the sky it would
			-- reflect — it must never read as chrome when wet. Scale by surface
			-- brightness: true blacks ≈0.12×, mid greys near full, whites slightly
			-- boosted. This is THE trick that makes wet streets look real instead of
			-- silver. (Lifted from a hand-tuned reference shader.)
			local albedo = Util.clamp(Util.luminance(part.Color) * 1.5 + 0.05, 0.12, 1.15)
			local target = Util.clamp(
				(strength * (f0 + (1 - f0) * fresnelTerm) + wet * 0.25) * albedo, 0, 1)
			Snapshot.set(part, "Reflectance", target * Util.lerp(0.7, 1, Reflections._q or 1))

			-- glass sheen overlay (lazy-created, capped) gets the probe colour
			if State.get("reflect_glass_overlay") and caps.futureLighting and not entry.overlay and not aboveEye then
				makeOverlay(entry)
			end
			if entry.overlay then
				Snapshot.set(entry.overlay, "Reflectance", Util.clamp(target + wet * 0.3, 0, 1))
				Snapshot.set(entry.overlay, "Transparency", Util.lerp(0.75, 0.45, wet))
				local probeColor = active and active.colorFor and active.colorFor(entry)
				if probeColor then
					entry.overlay.Color = entry.overlay.Color:Lerp(probeColor, 0.2)
				end
			end
			return true
		end

		local accum = 0
		maid:give(ctx.services.RunService.Heartbeat:Connect(function(dt)
			if not State.get("reflect_enabled") then return end
			accum += dt
			if accum < 0.08 then return end
			accum = 0
			local cam = ctx.camera()
			if not cam then return end
			local camPos = cam.CFrame.Position
			local camLook = cam.CFrame.LookVector
			local budget = math.max(4, math.floor(UPDATE_BUDGET * (Reflections._q or 1)))
			local n = #order
			local processed, scanned = 0, 0
			while processed < budget and scanned < n do
				local part = order[cursor]
				cursor = (cursor % n) + 1
				scanned += 1
				local entry = part and floors[part]
				if not entry or not part.Parent then
					-- compact lazily: skip dead refs (cleaned by unenroll over time)
				else
					if (part.Position - camPos).Magnitude <= FLOOR_RADIUS then
						updateFloor(entry, camLook, camPos)
						processed += 1
					end
				end
			end
		end))

		maid:give(State.observe("reflect_mode", switchStrategy))
		maid:give(State.observe("reflect_glass_overlay", function(on)
			if not on then
				for _, entry in pairs(floors) do
					if entry.overlay then entry.overlay:Destroy(); entry.overlay = nil end
				end
				overlayCount = 0
			end
		end))
		maid:give(workspace.DescendantRemoving:Connect(function(inst)
			if floors[inst] then unenroll(inst) end
		end))

		switchStrategy()

		-- Optional hero-floor viewport mirror — OFF by default and NEVER auto-enabled.
		-- It re-renders a cloned scene subset and was a periodic stutter source, so it
		-- is opt-in via the reflect_mirror toggle only (desktop only).
		local mirrorHandle = nil
		local function syncMirror()
			local want = State.get("reflect_mirror") and not ctx.platform.isMobile and State.get("reflect_enabled")
			if want and not mirrorHandle then
				maid:spawn(function()
					task.wait(0.5) -- let the Scanner populate floors first
					local ok, m = pcall(function() return require("reflections/ViewportMirror").start(ctx) end)
					if ok and m then mirrorHandle = m; ctx.registerHandle(m) end
				end)
			elseif not want and mirrorHandle then
				pcall(function() if mirrorHandle.stop then mirrorHandle.stop() end end)
				mirrorHandle = nil
			end
		end
		maid:give(State.observe("reflect_mirror", syncMirror))

		ctx.log.debug("Reflections online; floors seeded =", #order)
		return Reflections
	end

	function Reflections.setQuality(q)
		Reflections._q = math.clamp(q, 0, 1)
	end

	function Reflections.stop()
		if Reflections._maid then Reflections._maid:clean() end
	end

	return Reflections
end

end)()

__modules["reflections/OverlayReflection"] = (function()
--!nonstrict
--[[
	reflections/OverlayReflection.lua  —  probe strategy ("Color Blend (cheap)")
	-----------------------------------------------------------------------------
	The cheapest reflection tier: NO raycasting. Floors are tinted toward a single
	sampled environment colour (a blend of OutdoorAmbient and the sky's warm shift),
	refreshed a few times a second. Combined with the controller's Fresnel-driven
	Reflectance this gives a convincing flat sheen at almost zero cost — the right
	fallback for mobile / low tiers.

	Same strategy interface as RaycastProbe so the controller can swap between them.
]]

return function(require)
	local OverlayReflection = {}
	OverlayReflection.id = "reflections/OverlayReflection"

	local sharedColor = Color3.fromRGB(150, 160, 175)

	function OverlayReflection.register(_entry) end
	function OverlayReflection.unregister(_entry) end
	function OverlayReflection.colorFor(_entry) return sharedColor end
	function OverlayReflection.setQuality(_q) end

	function OverlayReflection.start(ctx)
		local maid = ctx.maid:childMaid()
		OverlayReflection._maid = maid
		local L = ctx.services.Lighting

		local function refresh()
			sharedColor = L.OutdoorAmbient:Lerp(L.ColorShift_Top, 0.4)
		end
		refresh()

		local accum = 0
		maid:give(ctx.services.RunService.Heartbeat:Connect(function(dt)
			accum += dt
			if accum < 0.5 then return end
			accum = 0
			refresh()
		end))

		ctx.log.debug("OverlayReflection (cheap color-blend) online")
		return OverlayReflection
	end

	function OverlayReflection.stop()
		if OverlayReflection._maid then OverlayReflection._maid:clean() end
	end

	return OverlayReflection
end

end)()

__modules["reflections/ViewportMirror"] = (function()
--!nonstrict
--[[
	reflections/ViewportMirror.lua  —  optional hero-floor planar mirror (HIGH tier)
	-----------------------------------------------------------------------------
	HONESTY FIRST: a ViewportFrame only renders instances parented INTO it, not the
	live workspace, and Roblox gives us no render-to-texture of the real scene. So a
	"true" mirror is impossible. This module implements the legitimate SHOWCASE
	technique: clone a small, budget-capped set of nearby ANCHORED parts into a
	ViewportFrame whose camera is the real camera reflected across one hero floor
	plane, and display it on a SurfaceGui on that floor. It reflects only that cloned
	static subset, refreshed slowly — a convincing hero-floor mirror, not a
	general-purpose reflection.

	Default OFF; only started by the controller at very high quality on desktop.
	Everything is capped, slow-refresh, and fully Maid-tracked.
]]

return function(require)
	local State = require("core/State")

	local ViewportMirror = {}
	ViewportMirror.id = "reflections/ViewportMirror"

	local CLONE_CAP = 40
	local CLONE_RADIUS = 80
	local REFRESH_EVERY = 3.0

	function ViewportMirror.start(ctx, heroFloor)
		local maid = ctx.maid:childMaid()
		ViewportMirror._maid = maid
		local Snapshot = ctx.snapshot

		heroFloor = heroFloor or ViewportMirror._pickHero(ctx)
		if not heroFloor then
			ctx.log.debug("ViewportMirror: no hero floor found — skipped")
			return ViewportMirror
		end

		-- The mirror's low-res buffer resolution is the reflect_resolution config (the
		-- same "small CPU-bound buffer" budget the probe uses). Read once at creation.
		local res = math.clamp(State.get("reflect_resolution") or 128, 64, 256)

		-- Parent the SurfaceGui directly to the floor part (most reliable rendering)
		-- It is tagged + tracked by Snapshot, so teardown destroys it cleanly.
		local surface = Snapshot.create("SurfaceGui", {
			Name = "MirrorSurface",
			Face = Enum.NormalId.Top,
			CanvasSize = Vector2.new(res * 2, res * 2),
			LightInfluence = 0,
		}, heroFloor)

		local vpf = Snapshot.create("ViewportFrame", {
			Size = UDim2.fromScale(1, 1),
			BackgroundTransparency = 1,
			ImageTransparency = 0.35,        -- let the floor show through (sheen)
			Ambient = Color3.fromRGB(140, 150, 165),
			LightColor = Color3.fromRGB(255, 250, 240),
		}, surface)

		local world = Snapshot.create("WorldModel", {}, vpf) -- proper lighting for clones
		local vpCam = Snapshot.create("Camera", {}, vpf)
		vpf.CurrentCamera = vpCam

		local cloneHolder = {}
		-- Cheap spatial query instead of workspace:GetDescendants() — the old code
		-- walked the ENTIRE instance tree on every refresh, a hard periodic hitch on
		-- big places. GetPartBoundsInBox returns only nearby BaseParts, capped.
		local overlap = OverlapParams.new()
		overlap.FilterType = Enum.RaycastFilterType.Exclude
		overlap.FilterDescendantsInstances = { ctx.worldFolder }
		overlap.MaxParts = CLONE_CAP * 3

		local function rebuildClones()
			for _, c in ipairs(cloneHolder) do c:Destroy() end
			table.clear(cloneHolder)
			local origin = heroFloor.Position
			local box = Vector3.new(CLONE_RADIUS * 2, CLONE_RADIUS * 2, CLONE_RADIUS * 2)
			local nearby = workspace:GetPartBoundsInBox(CFrame.new(origin), box, overlap)
			local n = 0
			for _, part in ipairs(nearby) do
				if n >= CLONE_CAP then break end
				if part.Anchored and part ~= heroFloor then
					local ok, clone = pcall(function()
						local cl = part:Clone()
						cl.Anchored = true
						for _, ch in ipairs(cl:GetChildren()) do
							-- drop scripts/sounds/heavy children from clones
							if not ch:IsA("DataModelMesh") and not ch:IsA("SpecialMesh")
								and not ch:IsA("Decal") and not ch:IsA("Texture")
								and not ch:IsA("SurfaceAppearance") then
								ch:Destroy()
							end
						end
						cl.Parent = world
						return cl
					end)
					if ok and clone then
						cloneHolder[#cloneHolder + 1] = clone
						n += 1
					end
				end
			end
		end

		rebuildClones()

		local refreshAccum = REFRESH_EVERY
		local frameAccum = 0
		maid:give(ctx.services.RunService.PreRender:Connect(function(dt)
			refreshAccum += dt
			if refreshAccum >= REFRESH_EVERY then
				refreshAccum = 0
				rebuildClones()
			end
			frameAccum += dt
			if frameAccum < 1 / 30 then return end -- mirror at 30fps max
			frameAccum = 0
			local cam = ctx.camera()
			if not cam then return end
			-- reflect the camera across the hero floor plane (point on plane = floor
			-- top centre, plane normal = floor up vector).
			local n = heroFloor.CFrame.UpVector
			local planePoint = heroFloor.Position + n * (heroFloor.Size.Y / 2)
			local camCF = cam.CFrame
			local pos = camCF.Position
			local d = (pos - planePoint):Dot(n)
			local mirroredPos = pos - 2 * d * n
			local look = camCF.LookVector
			local mirroredLook = look - 2 * look:Dot(n) * n
			vpCam.CFrame = CFrame.lookAt(mirroredPos, mirroredPos + mirroredLook, Vector3.yAxis)
			vpCam.FieldOfView = cam.FieldOfView
		end))

		-- destroy clones explicitly on teardown (they live under our tagged vpf, but
		-- be tidy).
		maid:give(function()
			for _, c in ipairs(cloneHolder) do pcall(function() c:Destroy() end) end
			table.clear(cloneHolder)
		end)

		ctx.log.debug("ViewportMirror online on", heroFloor:GetFullName())
		return ViewportMirror
	end

	function ViewportMirror._pickHero(ctx)
		local Scanner = require("detection/Scanner")
		local cam = ctx.camera()
		local camPos = cam and cam.CFrame.Position or Vector3.zero
		local best, bestScore
		for _, p in ipairs(Scanner.getFloors()) do
			local area = p.Size.X * p.Size.Z
			local dist = (p.Position - camPos).Magnitude
			local score = area - dist * 2
			if not bestScore or score > bestScore then
				best, bestScore = p, score
			end
		end
		return best
	end

	function ViewportMirror.stop()
		if ViewportMirror._maid then ViewportMirror._maid:clean() end
	end

	return ViewportMirror
end

end)()

__modules["reflections/RaycastProbe"] = (function()
--!nonstrict
--[[
	reflections/RaycastProbe.lua  —  probe strategy ("Raycast Probe (SSR approx.)")
	-----------------------------------------------------------------------------
	An HONEST approximation of screen-space reflections. NOT ray tracing, NOT mirror-
	accurate. Each frame we cast a small BUDGET of "roving" reflection rays
	(reflect_rays_per_frame) spread across the registered floors: from a sample point
	on a floor we reflect the view direction about the floor normal and
	workspace:Raycast outward. The colour we hit (or the sky/ambient on a miss) is
	accumulated into a per-floor exponentially-smoothed colour, so the estimate is
	temporally stable and shimmer-free.

	Camera-delta REPROJECTION: instead of warping a screen buffer (we have no depth
	buffer), we modulate the temporal blend factor by bus.camDelta — when the camera
	moves fast the estimate snaps toward fresh samples (less lag); when still it
	smooths hard (kills shimmer). reflect_smoothing sets the resting smoothness.

	Multi-bounce (reflect_multibounce, auto-off on mobile) casts one extra bounce.
	The controller reads colorFor(entry) and tints the floor's glass sheen overlay.
]]

return function(require)
	local State = require("core/State")
	local Util = require("core/Util")

	local RaycastProbe = {}
	RaycastProbe.id = "reflections/RaycastProbe"

	local registered = {}     -- array of floor entries
	local indexByEntry = {}   -- entry -> array index
	local cursor = 1
	local qualityMul = 1
	local rng = Random.new(99)

	function RaycastProbe.register(entry)
		if indexByEntry[entry] then return end
		registered[#registered + 1] = entry
		indexByEntry[entry] = #registered
		entry._probe = entry._probe or { color = Color3.fromRGB(150, 160, 175) }
	end

	function RaycastProbe.unregister(entry)
		local i = indexByEntry[entry]
		if not i then return end
		-- swap-remove
		local last = #registered
		registered[i] = registered[last]
		if registered[i] then indexByEntry[registered[i]] = i end
		registered[last] = nil
		indexByEntry[entry] = nil
	end

	function RaycastProbe.colorFor(entry)
		return entry._probe and entry._probe.color or nil
	end

	function RaycastProbe.setQuality(q)
		qualityMul = math.clamp(q, 0.25, 1)
	end

	function RaycastProbe.start(ctx)
		local maid = ctx.maid:childMaid()
		RaycastProbe._maid = maid
		local isMobile = ctx.platform.isMobile

		-- cached RaycastParams — never reallocate per ray.
		local params = RaycastParams.new()
		params.FilterType = Enum.RaycastFilterType.Exclude
		params.IgnoreWater = false
		local function refreshFilter()
			local ignore = { ctx.worldFolder }
			local char = ctx.services.Players.LocalPlayer and ctx.services.Players.LocalPlayer.Character
			if char then ignore[#ignore + 1] = char end
			params.FilterDescendantsInstances = ignore
		end
		refreshFilter()
		local lp = ctx.services.Players.LocalPlayer
		if lp then maid:give(lp.CharacterAdded:Connect(refreshFilter)) end

		local function skyColor()
			-- miss → environment colour: blend outdoor ambient toward sky tint.
			local L = ctx.services.Lighting
			return L.OutdoorAmbient:Lerp(L.ColorShift_Top, 0.35)
		end

		local function hitColor(result, fallback)
			if not result then return fallback end
			local inst = result.Instance
			local ok, c = pcall(function() return inst.Color end)
			if ok and typeof(c) == "Color3" then return c end
			return fallback
		end

		-- one reflection sample for a floor → returns a Color3
		local function sampleFloor(entry, camPos)
			local part = entry.part
			if not part.Parent then return nil end
			local n = part.CFrame.UpVector
			-- random point on the top face
			local size = part.Size
			local lx = (rng:NextNumber() - 0.5) * size.X
			local lz = (rng:NextNumber() - 0.5) * size.Z
			local p = (part.CFrame * CFrame.new(lx, size.Y / 2 + 0.05, lz)).Position
			local viewDir = (p - camPos)
			if viewDir.Magnitude < 1e-3 then return nil end
			viewDir = viewDir.Unit
			-- reflect view about the surface normal
			local refl = viewDir - 2 * viewDir:Dot(n) * n
			local dist = 120
			local result = workspace:Raycast(p + n * 0.05, refl * dist, params)
			local col = hitColor(result, skyColor())
			-- optional one extra bounce (desktop only)
			if result and State.get("reflect_multibounce") and not isMobile then
				local p2 = result.Position
				local n2 = result.Normal
				local refl2 = refl - 2 * refl:Dot(n2) * n2
				local r2 = workspace:Raycast(p2 + n2 * 0.05, refl2 * dist, params)
				col = col:Lerp(hitColor(r2, skyColor()), 0.4)
			end
			return col
		end

		maid:give(ctx.services.RunService.Heartbeat:Connect(function()
			local count = #registered
			if count == 0 then return end
			local cam = ctx.camera()
			if not cam then return end
			local camPos = cam.CFrame.Position

			-- reprojection-flavoured blend: faster camera → snappier estimate.
			-- The resting blend implements an N-frame temporal ACCUMULATION window:
			-- a running average over N frames has per-frame weight ~1/N, which we damp
			-- further by the smoothing slider. More accum frames OR more smoothing →
			-- smaller alpha → a more stable, shimmer-free estimate (and more lag).
			local smoothing = State.get("reflect_smoothing")
			local accumN = math.max(1, State.get("reflect_accum_frames"))
			local restAlpha = (1 - smoothing) / math.sqrt(accumN)
			local alpha = restAlpha
			if State.get("reflect_reproject") then
				local cd = ctx.bus.camDelta or 0
				alpha = Util.clamp(restAlpha + cd * 0.08, restAlpha, 1)
			end

			local budget = math.max(4, math.floor(State.get("reflect_rays_per_frame") * qualityMul))
			-- distribute rays round-robin across floors
			for _ = 1, budget do
				local entry = registered[cursor]
				cursor = (cursor % count) + 1
				if entry and entry.part.Parent then
					local c = sampleFloor(entry, camPos)
					if c then
						local pc = entry._probe
						pc.color = pc.color:Lerp(c, alpha)
					end
				end
			end
		end))

		ctx.log.debug("RaycastProbe online (SSR approximation)")
		return RaycastProbe
	end

	function RaycastProbe.stop()
		if RaycastProbe._maid then RaycastProbe._maid:clean() end
	end

	return RaycastProbe
end

end)()

__modules["weather/Weather"] = (function()
--!nonstrict
--[[
	weather/Weather.lua  —  CONTROLLER (manifest.boot)
	-----------------------------------------------------------------------------
	Weather state machine with SMOOTH transitions. Owns a single camera-following
	volume part (so precipitation always falls around the player without spawning
	emitters across the whole map) and cross-fades rain/snow levels with frame-rate-
	independent damping when weather_mode changes.

	It writes a target wetness to bus.wetness (rain/storm soak floors → the
	Reflections controller raises floor reflectance), drives wind (base ×
	storm gusts), and toggles Lightning during storms.
]]

return function(require)
	local State = require("core/State")
	local Util = require("core/Util")

	local Weather = {}
	Weather.id = "weather/Weather"

	local WIND_DIR = Vector3.new(1, 0, 0.3).Unit
	local MAX_WIND = 120

	function Weather.start(ctx)
		local maid = ctx.maid:childMaid()
		Weather._maid = maid
		local Snapshot = ctx.snapshot

		-- camera-following emission volume (high above the player)
		local volume = Snapshot.create("Part", {
			Name = "WeatherVolume",
			Anchored = true, CanCollide = false, CanQuery = false, CanTouch = false,
			Transparency = 1,
			Size = Vector3.new(240, 8, 240),
		}, ctx.worldFolder)

		-- start sub-emitters on the shared volume
		local Rain = require("weather/Rain"); Rain.start(ctx, volume); ctx.registerHandle(Rain)
		local Snow = require("weather/Snow"); Snow.start(ctx, volume); ctx.registerHandle(Snow)
		local Storm = require("weather/Storm"); Storm.start(ctx); ctx.registerHandle(Storm)
		local Lightning = require("weather/Lightning"); Lightning.start(ctx); ctx.registerHandle(Lightning)

		-- eased levels
		local rainLevel, snowLevel, wetLevel = 0, 0, 0

		local function targetsFor(mode, intensity)
			if mode == "Rain" then
				return intensity, 0, intensity, false
			elseif mode == "Snow" then
				return 0, intensity, intensity * 0.3, false
			elseif mode == "Storm" then
				return math.clamp(intensity * 1.3, 0, 1), 0, 1, true
			end
			return 0, 0, 0, false -- Clear
		end

		maid:give(ctx.services.RunService.Heartbeat:Connect(function(dt)
			local mode = State.get("weather_mode")
			local intensity = State.get("weather_intensity")
			local rT, sT, wT, storming = targetsFor(mode, intensity)

			rainLevel = Util.damp(rainLevel, rT, 1.0, dt)
			snowLevel = Util.damp(snowLevel, sT, 1.4, dt)
			wetLevel = Util.damp(wetLevel, wT, 1.5, dt)
			ctx.bus.wetness = wetLevel

			-- wind (base × storm gust), as a world-space horizontal vector
			Storm.setActive(storming)
			local gust = Storm.gust(dt)
			local windMag = State.get("weather_wind") * gust * MAX_WIND
			local windVec = WIND_DIR * windMag

			Rain.set(rainLevel, windVec)
			Snow.set(snowLevel, windVec)

			-- lightning only during storm AND when enabled
			Lightning.setActive(storming and State.get("weather_lightning"))

			-- follow the camera
			local cam = ctx.camera()
			if cam then
				volume.CFrame = CFrame.new(cam.CFrame.Position + Vector3.new(0, 55, 0))
			end
		end))

		ctx.log.debug("Weather online")
		return Weather
	end

	function Weather.setQuality(q)
		-- particle budget scaling handled implicitly via levels; nothing extra here.
		Weather._q = q
	end

	function Weather.stop()
		if Weather._maid then Weather._maid:clean() end
	end

	return Weather
end

end)()

__modules["weather/Rain"] = (function()
--!nonstrict
--[[
	weather/Rain.lua  —  precipitation emitter
	-----------------------------------------------------------------------------
	A single ParticleEmitter attached to the Weather controller's camera-following
	volume part. We use the REAL ParticleEmitter.Squash property to stretch particles
	along their fall direction so they read as rain streaks (no external texture
	needed). Every NumberSequence/ColorSequence is built ONCE at start; at runtime we
	mutate only scalar props (Rate, Acceleration) — zero per-frame allocation.

	Rain.set(rate01, wind01) is called by the Weather controller each frame.
]]

return function(require)
	local Rain = {}
