__modules["weather/Storm"] = (function()
--!nonstrict
--[[
	weather/Storm.lua  —  gust generator
	-----------------------------------------------------------------------------
	Storm is not its own particle system — it intensifies Rain and adds Lightning.
	This module's job is the WIND GUST signal: a smooth noise-driven multiplier the
	Weather controller applies on top of the base wind while a storm is active, so
	rain slant and foliage sway surge and ease like real gusts. Uses math.noise
	(deterministic, allocation-free) accumulated over time — no per-frame tables.
]]

return function(require)
	local Util = require("core/Util")

	local Storm = {}
	Storm.id = "weather/Storm"
	local t = 0
	local active = false

	function Storm.start(ctx)
		Storm._ctx = ctx
		ctx.log.debug("Storm gust generator ready")
		return Storm
	end

	function Storm.setActive(on)
		active = on
	end

	function Storm.isActive()
		return active
	end

	-- advance and return a wind multiplier in ~[0.6, 1.6]
	function Storm.gust(dt)
		if not active then return 1 end
		t += dt * 0.6
		local n = Util.noise(t, 0, 0)          -- -1..1
		return 1.1 + n * 0.5
	end

	function Storm.stop()
		active = false
	end

	return Storm
end

end)()

__modules["weather/Lightning"] = (function()
--!nonstrict
--[[
	weather/Lightning.lua  —  stochastic storm lightning
	-----------------------------------------------------------------------------
	When active, fires lightning flashes at random intervals. A flash:
	  * spikes the owned BloomEffect intensity briefly (bus.pipeline.bloom),
	  * pulses a bright transient PointLight high in the world,
	  * writes a decaying value to bus.flash so overlays can react,
	then decays back over a fraction of a second. Uses a Random instance; the bloom
	value is captured/restored each flash so we never drift the user's setting.
]]

return function(require)
	local Lightning = {}
	Lightning.id = "weather/Lightning"

	function Lightning.start(ctx)
		local maid = ctx.maid:childMaid()
		Lightning._maid = maid
		local Snapshot = ctx.snapshot
		local rng = Random.new(2024)
		local active = false
		local nextFlashIn = rng:NextNumber(3, 8)
		local flashEnergy = 0      -- 0..1 decaying
		local baseBloom = nil

		-- a transient light high above; off until a flash
		local lightPart = Snapshot.create("Part", {
			Name = "LightningLight",
			Anchored = true, CanCollide = false, CanQuery = false, CanTouch = false,
			Transparency = 1, Size = Vector3.new(1, 1, 1),
		}, ctx.worldFolder)
		local pointLight = Snapshot.create("PointLight", {
			Brightness = 0, Range = 200, Color = Color3.fromRGB(220, 230, 255), Enabled = false,
		}, lightPart)

		Lightning.setActive = function(on)
			active = on
			if not on then
				pointLight.Enabled = false
				flashEnergy = 0
			end
		end

		local function triggerFlash()
			flashEnergy = 1
			local cam = ctx.camera()
			if cam then
				lightPart.Position = cam.CFrame.Position + Vector3.new(rng:NextNumber(-80, 80), 120, rng:NextNumber(-80, 80))
			end
			local bloom = ctx.bus.pipeline and ctx.bus.pipeline.bloom
			if bloom and baseBloom == nil then baseBloom = bloom.Intensity end
		end

		maid:give(ctx.services.RunService.Heartbeat:Connect(function(dt)
			if not active then return end
			nextFlashIn -= dt
			if nextFlashIn <= 0 then
				nextFlashIn = rng:NextNumber(4, 12)
				triggerFlash()
			end
			if flashEnergy > 0 then
				flashEnergy = math.max(0, flashEnergy - dt * 3.5) -- ~0.3s decay
				ctx.bus.flash = flashEnergy
				pointLight.Enabled = true
				pointLight.Brightness = flashEnergy * 8
				local bloom = ctx.bus.pipeline and ctx.bus.pipeline.bloom
				if bloom and baseBloom ~= nil then
					bloom.Intensity = baseBloom + flashEnergy * 2.5
				end
				if flashEnergy <= 0 then
					pointLight.Enabled = false
					local b = ctx.bus.pipeline and ctx.bus.pipeline.bloom
					if b and baseBloom ~= nil then b.Intensity = baseBloom; baseBloom = nil end
					ctx.bus.flash = 0
				end
			end
		end))

		ctx.log.debug("Lightning ready")
		return Lightning
	end

	function Lightning.stop()
		if Lightning._maid then Lightning._maid:clean() end
	end

	return Lightning
end

end)()

__modules["timeofday/Mood"] = (function()
--!nonstrict
--[[
	timeofday/Mood.lua  —  CONTROLLER (manifest.boot)
	-----------------------------------------------------------------------------
	ClockTime driver + named time-of-day moods.

	Selecting a non-Custom mood pushes a coherent set of values through State (which
	the Lighting / Atmosphere / ColorGrade observers then apply) — ClockTime is eased
	smoothly with frame-rate-independent damping for a nice transition; the discrete
	colour keys are set directly. "Custom" leaves everything alone so the user's own
	tuning is respected.

	mood_auto_cycle advances ClockTime continuously (a living sky) at
	mood_cycle_speed in-game hours per real second; this naturally flows through
	Lighting.lua's lighting_clock_time observer.

	No invented APIs — every value lands on a real config key.
]]

return function(require)
	local State = require("core/State")
	local Util = require("core/Util")

	local Mood = {}
	Mood.id = "timeofday/Mood"

	-- Each mood seeds clock + the palette keys. Tuned for a filmic feel.
	local MOODS = {
		["Golden Hour"] = {
			clock = 17.6,
			ambient = Color3.fromRGB(46, 38, 32),
			outdoor = Color3.fromRGB(150, 110, 80),
			tint = Color3.fromRGB(255, 226, 196),
			atmos = Color3.fromRGB(232, 196, 160),
		},
		["Blue Hour"] = {
			clock = 5.6,
			ambient = Color3.fromRGB(30, 36, 50),
			outdoor = Color3.fromRGB(70, 88, 120),
			tint = Color3.fromRGB(216, 226, 255),
			atmos = Color3.fromRGB(150, 170, 205),
		},
		["Noon"] = {
			clock = 12.5,
			ambient = Color3.fromRGB(60, 62, 70),
			outdoor = Color3.fromRGB(130, 138, 150),
			tint = Color3.fromRGB(255, 250, 244),
			atmos = Color3.fromRGB(200, 210, 225),
		},
		["Night"] = {
			clock = 0.0,
			ambient = Color3.fromRGB(16, 20, 32),
			outdoor = Color3.fromRGB(34, 42, 64),
			tint = Color3.fromRGB(190, 205, 240),
			atmos = Color3.fromRGB(60, 72, 100),
		},
		["Overcast"] = {
			clock = 13.0,
			ambient = Color3.fromRGB(58, 60, 64),
			outdoor = Color3.fromRGB(120, 124, 130),
			tint = Color3.fromRGB(228, 230, 235),
			atmos = Color3.fromRGB(186, 190, 196),
		},
	}

	function Mood.start(ctx)
		local maid = ctx.maid:childMaid()
		Mood._maid = maid

		local targetClock = nil -- non-nil while easing toward a pinned mood

		local function applyMood(name)
			local m = MOODS[name]
			if not m then
				targetClock = nil -- "Custom" → stop driving the clock
				return
			end
			-- discrete palette keys land immediately (their own observers react)
			State.set("lighting_ambient", m.ambient)
			State.set("lighting_outdoor_ambient", m.outdoor)
			State.set("grade_tint", m.tint)
			State.set("atmos_color", m.atmos)
			targetClock = m.clock
		end

		maid:give(State.observe("mood_preset", applyMood))

		-- clock driver: cycling overrides; else ease toward a pinned mood's clock.
		maid:give(ctx.services.RunService.Heartbeat:Connect(function(dt)
			if State.get("mood_auto_cycle") then
				local speed = State.get("mood_cycle_speed")
				local t = State.get("lighting_clock_time") + speed * dt
				if t >= 24 then t -= 24 end
				State.set("lighting_clock_time", t)
				return
			end
			if targetClock ~= nil then
				local cur = State.get("lighting_clock_time")
				-- shortest-path easing around the 24h wrap
				local diff = targetClock - cur
				if diff > 12 then diff -= 24 elseif diff < -12 then diff += 24 end
				if math.abs(diff) < 0.01 then
					targetClock = nil
					return
				end
				local stepTarget = cur + diff
				local nextV = Util.damp(cur, stepTarget, 0.6, dt)
				if nextV < 0 then nextV += 24 elseif nextV >= 24 then nextV -= 24 end
				State.set("lighting_clock_time", nextV)
			end
		end))

		ctx.log.debug("Mood online")
		return Mood
	end

	function Mood.stop()
		if Mood._maid then Mood._maid:clean() end
	end

	return Mood
end

end)()

__modules["camera/CameraFX"] = (function()
--!nonstrict
--[[
	camera/CameraFX.lua  —  CONTROLLER (manifest.boot)
	-----------------------------------------------------------------------------
	The cinematic camera brain. Runs on RunService.PreRender (the right place for
	camera work — after the default camera has positioned itself, just before render)
	and composes the contributions of its sub-modules:
	    FOV.update / DoFAuto.update / MotionBlur.update  — write their own effects
	    Shake.getOffset                                  — additive CFrame offset
	    EyeAdaptation                                    — self-loops (exposure)
	    Freecam / PhotoMode                              — explicit camera takeover

	CONTENTION RULE: we are NON-EXCLUSIVE. We never set CameraType for normal play.
	If another script owns the camera (CameraType == Scriptable and it isn't our
	Freecam/PhotoMode), we still only ADD a shake offset on top of its CFrame and warn
	ONCE — we never seize control. Original FieldOfView/CameraType restore on unload.

	It also publishes camera metrics on the bus: camCFrame, camDelta, camSpeed.
]]

return function(require)
	local State = require("core/State")

	local CameraFX = {}
	CameraFX.id = "camera/CameraFX"

	function CameraFX.start(ctx)
		local maid = ctx.maid:childMaid()
		CameraFX._maid = maid

		-- start sub-modules
		local FOV = require("camera/FOV"); FOV.start(ctx); ctx.registerHandle(FOV)
		local DoFAuto = require("camera/DoFAuto"); DoFAuto.start(ctx); ctx.registerHandle(DoFAuto)
		local MotionBlur = require("camera/MotionBlur"); MotionBlur.start(ctx); ctx.registerHandle(MotionBlur)
		local EyeAdaptation = require("camera/EyeAdaptation"); EyeAdaptation.start(ctx); ctx.registerHandle(EyeAdaptation)
		local Shake = require("camera/Shake"); Shake.start(ctx); ctx.registerHandle(Shake)
		local Freecam = require("camera/Freecam"); Freecam.start(ctx); ctx.registerHandle(Freecam)
		local PhotoMode = require("camera/PhotoMode"); PhotoMode.start(ctx); ctx.registerHandle(PhotoMode)
		CameraFX.Shake = Shake
		CameraFX.Freecam = Freecam
		CameraFX.PhotoMode = PhotoMode

		local prevPos = nil
		local warnedContention = false

		maid:give(ctx.services.RunService.PreRender:Connect(function(dt)
			local cam = ctx.camera()
			if not cam then return end

			-- ── publish camera metrics ─────────────────────────────────────────
			local pos = cam.CFrame.Position
			ctx.bus.camDelta = prevPos and (pos - prevPos).Magnitude or 0
			prevPos = pos
			ctx.bus.camCFrame = cam.CFrame
			-- planar character speed
			local speed = 0
			local char = ctx.services.Players.LocalPlayer and ctx.services.Players.LocalPlayer.Character
			local hrp = char and char:FindFirstChild("HumanoidRootPart")
			if hrp then
				local v = hrp.AssemblyLinearVelocity
				speed = Vector3.new(v.X, 0, v.Z).Magnitude
			end
			ctx.bus.camSpeed = speed

			if not State.get("cam_enabled") then return end

			-- effects that don't seize the camera run always
			FOV.update(dt)
			DoFAuto.update(dt)
			MotionBlur.update(dt)

			-- Freecam owns the camera while active → skip our offsets
			if Freecam.isActive() then return end

			-- contention detection
			local foreignOwner = (cam.CameraType == Enum.CameraType.Scriptable)
				and not PhotoMode.isActive()
			if foreignOwner and not warnedContention then
				warnedContention = true
				ctx.log.warn("Another script controls the camera — running offset-only (non-exclusive).")
			end

			-- additive shake offset (safe even under a foreign owner)
			local offset = Shake.getOffset(dt)
			if offset then
				cam.CFrame = cam.CFrame * offset
			end
		end))

		ctx.log.debug("CameraFX online")
		return CameraFX
	end

	function CameraFX.setQuality(_q) end

	function CameraFX.stop()
		if CameraFX._maid then CameraFX._maid:clean() end
	end

	return CameraFX
end

end)()

__modules["camera/FOV"] = (function()
--!nonstrict
--[[
	camera/FOV.lua
	-----------------------------------------------------------------------------
	Dynamic field-of-view. The camera widens slightly as the player moves faster
	(a speed/sprint "kick"), eased with frame-rate-independent damping so it never
	snaps. Writes Camera.FieldOfView directly (captured once via Snapshot so unload
	restores the original FOV). Reads bus.camSpeed (written by CameraFX).
	update(dt) is called from the CameraFX PreRender loop for tight ordering.
]]

return function(require)
	local State = require("core/State")
	local Util = require("core/Util")

	local FOV = {}
	FOV.id = "camera/FOV"
	local SPRINT_REF = 26 -- studs/s treated as "full speed" for the kick

	function FOV.start(ctx)
		FOV._ctx = ctx
		FOV._captured = false
		return FOV
	end

	function FOV.update(dt)
		local ctx = FOV._ctx
		if not ctx then return end
		local cam = ctx.camera()
		if not cam then return end
		if not FOV._captured then
			ctx.snapshot.capture(cam, "FieldOfView")
			FOV._captured = true
		end
		local base = State.get("cam_fov_base")
		local kick = State.get("cam_fov_kick")
		local speed = ctx.bus.camSpeed or 0
		local target = base + kick * Util.clamp(speed / SPRINT_REF, 0, 1)
		cam.FieldOfView = Util.damp(cam.FieldOfView, target, 0.2, dt)
	end

	function FOV.stop() end

	return FOV
end

end)()

__modules["camera/DoFAuto"] = (function()
--!nonstrict
--[[
	camera/DoFAuto.lua
	-----------------------------------------------------------------------------
	Auto-focus depth of field. Each frame we raycast from the camera forward; the hit
	distance (or a far default on a miss) becomes the focus target, and we ease the
	owned DepthOfFieldEffect.FocusDistance (bus.pipeline.dof) toward it with frame-
	rate-independent damping (cam_dof_focus_speed = tau) for a smooth focus pull.

	postfx/DepthOfField owns the effect's static shape (aperture); we only drive the
	live FocusDistance. update(dt) is called from the CameraFX loop.
]]

return function(require)
	local State = require("core/State")
	local Util = require("core/Util")

	local DoFAuto = {}
	DoFAuto.id = "camera/DoFAuto"
	local FAR = 200

	function DoFAuto.start(ctx)
		local maid = ctx.maid:childMaid()
		DoFAuto._maid = maid
		DoFAuto._ctx = ctx
		-- cached raycast params (ignore our own instances + character)
		local params = RaycastParams.new()
		params.FilterType = Enum.RaycastFilterType.Exclude
		local function refresh()
			local ignore = { ctx.worldFolder }
			local char = ctx.services.Players.LocalPlayer and ctx.services.Players.LocalPlayer.Character
			if char then ignore[#ignore + 1] = char end
			params.FilterDescendantsInstances = ignore
		end
		refresh()
		local lp = ctx.services.Players.LocalPlayer
		if lp then maid:give(lp.CharacterAdded:Connect(refresh)) end
		DoFAuto._params = params
		DoFAuto._focus = 50
		return DoFAuto
	end

	function DoFAuto.update(dt)
		local ctx = DoFAuto._ctx
		if not ctx then return end
		if not State.get("cam_dof_enabled") then return end
		local dof = ctx.bus.pipeline and ctx.bus.pipeline.dof
		if not dof then return end
		local cam = ctx.camera()
		if not cam then return end
		local origin = cam.CFrame.Position
		local dir = cam.CFrame.LookVector * FAR
		local result = workspace:Raycast(origin, dir, DoFAuto._params)
		local targetDist = result and (result.Position - origin).Magnitude or FAR
		DoFAuto._focus = Util.damp(DoFAuto._focus, targetDist, State.get("cam_dof_focus_speed"), dt)
		dof.FocusDistance = DoFAuto._focus
	end

	function DoFAuto.stop() if DoFAuto._maid then DoFAuto._maid:clean() end end

	return DoFAuto
end

end)()

__modules["camera/MotionBlur"] = (function()
--!nonstrict
--[[
	camera/MotionBlur.lua  —  FAKED
	-----------------------------------------------------------------------------
	HARD TRUTH: there is NO MotionBlurEffect in Roblox. We fake velocity smear two
	cheap ways that combine acceptably:
	  * a faint full-screen GUI overlay whose alpha rises with camera movement
	    (bus.camDelta), giving a sense of speed blur at the edges,
	  * a tiny pulse on the owned BlurEffect.Size (bus.pipeline.blur) on fast motion.
	Neither truly smears per-pixel by velocity — documented as an approximation.
	update(dt) is called from the CameraFX loop. Overlay created once.
]]

return function(require)
	local State = require("core/State")
	local Util = require("core/Util")

	local MotionBlur = {}
	MotionBlur.id = "camera/MotionBlur"

	function MotionBlur.start(ctx)
		local maid = ctx.maid:childMaid()
		MotionBlur._maid = maid
		MotionBlur._ctx = ctx
		local Snapshot = ctx.snapshot

		MotionBlur._overlay = Snapshot.create("Frame", {
			Name = "MotionBlur",
			BackgroundColor3 = Color3.new(0, 0, 0),
			BackgroundTransparency = 1,
			Size = UDim2.fromScale(1, 1),
			ZIndex = 40, Active = false, Visible = true,
		}, ctx.gui)
		-- a soft inward gradient so the smear reads at the frame edges
		local grad = Snapshot.create("UIGradient", {
			Transparency = NumberSequence.new({
				NumberSequenceKeypoint.new(0, 0.2),
				NumberSequenceKeypoint.new(0.4, 1),
				NumberSequenceKeypoint.new(0.6, 1),
				NumberSequenceKeypoint.new(1, 0.2),
			}),
		}, MotionBlur._overlay)
		MotionBlur._smear = 0
		return MotionBlur
	end

	function MotionBlur.update(dt)
		local ctx = MotionBlur._ctx
		if not ctx then return end
		local overlay = MotionBlur._overlay
		if not overlay then return end
		if not State.get("cam_motionblur") then
			overlay.BackgroundTransparency = 1
			return
		end
		local amount = State.get("cam_motionblur_amount")
		-- normalise camera delta into 0..1 (delta is studs/frame; ~3 = fast)
		local d = Util.clamp((ctx.bus.camDelta or 0) / 3, 0, 1)
		MotionBlur._smear = Util.damp(MotionBlur._smear, d, 0.08, dt)
		overlay.BackgroundTransparency = 1 - MotionBlur._smear * amount * 0.5
		local blur = ctx.bus.pipeline and ctx.bus.pipeline.blur
		if blur then
			blur.Size = MotionBlur._smear * amount * 8
		end
	end

	function MotionBlur.stop() if MotionBlur._maid then MotionBlur._maid:clean() end end

	return MotionBlur
end

end)()

__modules["camera/EyeAdaptation"] = (function()
--!nonstrict
--[[
	camera/EyeAdaptation.lua
	-----------------------------------------------------------------------------
	Auto-exposure. We have no framebuffer/luminance readback, so we ESTIMATE scene
	luminance cheaply: a sky-brightness term from ClockTime plus a few forward/down
	raycasts whose hit-colour luminance proxies for what the camera sees. That
	estimate (bus.sceneLuminance) drives ExposureCompensation toward eye_adapt_target
	using frame-rate-independent exponential smoothing with a SLOW tau
	(eye_adapt_speed) — exactly the "v += (target-v)*(1-exp(-dt/tau))" form — so the
	exposure breathes like a real eye, clamped to [eye_adapt_min, eye_adapt_max].

	bus.exposure is consumed by lighting/Lighting (applies it) and postfx/Bloom
	(threshold coupling). Documented as an estimate, not a real meter.
]]

return function(require)
	local State = require("core/State")
	local Util = require("core/Util")

	local EyeAdaptation = {}
	EyeAdaptation.id = "camera/EyeAdaptation"

	function EyeAdaptation.start(ctx)
		local maid = ctx.maid:childMaid()
		EyeAdaptation._maid = maid
		local L = ctx.services.Lighting

		local params = RaycastParams.new()
		params.FilterType = Enum.RaycastFilterType.Exclude
		local function refresh()
			local ignore = { ctx.worldFolder }
			local char = ctx.services.Players.LocalPlayer and ctx.services.Players.LocalPlayer.Character
			if char then ignore[#ignore + 1] = char end
			params.FilterDescendantsInstances = ignore
		end
		refresh()
		local lp = ctx.services.Players.LocalPlayer
		if lp then maid:give(lp.CharacterAdded:Connect(refresh)) end

		-- seed exposure from the static config so we don't pop on first frame
		ctx.bus.exposure = State.get("lighting_exposure")
		local lum = 0.5

		local function skyLuminance()
			-- day factor from ClockTime: ~1 at noon, ~0 deep night.
			local h = State.get("lighting_clock_time")
			local day = math.clamp(math.sin((h - 6) / 12 * math.pi), 0, 1)
			return 0.10 + day * 0.78
		end

		-- A representative spread of rays approximating "what fills the frame":
		-- forward, four spread, two slightly-up (catch bright sky/windows), one down.
		-- Sky misses count at full sky brightness so looking at a bright sky correctly
		-- READS as bright (→ exposure pulls DOWN, preventing the white-out you'd get
		-- otherwise). This is the auto-adapt that keeps any game from blowing out.
		local FAN = {
			{ 0, 0 }, { 22, 6 }, { -22, 6 }, { 12, -8 }, { -12, -8 },
			{ 40, 14 }, { -40, 14 }, { 0, -28 },
		}
		local function sampleLuminance(cam)
			local cf = cam.CFrame
			local sky = skyLuminance()
			local total, n = 0, 0
			for _, a in ipairs(FAN) do
				local dir = (cf * CFrame.Angles(math.rad(a[2]), math.rad(a[1]), 0)).LookVector
				local r = workspace:Raycast(cf.Position, dir * 160, params)
				if r then
					local ok, c = pcall(function() return r.Instance.Color end)
					-- surface luminance lit by the current sky term; clamp so neon/white
					-- parts don't dominate the meter.
					local sl = (ok and typeof(c) == "Color3") and Util.luminance(c) or 0.5
					total += math.min(1, sl * (0.35 + 0.65 * sky))
				else
					total += sky -- the ray saw open sky → full sky brightness
				end
				n += 1
			end
			return total / math.max(1, n)
		end

		local sampleAccum = 0
		maid:give(ctx.services.RunService.Heartbeat:Connect(function(dt)
			if not State.get("eye_adapt_enabled") then
				-- hand exposure back to the static value when disabled
				ctx.bus.exposure = State.get("lighting_exposure")
				return
			end
			local cam = ctx.camera()
			if not cam then return end
			sampleAccum += dt
			if sampleAccum >= 0.12 then
				sampleAccum = 0
				lum = sampleLuminance(cam)
				ctx.bus.sceneLuminance = lum
			end
			-- Gentle proportional response around the static exposure baseline: a scene
			-- already near target leaves exposure ≈ lighting_exposure (we ENHANCE, we
			-- don't fight a well-lit game); brighter → pull down, darker → lift modestly.
			-- gain 1.4 + the tightened [min,max] clamp prevents runaway over-exposure.
			local err = State.get("eye_adapt_target") - lum
			local base = State.get("lighting_exposure")
			local target = Util.clamp(base + err * 1.4, State.get("eye_adapt_min"), State.get("eye_adapt_max"))
			ctx.bus.exposure = Util.damp(ctx.bus.exposure, target, State.get("eye_adapt_speed"), dt)
		end))

		ctx.log.debug("EyeAdaptation online")
		return EyeAdaptation
	end

	function EyeAdaptation.stop() if EyeAdaptation._maid then EyeAdaptation._maid:clean() end end

	return EyeAdaptation
end

end)()

__modules["camera/Shake"] = (function()
--!nonstrict
--[[
	camera/Shake.lua
	-----------------------------------------------------------------------------
	Handheld camera feel. Two layers:
	  * idle Perlin sway (math.noise over time) scaled by cam_shake_amount — the
	    subtle constant motion that makes a locked camera feel "held",
	  * impulse shakes (Shake.impulse(mag)) that spike and decay, for hits/landings.
	getOffset(dt) returns a small CFrame the CameraFX controller composites ONTO the
	camera (offset-only — never seizes the camera). Allocation-free.
]]

return function(require)
	local State = require("core/State")
	local Util = require("core/Util")

	local Shake = {}
	Shake.id = "camera/Shake"
	local t = 0
	local impulse = 0

	function Shake.start(ctx)
		Shake._ctx = ctx
		return Shake
	end

	function Shake.impulse(mag)
		impulse = math.min(2, impulse + (mag or 0.5))
	end

	-- returns a CFrame offset (rotation-dominant, tiny translation)
	function Shake.getOffset(dt)
		if not State.get("cam_shake") then return nil end
		t += dt
		local amt = State.get("cam_shake_amount")
		-- idle sway
		local rx = Util.noise(t * 0.7, 0, 0) * 0.012 * amt
		local ry = Util.noise(0, t * 0.6, 0) * 0.012 * amt
		local rz = Util.noise(0, 0, t * 0.5) * 0.006 * amt
		-- impulse (decays)
		if impulse > 0 then
			impulse = math.max(0, impulse - dt * 3)
			local k = impulse
			rx += Util.noise(t * 18, 0, 0) * 0.03 * k
			ry += Util.noise(0, t * 17, 0) * 0.03 * k
			rz += Util.noise(0, 0, t * 16) * 0.02 * k
		end
		return CFrame.Angles(rx, ry, rz)
	end

	function Shake.stop() end

	return Shake
end

end)()

__modules["camera/Freecam"] = (function()
--!nonstrict
--[[
	camera/Freecam.lua
	-----------------------------------------------------------------------------
	WASD / gamepad fly camera for screenshots and scene scouting.

	This is one of the few places we DELIBERATELY seize the camera: on enable we
	capture CameraType (Snapshot) and set it Scriptable, lock the mouse to centre,
	and drive the camera ourselves. On disable we restore everything. The session is
	owned by a dedicated Maid so repeated toggles never leak, and teardown disables a
	live session automatically.
]]

return function(require)
	local State = require("core/State")
	local Maid = require("core/Maid")
	local Util = require("core/Util")

	local Freecam = {}
	Freecam.id = "camera/Freecam"
	local active = false

	function Freecam.start(ctx)
		Freecam._ctx = ctx
		Freecam._maid = ctx.maid:childMaid()
		-- ensure a live session is torn down on unload
		Freecam._maid:give(function() if active then Freecam.toggle(false) end end)
		return Freecam
	end

	function Freecam.isActive() return active end

	function Freecam.toggle(on)
		if on == nil then on = not active end
		if on == active then return end
		if on then Freecam._enable() else Freecam._disable() end
	end

	function Freecam._enable()
		local ctx = Freecam._ctx
		local cam = ctx.camera()
		if not cam then return end
		active = true
		local UIS = ctx.services.UserInputService
		local session = Maid.new()
		Freecam._session = session

		ctx.snapshot.capture(cam, "CameraType")
		cam.CameraType = Enum.CameraType.Scriptable

		local prevMouseBehavior = UIS.MouseBehavior
		UIS.MouseBehavior = Enum.MouseBehavior.LockCenter
		session:give(function() pcall(function() UIS.MouseBehavior = prevMouseBehavior end) end)

		-- orientation state seeded from current camera
		local look = cam.CFrame.LookVector
		local yaw = math.atan2(-look.X, -look.Z)
		local pitch = math.asin(Util.clamp(look.Y, -1, 1))
		local pos = cam.CFrame.Position

		-- gamepad thumbstick cache
		local moveStick, lookStick = Vector2.zero, Vector2.zero
		session:give(UIS.InputChanged:Connect(function(input)
			if input.KeyCode == Enum.KeyCode.Thumbstick1 then
				moveStick = Vector2.new(input.Position.X, input.Position.Y)
			elseif input.KeyCode == Enum.KeyCode.Thumbstick2 then
				lookStick = Vector2.new(input.Position.X, input.Position.Y)
			end
		end))

		local SENS = 0.003
		session:give(ctx.services.RunService.PreRender:Connect(function(dt)
			-- mouse look
			local md = UIS:GetMouseDelta()
			yaw -= md.X * SENS
			pitch = Util.clamp(pitch - md.Y * SENS, -1.4, 1.4)
			-- gamepad look
			yaw -= lookStick.X * dt * 2
			pitch = Util.clamp(pitch + lookStick.Y * dt * 2, -1.4, 1.4)

			local rot = CFrame.fromEulerAnglesYXZ(pitch, yaw, 0)
			-- movement basis
			local fwd = rot.LookVector
			local right = rot.RightVector
			local speed = (UIS:IsKeyDown(Enum.KeyCode.LeftShift) and 120 or 48) * dt
			local move = Vector3.zero
			if UIS:IsKeyDown(Enum.KeyCode.W) then move += fwd end
			if UIS:IsKeyDown(Enum.KeyCode.S) then move -= fwd end
			if UIS:IsKeyDown(Enum.KeyCode.D) then move += right end
			if UIS:IsKeyDown(Enum.KeyCode.A) then move -= right end
			if UIS:IsKeyDown(Enum.KeyCode.E) or UIS:IsKeyDown(Enum.KeyCode.Space) then move += Vector3.yAxis end
			if UIS:IsKeyDown(Enum.KeyCode.Q) then move -= Vector3.yAxis end
			-- gamepad move
			move += fwd * moveStick.Y + right * moveStick.X
			if move.Magnitude > 0 then move = move.Unit end
			pos += move * speed

			cam.CFrame = CFrame.new(pos) * rot
		end))

		Freecam._maid:give(session)
		if ctx.notify then pcall(ctx.notify, "Freecam", "WASD + mouse to fly, Shift = fast. Toggle again to exit.", 4) end
		ctx.log.debug("Freecam enabled")
	end

	function Freecam._disable()
		local ctx = Freecam._ctx
		active = false
		if Freecam._session then
			Freecam._session:clean()
			Freecam._session = nil
		end
		local cam = ctx.camera()
		if cam then cam.CameraType = Enum.CameraType.Custom end
		ctx.log.debug("Freecam disabled")
	end

	function Freecam.stop() if Freecam._maid then Freecam._maid:clean() end end

	return Freecam
end

end)()

__modules["camera/PhotoMode"] = (function()
--!nonstrict
--[[
	camera/PhotoMode.lua
	-----------------------------------------------------------------------------
	A clean composition mode for screenshots:
	  * hides the game HUD (CoreGui) and our own control panel,
	  * shows rule-of-thirds guides + a level-horizon indicator (rotates with camera
	    roll so you can level the shot),
	  * keeps the cinematic grade/overlays for the "final frame" look,
	  * prompts the user to capture (Roblox/OS screenshot — there is no reliable
	    in-engine capture API; an executor hook is used if present).

	Pairs with Freecam for positioning. Does NOT seize the camera (non-exclusive),
	honouring the contention rule. Everything restores on exit.
]]

return function(require)
	local Maid = require("core/Maid")

	local PhotoMode = {}
	PhotoMode.id = "camera/PhotoMode"
	local active = false

	function PhotoMode.start(ctx)
		PhotoMode._ctx = ctx
		PhotoMode._maid = ctx.maid:childMaid()
		PhotoMode._maid:give(function() if active then PhotoMode.toggle(false) end end)
		return PhotoMode
	end

	function PhotoMode.isActive() return active end

	function PhotoMode.toggle(on)
		if on == nil then on = not active end
		if on == active then return end
		if on then PhotoMode._enable() else PhotoMode._disable() end
	end

	function PhotoMode._enable()
		local ctx = PhotoMode._ctx
		active = true
		local session = Maid.new()
		PhotoMode._session = session
		local Snapshot = ctx.snapshot

		-- hide game HUD
		pcall(function()
			ctx.services.StarterGui:SetCoreGuiEnabled(Enum.CoreGuiType.All, false)
		end)
		session:give(function()
			pcall(function() ctx.services.StarterGui:SetCoreGuiEnabled(Enum.CoreGuiType.All, true) end)
		end)

		-- hide our control panel (Rayfield) if present
		if ctx.toggleUI then pcall(ctx.toggleUI, false) end

		-- aids container
		local aids = Snapshot.create("Frame", {
			Name = "PhotoAids", BackgroundTransparency = 1,
			Size = UDim2.fromScale(1, 1), ZIndex = 80, Active = false,
		}, ctx.gui)
		session:give(aids)

		local function gridLine(size, pos)
			Snapshot.create("Frame", {
				BackgroundColor3 = Color3.new(1, 1, 1), BackgroundTransparency = 0.7,
				BorderSizePixel = 0, Size = size, Position = pos, ZIndex = 80, Active = false,
			}, aids)
		end
		-- rule of thirds
		gridLine(UDim2.new(0, 1, 1, 0), UDim2.fromScale(1 / 3, 0))
		gridLine(UDim2.new(0, 1, 1, 0), UDim2.fromScale(2 / 3, 0))
		gridLine(UDim2.new(1, 0, 0, 1), UDim2.fromScale(0, 1 / 3))
		gridLine(UDim2.new(1, 0, 0, 1), UDim2.fromScale(0, 2 / 3))

		-- horizon indicator (rotates to stay world-level)
		local horizon = Snapshot.create("Frame", {
			Name = "Horizon", BackgroundColor3 = Color3.fromRGB(120, 220, 140),
			BackgroundTransparency = 0.4, BorderSizePixel = 0,
			AnchorPoint = Vector2.new(0.5, 0.5),
			Position = UDim2.fromScale(0.5, 0.5),
			Size = UDim2.new(0.5, 0, 0, 2), ZIndex = 81, Active = false,
		}, aids)

		session:give(ctx.services.RunService.PreRender:Connect(function()
			local cam = ctx.camera()
			if not cam then return end
			-- camera roll: angle of RightVector off the horizontal plane
			local rv = cam.CFrame.RightVector
			local roll = math.atan2(rv.Y, Vector3.new(rv.X, 0, rv.Z).Magnitude)
			horizon.Rotation = math.deg(roll)
			horizon.BackgroundColor3 = (math.abs(roll) < 0.02)
				and Color3.fromRGB(120, 220, 140) or Color3.fromRGB(220, 180, 120)
		end))

		PhotoMode._tryScreenshotHint(ctx)
		PhotoMode._maid:give(session)
		ctx.log.debug("PhotoMode enabled")
	end

	function PhotoMode._tryScreenshotHint(ctx)
		-- No reliable in-engine capture; try executor hooks, else prompt.
		local captured = false
		for _, name in ipairs({ "captureScreenshot", "take_screenshot" }) do
			local fn = (getgenv and getgenv()[name]) or rawget(_G, name)
			if typeof(fn) == "function" then
				captured = pcall(fn)
				if captured then break end
			end
		end
		if not captured and ctx.notify then
			pcall(ctx.notify, "Photo Mode", "Compose, then use your screenshot key. Toggle again to exit.", 5)
		end
	end

	function PhotoMode._disable()
		local ctx = PhotoMode._ctx
		active = false
		if PhotoMode._session then
			PhotoMode._session:clean()
			PhotoMode._session = nil
		end
		if ctx.toggleUI then pcall(ctx.toggleUI, true) end
		ctx.log.debug("PhotoMode disabled")
	end

	function PhotoMode.stop() if PhotoMode._maid then PhotoMode._maid:clean() end end

	return PhotoMode
end

end)()

__modules["enhancers/Enhancers"] = (function()
--!nonstrict
--[[
	enhancers/Enhancers.lua  —  CONTROLLER (manifest.boot)
	-----------------------------------------------------------------------------
	Master gate for the budget-aware scene enhancers. Starts each sub-enhancer; each
	one self-gates on enh_enabled AND its own enh_* key, so toggling either in the UI
	turns the effect on/off live. setQuality fans out to subs that scale particle /
	beam budgets.
]]

return function(require)
	local State = require("core/State")

	local Enhancers = {}
	Enhancers.id = "enhancers/Enhancers"
	local subs = {}

	function Enhancers.start(ctx)
		local maid = ctx.maid:childMaid()
		Enhancers._maid = maid

		for _, name in ipairs({
			"enhancers/Foliage", "enhancers/Fire", "enhancers/Smoke", "enhancers/Water",
			"enhancers/Particles", "enhancers/Lights", "enhancers/Beams",
		}) do
			local ok, handle = pcall(function()
				local m = require(name)
				return m.start(ctx) or m
			end)
			if ok and handle then
				subs[#subs + 1] = handle
				ctx.registerHandle(handle)
			else
				ctx.log.error("enhancer failed:", name, handle)
			end
		end

		ctx.log.debug("Enhancers online (" .. #subs .. " active)")
		return Enhancers
	end

	function Enhancers.setQuality(q)
		for _, s in ipairs(subs) do
			if type(s.setQuality) == "function" then pcall(s.setQuality, q) end
		end
	end

	function Enhancers.stop()
		if Enhancers._maid then Enhancers._maid:clean() end
	end

	return Enhancers
end

end)()

__modules["enhancers/Foliage"] = (function()
--!nonstrict
--[[
	enhancers/Foliage.lua
	-----------------------------------------------------------------------------
	Noise-driven wind sway for foliage parts (Scanner kind "foliage"). We capture
	each swayed part's original CFrame ONCE via Snapshot (so unload restores it
	exactly) and apply a small, phase-offset rotational wobble around its base each
	frame. Budgeted: only a rotating subset of nearby foliage is updated per frame,
	amplitude scales with weather_wind. Only ANCHORED parts are swayed (moving a
	physics part would fight the engine).
]]

return function(require)
	local State = require("core/State")
	local Util = require("core/Util")

	local Foliage = {}
	Foliage.id = "enhancers/Foliage"
	local BUDGET = 40
	local RADIUS = 160

	function Foliage.start(ctx)
		local maid = ctx.maid:childMaid()
		Foliage._maid = maid
		local Snapshot = ctx.snapshot
		local Scanner = require("detection/Scanner")
		Foliage._q = ctx.getQuality()

		local bases = setmetatable({}, { __mode = "k" }) -- part -> base CFrame
		local list = {}
		local cursor = 1

		local function enroll(part)
			if bases[part] then return end
			if not part:IsA("BasePart") or not part.Anchored then return end
			Snapshot.capture(part, "CFrame")   -- remember original for restore
			bases[part] = part.CFrame
			list[#list + 1] = part
		end

		for _, p in ipairs(Scanner.getByKind("foliage")) do enroll(p) end
		maid:give(Scanner.onClassified:Connect(function(part, cls)
			if cls.isFoliage then enroll(part) end
		end))

		local t = 0
		maid:give(ctx.services.RunService.Heartbeat:Connect(function(dt)
			if not (State.get("enh_enabled") and State.get("enh_foliage_wind")) then return end
			t += dt
			local cam = ctx.camera()
			local camPos = cam and cam.CFrame.Position or Vector3.zero
			local amp = (0.04 + State.get("weather_wind") * 0.12) -- radians
			local n = #list
			if n == 0 then return end
			local budget = math.max(6, math.floor(BUDGET * (Foliage._q or 1)))
			local done, scanned = 0, 0
			while done < budget and scanned < n do
				local part = list[cursor]
				cursor = (cursor % n) + 1
				scanned += 1
				if part and part.Parent and bases[part] then
					if (part.Position - camPos).Magnitude <= RADIUS then
						local phase = (part.Position.X + part.Position.Z) * 0.1
						local sway = Util.noise(t * 0.6 + phase, 0, 0) * amp
						local sway2 = Util.noise(0, t * 0.5 + phase, 0) * amp * 0.6
						part.CFrame = bases[part] * CFrame.Angles(sway2, 0, sway)
						done += 1
					end
				end
			end
		end))

		ctx.log.debug("Foliage sway online; candidates =", #list)
		return Foliage
	end

	function Foliage.setQuality(q) Foliage._q = q end
	function Foliage.stop() if Foliage._maid then Foliage._maid:clean() end end

	return Foliage
end

end)()

__modules["enhancers/Fire"] = (function()
--!nonstrict
--[[
	enhancers/Fire.lua
	-----------------------------------------------------------------------------
	Upgrades stock Fire instances (Scanner kind "fire") with a flickering warm
	PointLight so flames actually light their surroundings, plus a gentle Fire size
	pulse. We create our own tagged PointLight (destroyed on unload) and only mutate
	scalar Brightness per frame — the flicker NumberSequence is conceptual; we drive
	Brightness directly from cheap noise. We never destroy the game's Fire.
]]

return function(require)
	local State = require("core/State")
	local Util = require("core/Util")

	local Fire = {}
	Fire.id = "enhancers/Fire"
	local RADIUS = 180

	function Fire.start(ctx)
		local maid = ctx.maid:childMaid()
		Fire._maid = maid
		local Snapshot = ctx.snapshot
		local Scanner = require("detection/Scanner")

		local lights = setmetatable({}, { __mode = "k" }) -- part -> PointLight (ours)

		local function enroll(part)
			if lights[part] then return end
			local fire = part:FindFirstChildOfClass("Fire")
			if not fire then return end
			local light = Snapshot.create("PointLight", {
				Name = "FireLight",
				Color = Color3.fromRGB(255, 150, 70),
				Range = 18, Brightness = 2, Enabled = true,
			}, part)
			lights[part] = light
		end

		for _, p in ipairs(Scanner.getByKind("fire")) do enroll(p) end
		maid:give(Scanner.onClassified:Connect(function(part, cls)
			if cls.kind == "fire" then enroll(part) end
		end))

		local t = 0
		maid:give(ctx.services.RunService.Heartbeat:Connect(function(dt)
			local on = State.get("enh_enabled") and State.get("enh_fire")
			t += dt
			local cam = ctx.camera()
			local camPos = cam and cam.CFrame.Position or Vector3.zero
			for part, light in pairs(lights) do
				if part.Parent and light.Parent then
					light.Enabled = on
					if on and (part.Position - camPos).Magnitude <= RADIUS then
						local flick = 0.5 + 0.5 * (Util.noise(t * 6 + part.Position.X, 0, 0) * 0.5 + 0.5)
						light.Brightness = 1.5 + flick * 3
						light.Range = 16 + flick * 6
					end
				end
			end
		end))

		ctx.log.debug("Fire enhancer online")
		return Fire
	end

	function Fire.stop() if Fire._maid then Fire._maid:clean() end end

	return Fire
end

end)()

__modules["enhancers/Smoke"] = (function()
--!nonstrict
--[[
	enhancers/Smoke.lua
	-----------------------------------------------------------------------------
	Softens / layers existing Smoke instances (Scanner kind "smoke") by nudging their
	Opacity, Size and RiseVelocity for a thicker, slower, more volumetric look. We
	mutate the GAME's Smoke via Snapshot (capture-once → restore on unload); we never
	create or destroy the game's emitters. All real Smoke properties.
]]

return function(require)
	local State = require("core/State")

	local Smoke = {}
	Smoke.id = "enhancers/Smoke"

	function Smoke.start(ctx)
		local maid = ctx.maid:childMaid()
		Smoke._maid = maid
		local Snapshot = ctx.snapshot
		local Scanner = require("detection/Scanner")
		local touched = setmetatable({}, { __mode = "k" })

		local function apply(part)
			local on = State.get("enh_enabled") and State.get("enh_smoke")
			if not on then return end
			local smoke = part:FindFirstChildOfClass("Smoke")
			if not smoke or touched[smoke] then return end
			touched[smoke] = true
			Snapshot.set(smoke, "Opacity", math.min(1, smoke.Opacity * 1.15))
			Snapshot.set(smoke, "Size", smoke.Size * 1.25)
			Snapshot.set(smoke, "RiseVelocity", smoke.RiseVelocity * 0.7)
		end

		local function applyAll()
			for _, p in ipairs(Scanner.getByKind("smoke")) do apply(p) end
		end

		maid:give(Scanner.onClassified:Connect(function(part, cls)
			if cls.kind == "smoke" then apply(part) end
		end))
		maid:give(State.observeMany({ "enh_enabled", "enh_smoke" }, applyAll))
		task.defer(applyAll)

		ctx.log.debug("Smoke enhancer online")
		return Smoke
	end

	function Smoke.stop() if Smoke._maid then Smoke._maid:clean() end end

	return Smoke
end

end)()

__modules["enhancers/Water"] = (function()
--!nonstrict
--[[
	enhancers/Water.lua
	-----------------------------------------------------------------------------
	Polishes Terrain water for a cleaner, more reflective, more cinematic look by
	tuning the REAL Terrain water properties — WaterColor, WaterTransparency,
	WaterReflectance, WaterWaveSize, WaterWaveSpeed — via Snapshot (restored on
	unload). Wetness from weather nudges reflectance up. Guards the (possible)
	absence of Terrain on baseplate / void places.
]]

return function(require)
	local State = require("core/State")
	local Util = require("core/Util")

	local Water = {}
	Water.id = "enhancers/Water"

	function Water.start(ctx)
		local maid = ctx.maid:childMaid()
		Water._maid = maid
		local Snapshot = ctx.snapshot
		local terrain = ctx.services.Workspace:FindFirstChildOfClass("Terrain")
		if not terrain then
			ctx.log.debug("Water: no Terrain — skipped")
			return Water
		end

		local function apply()
			if not (State.get("enh_enabled") and State.get("enh_water")) then return end
			local wet = ctx.bus.wetness or 0
			Snapshot.set(terrain, "WaterColor", Color3.fromRGB(18, 58, 78))
			Snapshot.set(terrain, "WaterTransparency", 0.18)
			Snapshot.set(terrain, "WaterReflectance", Util.clamp(0.6 + wet * 0.3, 0, 1))
			Snapshot.set(terrain, "WaterWaveSize", 0.12)
			Snapshot.set(terrain, "WaterWaveSpeed", 8)
		end

		maid:give(State.observeMany({ "enh_enabled", "enh_water" }, apply))
		-- refresh reflectance as wetness drifts (throttled)
		local accum = 0
		maid:give(ctx.services.RunService.Heartbeat:Connect(function(dt)
			accum += dt
			if accum < 1 then return end
			accum = 0
			apply()
		end))
		apply()

		ctx.log.debug("Water polish online")
		return Water
	end

	function Water.stop() if Water._maid then Water._maid:clean() end end

	return Water
end

end)()

__modules["enhancers/Particles"] = (function()
--!nonstrict
--[[
	enhancers/Particles.lua
	-----------------------------------------------------------------------------
	Ambient floating dust motes near the camera — the cheap trick that makes air feel
	volumetric in light shafts. One ParticleEmitter on a camera-following part; cached
	sequences; only Rate is mutated at runtime (scaled by quality + the enh_dust
	toggle). Zero per-frame allocation.
]]

return function(require)
	local State = require("core/State")

	local Particles = {}
	Particles.id = "enhancers/Particles"

	local SIZE = NumberSequence.new({
		NumberSequenceKeypoint.new(0, 0.04),
		NumberSequenceKeypoint.new(1, 0.06),
	})
	local TRANSP = NumberSequence.new({
		NumberSequenceKeypoint.new(0, 1),
		NumberSequenceKeypoint.new(0.3, 0.6),
		NumberSequenceKeypoint.new(0.7, 0.6),
		NumberSequenceKeypoint.new(1, 1),
	})
	local COLOR = ColorSequence.new(Color3.fromRGB(255, 250, 235))
	local BASE_RATE = 40

	function Particles.start(ctx)
		local maid = ctx.maid:childMaid()
		Particles._maid = maid
		local Snapshot = ctx.snapshot
		Particles._q = ctx.getQuality()

		local part = Snapshot.create("Part", {
			Name = "DustVolume",
			Anchored = true, CanCollide = false, CanQuery = false, CanTouch = false,
			Transparency = 1, Size = Vector3.new(60, 30, 60),
		}, ctx.worldFolder)

		local emitter = Snapshot.create("ParticleEmitter", {
			Name = "Dust",
			Rate = 0, Enabled = false,
			Lifetime = NumberRange.new(4, 8),
			Speed = NumberRange.new(0.4, 1.2),
			SpreadAngle = Vector2.new(180, 180),
			Acceleration = Vector3.new(0.3, -0.2, 0),
			Drag = 1,
			RotSpeed = NumberRange.new(-15, 15),
			Size = SIZE, Transparency = TRANSP, Color = COLOR,
			LightInfluence = 1, LightEmission = 0.4,
		}, part)

		maid:give(ctx.services.RunService.Heartbeat:Connect(function()
			local on = State.get("enh_enabled") and State.get("enh_dust")
			emitter.Enabled = on
			if on then
				emitter.Rate = BASE_RATE * (Particles._q or 1)
				local cam = ctx.camera()
				if cam then part.CFrame = cam.CFrame end
			end
		end))

		ctx.log.debug("Dust particles online")
		return Particles
	end

	function Particles.setQuality(q) Particles._q = math.clamp(q, 0, 1) end
	function Particles.stop() if Particles._maid then Particles._maid:clean() end end

	return Particles
end

end)()

__modules["enhancers/Lights"] = (function()
--!nonstrict
--[[
	enhancers/Lights.lua
	-----------------------------------------------------------------------------
	Light polish for existing PointLight/SpotLight/SurfaceLight (Scanner kind
	"light"). Three layers, each individually toggleable:

	  1. SHADOWS (enh_light_shadows) — most games ship lights with Shadows=false.
	     Turning it on is the single biggest indoor/night upgrade: streetlamps and
	     room lights start casting real shadows under Future lighting. Captured via
	     Snapshot so unload restores the original exactly.

	  2. STREET BEAMS (enh_light_beams) — the developed-night-city look. Each light
	     gets a tight inner cone + soft outer halo (camera-facing Beams), visible
	     ONLY at night (driven by the real sun direction). Coverage-capped and
	     near-camera only so it never floods a busy place. Beam Color/Transparency
	     sequences are cached/set-once — zero per-frame allocation; we only flip
	     .Enabled and nudge Brightness.

	  3. FLICKER (enh_lights_repair) — gentle noise wobble around base brightness
	     for a lived-in feel.

	Budgeted to lights within RADIUS of the camera; rig creation is spread across
	frames (CREATE_BUDGET/frame) so spawning a lit district never spikes a frame.
]]

return function(require)
	local State = require("core/State")
	local Util = require("core/Util")

	local Lights = {}
	Lights.id = "enhancers/Lights"

	local RADIUS = 160          -- only service lights within this of the camera
	local CREATE_BUDGET = 4     -- new beam rigs built per frame (spreads cost)

	-- cached, set-ONCE beam transparency profiles (never rebuilt per frame).
	local INNER_TRANSP = NumberSequence.new({
		NumberSequenceKeypoint.new(0, 1),
		NumberSequenceKeypoint.new(0.16, 0.45),
		NumberSequenceKeypoint.new(0.85, 0.72),
		NumberSequenceKeypoint.new(1, 1),
	})
	local OUTER_TRANSP = NumberSequence.new({
		NumberSequenceKeypoint.new(0, 1),
		NumberSequenceKeypoint.new(0.2, 0.8),
		NumberSequenceKeypoint.new(0.8, 0.92),
		NumberSequenceKeypoint.new(1, 1),
	})

	function Lights.start(ctx)
		local maid = ctx.maid:childMaid()
		Lights._maid = maid
		local Snapshot = ctx.snapshot
		local L = ctx.services.Lighting
		local Scanner = require("detection/Scanner")
		local isMobile = ctx.platform.isMobile

		Lights._q = ctx.getQuality()
		local MAX_RIGS = isMobile and 24 or 120

		-- light -> { base = brightness, baseShadows = bool, rig = {...}|nil }
		local lights = setmetatable({}, { __mode = "k" })
		local rigCount = 0

		local function enrollPart(part)
			for _, child in ipairs(part:GetChildren()) do
				if child:IsA("Light") and not lights[child] then
					Snapshot.capture(child, "Brightness")
					Snapshot.capture(child, "Shadows")
					lights[child] = { base = child.Brightness, parent = part }
					if State.get("enh_light_shadows") then
						pcall(function() child.Shadows = true end)
					end
				end
			end
		end

		for _, p in ipairs(Scanner.getByKind("light")) do enrollPart(p) end
		maid:give(Scanner.onClassified:Connect(function(part, cls)
			if cls.kind == "light" then enrollPart(part) end
		end))

		-- toggle shadows live
		maid:give(State.observe("enh_light_shadows", function(on)
			for light, info in pairs(lights) do
				if light.Parent then pcall(function() light.Shadows = on end) end
			end
		end))

		-- build a beam rig (inner cone + outer halo) for one light. Returns rig or nil.
		local function buildRig(light, part)
			if rigCount >= MAX_RIGS then return nil end
			local range = light.Range
			if range < 8 then return nil end
			local a0 = Snapshot.create("Attachment", { Name = "CinLightBeamA0" }, part)
			local a1 = Snapshot.create("Attachment", { Name = "CinLightBeamA1" }, part)
			a0.WorldPosition = part.Position
			a1.WorldPosition = part.Position + Vector3.new(0, -1, 0) * (range * 0.82)
			local col = ColorSequence.new(light.Color)
			local inner = Snapshot.create("Beam", {
				Name = "CinLightBeamInner", Attachment0 = a0, Attachment1 = a1,
				Color = col, Transparency = INNER_TRANSP, LightEmission = 1, LightInfluence = 0,
				FaceCamera = true, Segments = 6, Enabled = false,
				Width0 = math.clamp(range * 0.05, 0.25, 1.4),
				Width1 = math.clamp(range * 0.11, 0.5, 3.0),
			}, part)
			local outer = Snapshot.create("Beam", {
				Name = "CinLightBeamOuter", Attachment0 = a0, Attachment1 = a1,
				Color = col, Transparency = OUTER_TRANSP, LightEmission = 1, LightInfluence = 0,
				FaceCamera = true, Segments = 8, Enabled = false,
				Width0 = math.clamp(range * 0.16, 0.6, 4.5),
				Width1 = math.clamp(range * 0.32, 1.5, 9.0),
			}, part)
			rigCount += 1
			return { a0 = a0, a1 = a1, inner = inner, outer = outer }
		end

		local t = 0
		local accum = 0
		maid:give(ctx.services.RunService.Heartbeat:Connect(function(dt)
			t += dt
			accum += dt
			if accum < 0.08 then return end  -- run the pass at ~12 Hz, not every frame
			accum = 0
			local flickerOn = State.get("enh_enabled") and State.get("enh_lights_repair")
			local beamsOn = State.get("enh_enabled") and State.get("enh_light_beams")
			local cam = ctx.camera()
			local camPos = cam and cam.CFrame.Position or Vector3.zero

			-- night factor from the REAL sun position (below horizon → night).
			local sunY = L:GetSunDirection().Y
			local night = Util.clamp((0.04 - sunY) * 3.5, 0, 1)
			local beamsVisible = beamsOn and night > 0.45
			local created = 0

			for light, info in pairs(lights) do
				local part = light.Parent
				if part and part:IsA("BasePart") then
					local near = (part.Position - camPos).Magnitude <= RADIUS

					-- flicker
					if flickerOn and near then
						local flick = Util.noise(t * 4 + part.Position.X * 0.05, 0, 0)
						light.Brightness = math.max(0, info.base * (1 + flick * 0.12))
					elseif not flickerOn then
						light.Brightness = info.base
					end

					-- street beams: lazily build (budgeted) when near + night, toggle visibility
					if beamsVisible and near then
						if not info.rig and created < CREATE_BUDGET then
							info.rig = buildRig(light, part)
							created += 1
						end
						if info.rig then
							info.rig.inner.Enabled = true
							info.rig.outer.Enabled = true
						end
					elseif info.rig then
						info.rig.inner.Enabled = false
						info.rig.outer.Enabled = false
					end
				end
			end
		end))

		ctx.log.debug("Light polish online (shadows + street beams)")
		return Lights
	end

	function Lights.setQuality(q) Lights._q = math.clamp(q, 0, 1) end
	function Lights.stop() if Lights._maid then Lights._maid:clean() end end

	return Lights
end

end)()

__modules["enhancers/Beams"] = (function()
--!nonstrict
--[[
	enhancers/Beams.lua  —  god-rays (sun shafts)
	-----------------------------------------------------------------------------
	Roblox has no programmable volumetric scattering, BUT it ships a real, good-
	looking screen-space sun-ray effect: SunRaysEffect. It scatters rays from the
	ACTUAL sun's on-screen position and naturally fades as the sun leaves view —
	exactly what god-rays should do.

	An earlier version parked wide glowing Beam slabs in front of the camera; those
	read as blocky white shafts regardless of where the sun was. We deleted that and
	now drive SunRaysEffect (owned by postfx/Pipeline, published on bus.pipeline.sunrays)
	from real geometry: enh_godray_strength × how directly the camera faces the sun ×
	daytime. A whisper-thin pair of FaceCamera Beams is added ONLY when you look almost
	straight at the sun, as a soft accent — never wide, never opaque.

	Honest framing: this is screen-space sun scattering, not true volumetrics.
]]

return function(require)
	local State = require("core/State")
	local Util = require("core/Util")

	local Beams = {}
	Beams.id = "enhancers/Beams"

	-- cached, very faint accent-beam transparency (built ONCE).
	local ACCENT_TRANSP = NumberSequence.new({
		NumberSequenceKeypoint.new(0, 1),
		NumberSequenceKeypoint.new(0.5, 0.9),
		NumberSequenceKeypoint.new(1, 1),
	})

	function Beams.start(ctx)
		local maid = ctx.maid:childMaid()
		Beams._maid = maid
		local Snapshot = ctx.snapshot
		local L = ctx.services.Lighting
		Beams._q = ctx.getQuality()

		-- two thin accent shafts on a camera-following rig (subtle, sun-gated).
		local rig = Snapshot.create("Part", {
			Name = "GodRayRig", Anchored = true, CanCollide = false,
			CanQuery = false, CanTouch = false, Transparency = 1, Size = Vector3.new(1, 1, 1),
		}, ctx.worldFolder)
		local accents = {}
		for i = 1, 2 do
			local a0 = Snapshot.create("Attachment", { Name = "GA0_" .. i }, rig)
			local a1 = Snapshot.create("Attachment", { Name = "GA1_" .. i }, rig)
			local beam = Snapshot.create("Beam", {
				Name = "GodRayAccent_" .. i, Attachment0 = a0, Attachment1 = a1,
				Color = ColorSequence.new(Color3.fromRGB(255, 246, 220)),
				Transparency = ACCENT_TRANSP, LightEmission = 1, LightInfluence = 0,
				FaceCamera = true, Width0 = 1.5, Width1 = 4, Segments = 5, Enabled = false,
			}, rig)
			accents[i] = { a0 = a0, a1 = a1, beam = beam, side = (i == 1) and 1 or -1 }
		end

		local accum = 0
		maid:give(ctx.services.RunService.Heartbeat:Connect(function(dt)
			accum += dt
			if accum < 0.08 then return end
			accum = 0

			local sunrays = ctx.bus.pipeline and ctx.bus.pipeline.sunrays
			local cam = ctx.camera()
			local on = State.get("enh_enabled") and State.get("enh_godrays")
			local sunDir = L:GetSunDirection()           -- unit vector toward the sun
			local daytime = math.clamp(sunDir.Y * 6, 0, 1) -- fade near horizon/night
			local facing = 0
			if cam then
				facing = math.clamp(cam.CFrame.LookVector:Dot(sunDir), 0, 1) -- 1 = staring at sun
			end
			local strength = State.get("enh_godray_strength")

			-- DRIVE THE REAL ENGINE EFFECT (the good rays).
			if sunrays then
				local target = on and (strength * 0.45 * daytime * (0.35 + 0.65 * facing)) or 0
				Snapshot.set(sunrays, "Intensity", Util.clamp(target * (Beams._q or 1), 0, 0.5))
				Snapshot.set(sunrays, "Spread", 0.9)
			end

			-- whisper-thin accent shafts, ONLY when looking almost into the sun.
			local accentOn = on and daytime > 0.2 and facing > 0.55 and strength > 0.01
			if cam and accentOn then
				local base = cam.CFrame.Position + sunDir * 80
				for _, s in ipairs(accents) do
					s.beam.Enabled = true
					local lateral = cam.CFrame.RightVector * (s.side * 5)
					s.a0.WorldPosition = base + lateral + sunDir * 40
					s.a1.WorldPosition = base + lateral - cam.CFrame.LookVector * 30
					s.beam.Width0 = 1 + strength * 1.5
					s.beam.Width1 = 3 + strength * 4
				end
			else
				for _, s in ipairs(accents) do s.beam.Enabled = false end
			end
		end))

		ctx.log.debug("God-rays online (SunRaysEffect-driven)")
		return Beams
	end

	function Beams.setQuality(q) Beams._q = math.clamp(q, 0, 1) end
	function Beams.stop() if Beams._maid then Beams._maid:clean() end end

	return Beams
end

end)()

__modules["perf/AdaptiveQuality"] = (function()
--!nonstrict
--[[
	perf/AdaptiveQuality.lua  —  CONTROLLER (manifest.boot)
	-----------------------------------------------------------------------------
	Closed-loop quality controller. Tracks an FPS EMA and nudges bus.qualityMul up or
	down to defend perf_target_fps, WITH HYSTERESIS (a deadband + consecutive-sample
	requirement) so it doesn't oscillate. Every effect module consumes the resulting
	ctx.getQuality() via its setQuality(0..1), so a single dial scales the whole
	pipeline.

	Conceptual step ladder when LOWERING (cost-first): viewport mirror → volumetric
	beams → particle rates → scanner budget → DoF; raising reverses it. Rather than
	bespoke per-feature toggles (which would fight the user's explicit settings) we
	scale the shared qualityMul, which those subsystems already interpret in that
	rough cost order via their setQuality implementations.

	Starts Benchmark (for the initial tier) and PerfHUD.
]]

return function(require)
	local State = require("core/State")
	local Util = require("core/Util")

	local AdaptiveQuality = {}
	AdaptiveQuality.id = "perf/AdaptiveQuality"

	function AdaptiveQuality.start(ctx)
		local maid = ctx.maid:childMaid()
		AdaptiveQuality._maid = maid

		local Benchmark = require("perf/Benchmark"); Benchmark.start(ctx); ctx.registerHandle(Benchmark)
		local PerfHUD = require("perf/PerfHUD"); PerfHUD.start(ctx); ctx.registerHandle(PerfHUD)
		AdaptiveQuality.Benchmark = Benchmark

		local fps = 60
		local belowCount, aboveCount = 0, 0
		local STEP = 0.08
		local tickAccum = 0

		maid:give(ctx.services.RunService.Heartbeat:Connect(function(dt)
			-- FPS EMA (frame-rate independent-ish; dt is per frame)
			if dt > 0 then
				local inst = 1 / dt
				fps = fps + (inst - fps) * 0.1
			end
			ctx.bus.fps = fps

			tickAccum += dt
			if tickAccum < 0.5 then return end
			tickAccum = 0
			if not State.get("perf_adaptive") then return end

			local target = State.get("perf_target_fps")
			local lowBand = target * 0.92
			local highBand = target * 1.06
			local minMul = State.get("perf_min_quality")

			if fps < lowBand then
				belowCount += 1; aboveCount = 0
				if belowCount >= 2 then
					belowCount = 0
					local newMul = Util.clamp((ctx.bus.qualityMul or 1) - STEP, minMul, 1)
					if newMul ~= ctx.bus.qualityMul then
						ctx.bus.qualityMul = newMul
						if ctx.fanoutQuality then pcall(ctx.fanoutQuality) end
						ctx.log.debug(("Adaptive ↓ q=%.2f (fps %.0f)"):format(newMul, fps))
					end
				end
			elseif fps > highBand then
				aboveCount += 1; belowCount = 0
				if aboveCount >= 3 then -- raise more cautiously than we drop
					aboveCount = 0
					local newMul = Util.clamp((ctx.bus.qualityMul or 1) + STEP * 0.6, minMul, 1)
					if newMul ~= ctx.bus.qualityMul then
						ctx.bus.qualityMul = newMul
						if ctx.fanoutQuality then pcall(ctx.fanoutQuality) end
						ctx.log.debug(("Adaptive ↑ q=%.2f (fps %.0f)"):format(newMul, fps))
					end
				end
			else
				belowCount = 0; aboveCount = 0 -- in the deadband: stable
			end
		end))

		ctx.log.debug("AdaptiveQuality online")
		return AdaptiveQuality
	end

	function AdaptiveQuality.stop()
		if AdaptiveQuality._maid then AdaptiveQuality._maid:clean() end
	end

	return AdaptiveQuality
end

end)()

__modules["perf/Benchmark"] = (function()
--!nonstrict
--[[
	perf/Benchmark.lua
	-----------------------------------------------------------------------------
	Startup micro-benchmark → initial quality tier. We can't read GPU specs, so we
	time a fixed batch of CPU work (math + a handful of raycasts) across a few frames
	and bucket the result into tier 1/2/3, then seed bus.qualityMul accordingly
	(lower on mobile regardless). It's a coarse starting point; AdaptiveQuality then
	closes the loop on real frame-rate. Re-runnable from the UI.
]]

return function(require)
	local Benchmark = {}
	Benchmark.id = "perf/Benchmark"

	function Benchmark.start(ctx)
		Benchmark._ctx = ctx
		-- defer the first run a moment so boot cost doesn't skew it
		task.defer(function() Benchmark.run() end)
		return Benchmark
	end

	-- returns tier 1..3 and sets bus.qualityMul
	function Benchmark.run()
		local ctx = Benchmark._ctx
		if not ctx then return 2 end
		local params = RaycastParams.new()
		params.FilterType = Enum.RaycastFilterType.Exclude
		params.FilterDescendantsInstances = { ctx.worldFolder }

		local t0 = os.clock()
		local acc = 0
		for i = 1, 12000 do
			acc += math.sqrt(i) * math.sin(i * 0.001)
		end
		local origin = Vector3.new(0, 50, 0)
		for i = 1, 40 do
			workspace:Raycast(origin, Vector3.new(math.sin(i), -1, math.cos(i)) * 100, params)
		end
		local elapsed = os.clock() - t0  -- seconds for the fixed batch

		-- bucket: faster machines finish the batch quicker
		local tier
		if elapsed < 0.004 then tier = 3
		elseif elapsed < 0.012 then tier = 2
		else tier = 1 end
		if ctx.platform.isMobile then tier = math.min(tier, 1) end

		local mulByTier = { [1] = 0.45, [2] = 0.75, [3] = 1.0 }
		ctx.bus.qualityMul = mulByTier[tier]
		if ctx.fanoutQuality then pcall(ctx.fanoutQuality) end
		ctx.log.info(("Benchmark: tier %d (batch %.2fms) → qualityMul %.2f"):format(
			tier, elapsed * 1000, ctx.bus.qualityMul))
		return tier
	end

	function Benchmark.stop() end

	return Benchmark
end

end)()

__modules["perf/PerfHUD"] = (function()
--!nonstrict
--[[
	perf/PerfHUD.lua
	-----------------------------------------------------------------------------
	Toggleable on-screen diagnostics (perf_hud): FPS, frame-time, effective quality,
	and per-effect cost reported via ctx.perf.report(name, ms). A plain GUI overlay
	updated a few times a second (never per-frame string building). Reads bus.fps from
	AdaptiveQuality.
]]

return function(require)
	local State = require("core/State")

	local PerfHUD = {}
	PerfHUD.id = "perf/PerfHUD"

	function PerfHUD.start(ctx)
		local maid = ctx.maid:childMaid()
		PerfHUD._maid = maid
		local Snapshot = ctx.snapshot

		local frame = Snapshot.create("Frame", {
			Name = "PerfHUD",
			BackgroundColor3 = Color3.fromRGB(0, 0, 0),
			BackgroundTransparency = 0.4,
			Position = UDim2.fromOffset(8, 8),
			Size = UDim2.fromOffset(196, 86),
			BorderSizePixel = 0,
			ZIndex = 90, Visible = false,
		}, ctx.gui)
		Snapshot.create("UICorner", { CornerRadius = UDim.new(0, 6) }, frame)
		local label = Snapshot.create("TextLabel", {
			BackgroundTransparency = 1,
			Size = UDim2.new(1, -12, 1, -12),
			Position = UDim2.fromOffset(6, 6),
			Font = Enum.Font.Code,
			TextColor3 = Color3.fromRGB(180, 255, 200),
			TextXAlignment = Enum.TextXAlignment.Left,
			TextYAlignment = Enum.TextYAlignment.Top,
			TextSize = 13, ZIndex = 91, Text = "",
		}, frame)

		local accum = 0
		maid:give(ctx.services.RunService.Heartbeat:Connect(function(dt)
			local on = State.get("perf_hud")
			frame.Visible = on
			if not on then return end
			accum += dt
			if accum < 0.2 then return end
			accum = 0
			local fps = ctx.bus.fps or (1 / math.max(dt, 1e-3))
			local q = ctx.getQuality()
			local lines = {
				("FPS  %3d   (%.1f ms)"):format(math.floor(fps + 0.5), 1000 / math.max(fps, 1)),
				("Quality  %.0f%%  (mul %.2f)"):format(q * 100, ctx.bus.qualityMul or 1),
			}
			local costs = ctx.perf.get()
			local shown = 0
			for name, ms in pairs(costs) do
				lines[#lines + 1] = ("%-10s %.2fms"):format(name, ms)
				shown += 1
				if shown >= 2 then break end
			end
			label.Text = table.concat(lines, "\n")
		end))

		ctx.log.debug("PerfHUD ready")
		return PerfHUD
	end

	function PerfHUD.stop() if PerfHUD._maid then PerfHUD._maid:clean() end end

	return PerfHUD
end

end)()

