__modules["presets/Serializer"] = (function()
--!nonstrict
--[[
	presets/Serializer.lua  —  pure module
	-----------------------------------------------------------------------------
	Round-trips the full live State to/from a schema-versioned JSON string:
	    { v = <schemaVersion>, data = { key = value, ... } }
	HttpService:JSONEncode can't encode Color3/Vector3/Enum, so we flatten those via
	Util.encodeValue and rebuild them with Util.decodeValue on import. The copy/paste
	string is the PRIMARY portable path; writefile (ConfigStore) is a convenience.
	Everything is pcall-guarded so a malformed paste can never poison State.
]]

return function(require)
	local State = require("core/State")
	local Config = require("core/Config")
	local Util = require("core/Util")
	local Logger = require("core/Logger")

	local HttpService = game:GetService("HttpService")

	local Serializer = {}

	function Serializer.export()
		local snap = State.snapshot()
		local data = {}
		for k, v in pairs(snap) do
			if Config.meta[k] ~= nil then
				data[k] = Util.encodeValue(v)
			end
		end
		local payload = { v = Config.schemaVersion, data = data }
		local ok, json = pcall(function() return HttpService:JSONEncode(payload) end)
		if not ok then
			Logger.error("Serializer.export failed:", json)
			return nil
		end
		return json
	end

	-- returns ok, errOrChangedCount
	function Serializer.import(jsonString)
		if type(jsonString) ~= "string" or jsonString == "" then
			return false, "empty input"
		end
		local ok, payload = pcall(function() return HttpService:JSONDecode(jsonString) end)
		if not ok or type(payload) ~= "table" or type(payload.data) ~= "table" then
			Logger.error("Serializer.import: bad JSON")
			return false, "invalid JSON"
		end
		if payload.v ~= nil and payload.v ~= Config.schemaVersion then
			Logger.warn("Serializer.import: schema v" .. tostring(payload.v)
				.. " (current v" .. Config.schemaVersion .. ") — importing leniently")
		end
		local overlay = {}
		for k, v in pairs(payload.data) do
			if Config.meta[k] ~= nil then
				overlay[k] = Util.decodeValue(v)
			end
		end
		local changed = State.applyOverlay(overlay)
		return true, #changed
	end

	return Serializer
end

end)()

__modules["presets/ConfigStore"] = (function()
--!nonstrict
--[[
	presets/ConfigStore.lua  —  pure module
	-----------------------------------------------------------------------------
	Executor-only disk persistence convenience (writefile/readfile/isfile), keyed by
	schema version. EVERY filesystem call is gated behind a Platform capability check
	and wrapped in pcall, so on vanilla Roblox / Studio this degrades to silent no-ops
	and the copy/paste JSON path (Serializer) remains the portable source of truth.
]]

return function(require)
	local Platform = require("core/Platform")
	local Config = require("core/Config")
	local Logger = require("core/Logger")

	local ConfigStore = {}
	local FOLDER = "CinematicSuite"
	local PATH = FOLDER .. "/config_v" .. Config.schemaVersion .. ".json"

	local function ensureFolder()
		if Platform.caps.makefolder and Platform.caps.isfile then
			pcall(function()
				if isfile and not isfile(FOLDER) then
					if makefolder then makefolder(FOLDER) end
				end
			end)
		end
	end

	function ConfigStore.available()
		return Platform.caps.writefile and Platform.caps.readfile and Platform.caps.isfile
	end

	function ConfigStore.save(jsonString)
		if not (Platform.caps.writefile and type(jsonString) == "string") then return false end
		ensureFolder()
		local ok, err = pcall(function() writefile(PATH, jsonString) end)
		if not ok then Logger.warn("ConfigStore.save failed:", err) end
		return ok
	end

	function ConfigStore.exists()
		if not Platform.caps.isfile then return false end
		local ok, res = pcall(function() return isfile(PATH) end)
		return ok and res == true
	end

	function ConfigStore.load()
		if not (Platform.caps.readfile and ConfigStore.exists()) then return nil end
		local ok, data = pcall(function() return readfile(PATH) end)
		if ok and type(data) == "string" then return data end
		return nil
	end

	return ConfigStore
end

end)()

__modules["ui/UI"] = (function()
--!nonstrict
--[[
	ui/UI.lua  —  CONTROLLER (manifest.boot, near last)
	-----------------------------------------------------------------------------
	Builds the Rayfield control panel: one window with ConfigurationSaving, a tab per
	Config.tabs, every config setting AUTO-GENERATED from ui/Schema (live + persisted),
	and only the ACTION controls hand-wired (Freecam, Photo Mode, presets, import/
	export, re-benchmark, unload). Wires the toggle keybind and the Notify entry-point.
	Falls back to ui/FallbackUI if Rayfield can't be fetched/loaded.

	Rayfield is executor/Studio-loaded over HTTP — every remote call is pcall-guarded.
]]

return function(require)
	local State = require("core/State")
	local Config = require("core/Config")
	local Logger = require("core/Logger")
	local Platform = require("core/Platform")
	local Schema = require("ui/Schema")
	local Controls = require("ui/Controls")
	local Notify = require("ui/Notify")

	local UI = {}
	UI.id = "ui/UI"

	local function loadRayfield()
		if not (Platform.caps.httpGet and Platform.caps.loadstring) then return nil end
		local ok, lib = pcall(function()
			return loadstring(game:HttpGet("https://sirius.menu/rayfield"))()
		end)
		if ok and type(lib) == "table" then return lib end
		Logger.warn("Rayfield load failed:", lib)
		return nil
	end

	local function findRayfieldGui()
		local candidates = {}
		if Platform.caps.gethui then
			local ok, hui = pcall(gethui)
			if ok then candidates[#candidates + 1] = hui end
		end
		pcall(function() candidates[#candidates + 1] = game:GetService("CoreGui") end)
		local lp = game:GetService("Players").LocalPlayer
		if lp then candidates[#candidates + 1] = lp:FindFirstChild("PlayerGui") end
		for _, parent in ipairs(candidates) do
			if parent then
				local gui = parent:FindFirstChild("Rayfield")
				if gui then return gui end
			end
		end
		return nil
	end

	function UI.start(ctx)
		local maid = ctx.maid:childMaid()
		UI._maid = maid
		local globals = Platform.globalTable()
		local handle = globals["__CINEMATIC_SHADER"] or {}

		local Rayfield = loadRayfield()
		if not Rayfield then
			Logger.warn("Mounting FallbackUI (Rayfield unavailable).")
			local Fallback = require("ui/FallbackUI")
			Fallback.start(ctx)
			ctx.registerHandle(Fallback)
			-- minimal toggle + notify still available
			UI.toggle = function() end
			ctx.toggleUI = UI.toggle
			handle.toggleUI = UI.toggle
			handle.notify = Notify.send
			ctx.notify = Notify.send
			return UI
		end
		UI._rayfield = Rayfield
		Notify.setRayfield(Rayfield)

		-- ── window ────────────────────────────────────────────────────────────
		local placeId = 0
		pcall(function() placeId = game.PlaceId end)
		local window
		local okWin = pcall(function()
			window = Rayfield:CreateWindow({
				Name = "Cinematic Suite  v" .. Config.version,
				LoadingTitle = "Cinematic Graphics Suite",
				LoadingSubtitle = "by a senior rendering engineer",
				ConfigurationSaving = {
					Enabled = true,
					FolderName = "CinematicSuite",
					-- save-slot is suffixed with a tuning epoch: bumping it makes a
					-- retuned release start from fresh defaults instead of reloading a
					-- user's old (e.g. blown-out) saved values.
					FileName = "settings_t4_" .. tostring(placeId),
				},
				Discord = { Enabled = false },
				KeySystem = false,
			})
		end)
		if not okWin or not window then
			Logger.error("Rayfield CreateWindow failed — falling back.")
			local Fallback = require("ui/FallbackUI")
			Fallback.start(ctx); ctx.registerHandle(Fallback)
			return UI
		end
		UI._window = window

		-- ── tabs ──────────────────────────────────────────────────────────────
		local tabsByName = {}
		for _, name in ipairs(Config.tabs) do
			local ok, tab = pcall(function() return window:CreateTab(name) end)
			if ok and tab then tabsByName[name] = tab end
		end

		-- ── auto-generated settings ────────────────────────────────────────────
		local registry = Schema.build(tabsByName, ctx)
		UI._registry = registry

		-- State → UI sync (preset/import refresh). Equal-value guard in State.set
		-- breaks any feedback loop.
		maid:give(State.changed:Connect(function(key, value)
			local control = registry[key]
			if control then Controls.setValue(control, Config.meta[key], value) end
		end))

		-- ── hand-wired ACTIONS ─────────────────────────────────────────────────
		UI._wireActions(ctx, tabsByName, handle)

		-- ── toggle keybind ─────────────────────────────────────────────────────
		UI.toggle = function(on)
			local gui = UI._gui or findRayfieldGui()
			UI._gui = gui
			if gui then
				if on == nil then on = not gui.Enabled end
				gui.Enabled = on and true or false
			end
		end
		ctx.toggleUI = UI.toggle
		handle.toggleUI = UI.toggle
		handle.notify = Notify.send
		ctx.notify = Notify.send

		maid:give(ctx.services.UserInputService.InputBegan:Connect(function(input, gp)
			if gp then return end
			if input.UserInputType ~= Enum.UserInputType.Keyboard then return end
			local name = State.get("ui_keybind")
			local ok, kc = pcall(function() return Enum.KeyCode[name] end)
			if ok and input.KeyCode == kc then
				UI.toggle()
			end
		end))

		-- persistence: load any flagged config Rayfield saved last session
		pcall(function() Rayfield:LoadConfiguration() end)

		if State.get("intro_notify") then
			Notify.send("Cinematic Suite", "Loaded. Press " .. tostring(State.get("ui_keybind")) .. " to toggle.", 5)
		end

		Logger.debug("UI online")
		return UI
	end

	function UI._wireActions(ctx, tabsByName, handle)
		local camTab = tabsByName["Camera & Cinematic"]
		local presetTab = tabsByName["Presets"]
		local perfTab = tabsByName["Performance"]
		local aboutTab = tabsByName["About"]

		-- Camera actions
		if camTab then
			pcall(function() camTab:CreateSection("Actions") end)
			pcall(function()
				camTab:CreateButton({ Name = "Toggle Freecam", Callback = function()
					require("camera/Freecam").toggle()
				end })
			end)
			pcall(function()
				camTab:CreateButton({ Name = "Toggle Photo Mode", Callback = function()
					require("camera/PhotoMode").toggle()
				end })
			end)
		end

		-- Presets + import/export
		if presetTab then
			local Presets = require("presets/Presets")
			local Serializer = require("presets/Serializer")
			local ConfigStore = require("presets/ConfigStore")
			pcall(function() presetTab:CreateSection("Look Presets") end)
			local chosen = Presets.current()
			pcall(function()
				presetTab:CreateDropdown({
					Name = "Preset", Options = Presets.names(),
					CurrentOption = { chosen }, MultipleOptions = false,
					Callback = function(o) chosen = (type(o) == "table") and o[1] or o end,
				})
			end)
			pcall(function()
				presetTab:CreateButton({ Name = "Apply Preset", Callback = function()
					Presets.apply(chosen)
					require("ui/Notify").send("Preset", "Applied: " .. tostring(chosen), 3)
				end })
			end)
			pcall(function() presetTab:CreateSection("Import / Export (portable JSON)") end)
			pcall(function()
				presetTab:CreateButton({ Name = "Export to Clipboard / Box", Callback = function()
					local json = Serializer.export()
					if json then
						if Platform.caps.setclipboard then pcall(setclipboard, json) end
						if ConfigStore.available() then ConfigStore.save(json) end
						require("ui/Notify").send("Export", "Config copied (and saved if supported).", 4)
					end
				end })
			end)
			local importBox = ""
			pcall(function()
				presetTab:CreateInput({
					Name = "Paste config JSON here",
					PlaceholderText = "{ \"v\":1, \"data\":{...} }",
					RemoveTextAfterFocusLost = false,
					Callback = function(t) importBox = t end,
				})
			end)
			pcall(function()
				presetTab:CreateButton({ Name = "Import from Box", Callback = function()
					local ok, n = Serializer.import(importBox)
					require("ui/Notify").send("Import", ok and ("Applied " .. tostring(n) .. " settings.") or ("Failed: " .. tostring(n)), 4)
				end })
			end)
		end

		-- Performance: re-benchmark
		if perfTab then
			pcall(function() perfTab:CreateSection("Actions") end)
			pcall(function()
				perfTab:CreateButton({ Name = "Re-run Benchmark", Callback = function()
					local tier = require("perf/Benchmark").run()
					require("ui/Notify").send("Benchmark", "Re-tiered: " .. tostring(tier), 3)
				end })
			end)
		end

		-- About
		if aboutTab then
			pcall(function() aboutTab:CreateSection("About") end)
			pcall(function()
				aboutTab:CreateParagraph({
					Title = "Cinematic Graphics Suite v" .. Config.version,
					Content = "A client-side visual enhancement suite. Composes Roblox's built-in "
						.. "lighting, post-processing, atmosphere and particle stack — no GPU shaders. "
						.. "Reflections are an honest SSR approximation, not ray tracing.\n\n"
						.. "Load source: " .. tostring(handle.loadSource or "unknown"),
				})
			end)
			pcall(function()
				aboutTab:CreateButton({ Name = "Show Last Error", Callback = function()
					require("ui/Notify").send("Last Error", tostring(Logger.getLastError() or "none"), 6)
				end })
			end)
			pcall(function()
				aboutTab:CreateButton({ Name = "⛔ UNLOAD / KILL", Callback = function()
					require("api/Teardown").kill()
				end })
			end)
		end
	end

	function UI.stop()
		-- Destroy the Rayfield window if present (its GUI is tagged by Rayfield, not
		-- us, so we explicitly Destroy it here; our own overlays go via the Maid).
		if UI._rayfield then pcall(function() UI._rayfield:Destroy() end) end
		if UI._maid then UI._maid:clean() end
	end

	return UI
end

end)()

__modules["ui/Schema"] = (function()
--!nonstrict
--[[
	ui/Schema.lua  —  pure module
	-----------------------------------------------------------------------------
	Generates the entire settings UI from Config.layout. Walks each {tab, group,
	keys} entry, creates a section header per group, and emits the matching Rayfield
	control for every key (via ui/Controls), wiring each to State.set. Controls whose
	meta.requires capability is unavailable are skipped with a note, so the UI never
	exposes a control that can't work on this client.

	Returns a control registry { key = controlObject } so ui/UI can push State changes
	back into the controls (preset/import → live UI refresh).
]]

return function(require)
	local Config = require("core/Config")
	local State = require("core/State")
	local Controls = require("ui/Controls")

	local Schema = {}

	-- tabsByName: { [tabName] = rayfieldTab }
	function Schema.build(tabsByName, ctx)
		local registry = {}
		-- group layout entries by tab to create sections in order
		for _, entry in ipairs(Config.layout) do
			local tab = tabsByName[entry.tab]
			if tab then
				pcall(function() tab:CreateSection(entry.group) end)
				for _, key in ipairs(entry.keys) do
					local meta = Config.meta[key]
					if meta then
						local gated = meta.requires and not ctx.platform.caps[meta.requires]
						if gated then
							pcall(function()
								tab:CreateParagraph({
									Title = meta.label or key,
									Content = "Unavailable on this client (requires " .. meta.requires .. ").",
								})
							end)
						else
							local control = Controls.create(tab, key, meta, function(v)
								State.set(key, v)
							end)
							if control then registry[key] = control end
						end
					end
				end
			end
		end
		return registry
	end

	return Schema
end

end)()

__modules["ui/Controls"] = (function()
--!nonstrict
--[[
	ui/Controls.lua  —  pure module
	-----------------------------------------------------------------------------
	Maps one Config metadata entry to the matching Rayfield control. Every control's
	Callback is wired to onChanged(value) (which the Schema points at State.set), and
	meta.save adds a Flag so Rayfield ConfigurationSaving persists it. Returns the
	created control object (which exposes :Set for State→UI sync) or nil.

	Only REAL Rayfield creators are used: CreateSlider/CreateToggle/CreateDropdown/
	CreateColorPicker/CreateKeybind/CreateInput. Each is pcall-guarded because the
	remote library's exact signature can drift between versions.
]]

return function(require)
	local State = require("core/State")

	local Controls = {}

	-- Rayfield dropdowns (newer) pass the selection as a table; normalise.
	local function pickOption(o)
		if type(o) == "table" then return o[1] end
		return o
	end

	function Controls.create(tab, key, meta, onChanged)
		local flag = meta.save and key or nil
		local ok, control = pcall(function()
			if meta.type == "number" then
				return tab:CreateSlider({
					Name = meta.label or key,
					Range = { meta.min or 0, meta.max or 1 },
					Increment = meta.step or 0.01,
					Suffix = "",
					CurrentValue = State.get(key),
					Flag = flag,
					Callback = function(v) onChanged(v) end,
				})
			elseif meta.type == "boolean" then
				return tab:CreateToggle({
					Name = meta.label or key,
					CurrentValue = State.get(key) and true or false,
					Flag = flag,
					Callback = function(v) onChanged(v and true or false) end,
				})
			elseif meta.type == "option" then
				return tab:CreateDropdown({
					Name = meta.label or key,
					Options = meta.options or {},
					CurrentOption = { State.get(key) },
					MultipleOptions = false,
					Flag = flag,
					Callback = function(o) onChanged(pickOption(o)) end,
				})
			elseif meta.type == "color" then
				return tab:CreateColorPicker({
					Name = meta.label or key,
					Color = State.get(key),
					Flag = flag,
					Callback = function(c) onChanged(c) end,
				})
			elseif meta.type == "keybind" then
				return tab:CreateKeybind({
					Name = meta.label or key,
					CurrentKeybind = tostring(State.get(key)),
					HoldToInteract = false,
					Flag = flag,
					Callback = function(k) onChanged(k) end,
				})
			else -- string / freeform
				return tab:CreateInput({
					Name = meta.label or key,
					CurrentValue = tostring(State.get(key)),
					PlaceholderText = meta.desc or "",
					RemoveTextAfterFocusLost = false,
					Flag = flag,
					Callback = function(t) onChanged(t) end,
				})
			end
		end)
		if not ok then
			require("core/Logger").warn("Controls.create failed for", key, "->", control)
			return nil
		end
		return control
	end

	-- push a value from State back into a control (preset/import refresh).
	function Controls.setValue(control, meta, value)
		if not control or type(control.Set) ~= "function" then return end
		pcall(function()
			if meta.type == "option" then
				control:Set({ value })
			else
				control:Set(value)
			end
		end)
	end

	return Controls
end

end)()

__modules["ui/Notify"] = (function()
--!nonstrict
--[[
	ui/Notify.lua  —  pure module
	-----------------------------------------------------------------------------
	Single toast entry-point. Prefers Rayfield:Notify (set by ui/UI once Rayfield is
	loaded); falls back to the CoreGui SendNotification via StarterGui:SetCore so
	notifications still work under FallbackUI or before Rayfield mounts. All pcall'd.
]]

return function(require)
	local Notify = {}
	local rayfield = nil

	function Notify.setRayfield(rf)
		rayfield = rf
	end

	function Notify.send(title, content, duration)
		title = tostring(title or "Cinematic")
		content = tostring(content or "")
		duration = duration or 4
		if rayfield then
			local ok = pcall(function()
				rayfield:Notify({ Title = title, Content = content, Duration = duration })
			end)
			if ok then return end
		end
		pcall(function()
			game:GetService("StarterGui"):SetCore("SendNotification", {
				Title = title, Text = content, Duration = duration,
			})
		end)
	end

	return Notify
end

end)()

__modules["ui/FallbackUI"] = (function()
--!nonstrict
--[[
	ui/FallbackUI.lua
	-----------------------------------------------------------------------------
	Minimal native-GUI control panel for when Rayfield can't be fetched (no HTTP / no
	loadstring / network failure). Covers the essentials: master enable, a quality
	slider, and an unload button — enough to control and safely remove the suite. All
	instances are tagged + Maid-tracked.
]]

return function(require)
	local State = require("core/State")

	local FallbackUI = {}
	FallbackUI.id = "ui/FallbackUI"

	function FallbackUI.start(ctx)
		local maid = ctx.maid:childMaid()
		FallbackUI._maid = maid
		local S = ctx.snapshot

		local root = S.create("Frame", {
			Name = "FallbackUI",
			BackgroundColor3 = Color3.fromRGB(18, 20, 26),
			BackgroundTransparency = 0.1,
			Position = UDim2.fromScale(0.02, 0.3),
			Size = UDim2.fromOffset(220, 150),
			BorderSizePixel = 0, ZIndex = 95,
		}, ctx.gui)
		S.create("UICorner", { CornerRadius = UDim.new(0, 8) }, root)
		S.create("TextLabel", {
			BackgroundTransparency = 1, Size = UDim2.new(1, 0, 0, 28),
			Text = "Cinematic Suite (fallback)", Font = Enum.Font.GothamBold,
			TextColor3 = Color3.fromRGB(235, 240, 250), TextSize = 14, ZIndex = 96,
		}, root)

		-- master enable toggle button
		local enableBtn = S.create("TextButton", {
			Position = UDim2.fromOffset(12, 36), Size = UDim2.fromOffset(196, 30),
			BackgroundColor3 = Color3.fromRGB(40, 120, 90), Font = Enum.Font.Gotham,
			TextColor3 = Color3.new(1, 1, 1), TextSize = 13, ZIndex = 96,
			Text = State.get("master_enabled") and "Enabled ✓" or "Disabled",
		}, root)
		S.create("UICorner", { CornerRadius = UDim.new(0, 6) }, enableBtn)
		maid:give(enableBtn.MouseButton1Click:Connect(function()
			local v = not State.get("master_enabled")
			State.set("master_enabled", v)
			enableBtn.Text = v and "Enabled ✓" or "Disabled"
			enableBtn.BackgroundColor3 = v and Color3.fromRGB(40, 120, 90) or Color3.fromRGB(120, 60, 60)
		end))

		-- quality slider (click-drag track)
		local track = S.create("Frame", {
			Position = UDim2.fromOffset(12, 74), Size = UDim2.fromOffset(196, 18),
			BackgroundColor3 = Color3.fromRGB(40, 44, 54), BorderSizePixel = 0, ZIndex = 96,
		}, root)
		S.create("UICorner", { CornerRadius = UDim.new(0, 4) }, track)
		local fill = S.create("Frame", {
			Size = UDim2.fromScale(State.get("quality"), 1),
			BackgroundColor3 = Color3.fromRGB(90, 150, 230), BorderSizePixel = 0, ZIndex = 97,
		}, track)
		S.create("UICorner", { CornerRadius = UDim.new(0, 4) }, fill)
		local UIS = ctx.services.UserInputService
		local dragging = false
		local function setFromX(px)
			local rel = math.clamp((px - track.AbsolutePosition.X) / math.max(1, track.AbsoluteSize.X), 0, 1)
			fill.Size = UDim2.fromScale(rel, 1)
			State.set("quality", rel)
		end
		maid:give(track.InputBegan:Connect(function(i)
			if i.UserInputType == Enum.UserInputType.MouseButton1 or i.UserInputType == Enum.UserInputType.Touch then
				dragging = true; setFromX(i.Position.X)
			end
		end))
		maid:give(UIS.InputChanged:Connect(function(i)
			if dragging and (i.UserInputType == Enum.UserInputType.MouseMovement or i.UserInputType == Enum.UserInputType.Touch) then
				setFromX(i.Position.X)
			end
		end))
		maid:give(UIS.InputEnded:Connect(function(i)
			if i.UserInputType == Enum.UserInputType.MouseButton1 or i.UserInputType == Enum.UserInputType.Touch then
				dragging = false
			end
		end))

		-- unload
		local kill = S.create("TextButton", {
			Position = UDim2.fromOffset(12, 104), Size = UDim2.fromOffset(196, 30),
			BackgroundColor3 = Color3.fromRGB(150, 50, 50), Font = Enum.Font.GothamBold,
			TextColor3 = Color3.new(1, 1, 1), TextSize = 13, ZIndex = 96, Text = "Unload",
		}, root)
		S.create("UICorner", { CornerRadius = UDim.new(0, 6) }, kill)
		maid:give(kill.MouseButton1Click:Connect(function()
			require("api/Teardown").kill()
		end))

		ctx.log.debug("FallbackUI mounted")
		return FallbackUI
	end

	function FallbackUI.stop() if FallbackUI._maid then FallbackUI._maid:clean() end end

	return FallbackUI
end

end)()

__modules["api/API"] = (function()
--!nonstrict
--[[
	api/API.lua  —  CONTROLLER (manifest.boot, last)
	-----------------------------------------------------------------------------
	Defines the public programmatic surface on the global handle that init seeded in
	Platform.globalTable().__CINEMATIC_SHADER. Everything a script (or the user via
	the console) needs:

	    handle.get(key)               handle.set(key, value)
	    handle.applyPreset(name)      handle.toggleUI(on?)
	    handle.setQuality(n)          handle.exportConfig()  handle.importConfig(json)
	    handle.reBenchmark()          handle.getLastError()
	    handle.kill() / handle.destroy()           handle.version  handle.loadSource

	We attach to the EXISTING handle table (never replace it) so the double-load guard
	and init's stored ctx/handles stay intact.
]]

return function(require)
	local State = require("core/State")
	local Logger = require("core/Logger")
	local Platform = require("core/Platform")

	local API = {}
	API.id = "api/API"

	function API.start(ctx)
		local globals = Platform.globalTable()
		local handle = globals["__CINEMATIC_SHADER"]
		if type(handle) ~= "table" then
			handle = {}
			globals["__CINEMATIC_SHADER"] = handle
		end

		handle.get = function(key) return State.get(key) end
		handle.set = function(key, value) return State.set(key, value) end
		handle.setQuality = function(n) return State.set("quality", n) end
		handle.applyPreset = function(name) return require("presets/Presets").apply(name) end
		handle.presets = function() return require("presets/Presets").names() end
		handle.toggleUI = handle.toggleUI or function(on)
			if ctx.toggleUI then ctx.toggleUI(on) end
		end
		handle.exportConfig = function() return require("presets/Serializer").export() end
		handle.importConfig = function(json) return require("presets/Serializer").import(json) end
		handle.reBenchmark = function() return require("perf/Benchmark").run() end
		handle.getLastError = function() return Logger.getLastError() end
		handle.notify = handle.notify or function(t, c, d) require("ui/Notify").send(t, c, d) end
		handle.kill = function() return require("api/Teardown").kill() end
		handle.destroy = handle.kill
		handle.version = ctx.manifest and ctx.manifest.version or "1.0.0"
		handle.__alive = true

		ctx.log.info("Public API ready on _G/getgenv().__CINEMATIC_SHADER")
		return API
	end

	function API.stop() end

	return API
end

end)()

__modules["api/Teardown"] = (function()
--!nonstrict
--[[
	api/Teardown.lua  —  the kill switch
	-----------------------------------------------------------------------------
	Bulletproof, idempotent unload that leaves ZERO residue:
	  1. exit PhotoMode / Freecam if active (restores camera takeover),
	  2. destroy the Rayfield window (UI.stop),
	  3. ctx.maid:clean() — stops EVERY loop/connection/thread (no orphaned
	     PreRender/Heartbeat),
	  4. Snapshot.restoreAll — writes back EVERY captured original property (Lighting,
	     Camera FOV/Type, Terrain water, part Reflectance/CFrame, …) and Destroys ONLY
	     our tagged created instances (effects, overlays, folders, emitters),
	  5. force Camera back to Custom,
	  6. clear the global handle.
	Each step is pcall-guarded so one failure can't strand the rest.
]]

return function(require)
	local Platform = require("core/Platform")
	local Snapshot = require("core/Snapshot")
	local Logger = require("core/Logger")

	local Teardown = {}
	local killing = false

	function Teardown.kill()
		if killing then return end
		killing = true
		Logger.info("Teardown: unloading…")

		local globals = Platform.globalTable()
		local handle = globals["__CINEMATIC_SHADER"]
		local ctx = handle and handle.ctx

		-- 1. exit camera takeovers
		pcall(function()
			local fc = require("camera/Freecam")
			if fc.isActive and fc.isActive() then fc.toggle(false) end
		end)
		pcall(function()
			local pm = require("camera/PhotoMode")
			if pm.isActive and pm.isActive() then pm.toggle(false) end
		end)

		-- 2. destroy the UI (Rayfield window is not ours to tag, so stop() Destroys it)
		pcall(function() require("ui/UI").stop() end)

		-- 3. stop every subsystem loop/connection
		if ctx and ctx.maid then
			pcall(function() ctx.maid:clean() end)
		end

		-- 4. restore all captured properties + destroy all tagged instances
		local roots = {}
		if ctx and ctx.services then
			roots[#roots + 1] = ctx.services.Lighting
			roots[#roots + 1] = ctx.services.Workspace
		end
		pcall(function() Snapshot.restoreAll(roots) end)

		-- 5. force camera back to default control
		pcall(function()
			local cam = workspace.CurrentCamera
			if cam and cam.CameraType == Enum.CameraType.Scriptable then
				cam.CameraType = Enum.CameraType.Custom
			end
		end)

		-- 6. clear the global handle
		if handle then handle.__alive = false end
		pcall(function() globals["__CINEMATIC_SHADER"] = nil end)

		Logger.info("Teardown complete — game state restored.")
		killing = false
	end

	Teardown.destroy = Teardown.kill
	return Teardown
end

end)()

return __require("init")
